    def _make_log_panel(title, dots=True):
        panel = tk.Frame(logs_pane, bg=C["panel"], bd=0,
                         highlightthickness=1, highlightbackground=C["border"])
        hdr = tk.Frame(panel, bg=C["panel"], pady=5, padx=12)
        hdr.pack(fill="x")
        if dots:
            for col, sym in [("#f87171","●"), ("#fbbf24","●"), ("#22d3a0","●")]:
                tk.Label(hdr, text=sym, font=("Consolas", 9),
                         bg=C["panel"], fg=col).pack(side="left", padx=1)
        title_lbl = tk.Label(hdr, text=f"   {title}", font=("Consolas", 8),
                             bg=C["panel"], fg=C["muted"])
        title_lbl.pack(side="left")
        txt_ref = [None]
        def _copy_log(t=txt_ref):
            w = t[0]
            if not w: return
            try:
                panel.clipboard_clear()
                panel.clipboard_append(w.get("1.0", "end").strip())
            except Exception: pass
        tk.Button(hdr, text="⎘ copy", font=("Consolas", 7),
                  bg=C["border"], fg=C["subtext"], relief="flat", bd=0,
                  padx=6, pady=2, cursor="hand2",
                  activebackground=C["muted"],
                  command=_copy_log).pack(side="right")
        tk.Frame(panel, bg=C["border"], height=1).pack(fill="x")
        inner = tk.Frame(panel, bg="#07070f")
        inner.pack(fill="both", expand=True)
        sc = tk.Scrollbar(inner, bg=C["card"], width=7,
                          troughcolor="#07070f", relief="flat")
        sc.pack(side="right", fill="y")
        txt = tk.Text(inner, bg="#07070f", fg=C["text"],
                      font=("Consolas", 8), relief="flat", bd=0,
                      padx=10, pady=8, wrap="none", cursor="arrow",
                      yscrollcommand=sc.set, state="disabled")
        sc.config(command=txt.yview)
        txt.pack(fill="both", expand=True)
        txt_ref[0] = txt
        return panel, txt, title_lbl

