def _defense_log(msg: str, tag: str = "DIM"):
    _log_op(f"[DEFENSE] {msg}", "INFO")
    for cb in _defense_log_cbs:
        try: root.after(0, lambda m=msg, t=tag: cb(m, t))
        except Exception: pass



def _defense_auto_action(result: dict) -> str:
    path  = result["path"]
    score = result["score"]
    if score >= 2 and _DEFENSE_SETTINGS.get("auto_quarantine", False):
        reason = "; ".join(result["findings"][:3])
        ok = _quar_quarantine(path, reason=f"defense_auto: {reason}")
        return "quarantined" if ok else "quarantine_failed"
    if score >= 3 and _DEFENSE_SETTINGS.get("auto_delete", False):
        try:
            os.remove(path); return "deleted"
        except Exception:
            return "delete_failed"
    return "none"


