def _run_splash():
    sp = tk.Toplevel()
    sp.title("V0RTEX — Starting")
    sp.configure(bg="#0d0d14")
    sp.geometry("680x520")
    sp.resizable(False, False)

    sp.update_idletasks()
    sw = sp.winfo_screenwidth(); sh = sp.winfo_screenheight()
    sp.geometry(f"680x520+{(sw-680)//2}+{(sh-520)//2}")
    sp.overrideredirect(True)
    try: sp.attributes("-topmost", True)
    except Exception: pass
    sp.lift(); sp.focus_force(); sp.update()


    logo_f = tk.Frame(sp, bg="#11111b", pady=10); logo_f.pack(fill=tk.X)
    tk.Label(logo_f, text="V0RTEX",       font=("Consolas",18,"bold"),
             bg="#11111b", fg="#cba6f7").pack(side=tk.LEFT, padx=(20,0))
    tk.Label(logo_f, text=f"  v{_VX_VER}",     font=("Consolas",11),
             bg="#11111b", fg="#6c7086").pack(side=tk.LEFT, pady=4)
    tk.Label(logo_f, text="by Vider_06",  font=("Consolas",10),
             bg="#11111b", fg="#45475a").pack(side=tk.RIGHT, padx=20)
    tk.Frame(sp, bg="#313244", height=1).pack(fill=tk.X)


    txt = tk.Text(sp, bg="#0d0d14", fg="#cdd6f4",
                  font=("Consolas",10), relief="flat", bd=0,
                  padx=18, pady=12, cursor="arrow", state="disabled",
                  insertbackground="#cdd6f4")
    txt.pack(fill=tk.BOTH, expand=True)
    for tag, color in [
        ("blue", "#89b4fa"), ("green", "#a6e3a1"), ("yellow", "#fab387"),
        ("mauve", "#cba6f7"), ("dim", "#6c7086"), ("text", "#cdd6f4"),
    ]:
        txt.tag_configure(tag, foreground=color)


    prog_f = tk.Frame(sp, bg="#11111b", pady=8, padx=12); prog_f.pack(fill=tk.X)
    prog_lbl = tk.StringVar(value="Initializing...")
    tk.Label(prog_f, textvariable=prog_lbl, font=("Consolas",9),
             bg="#11111b", fg="#6c7086").pack(anchor="w")
    from tkinter import ttk as _ttk2
    pbar = _ttk2.Progressbar(prog_f, orient="horizontal", mode="determinate",
                              maximum=len(_SPLASH_LINES), value=0)
    pbar.pack(fill=tk.X, pady=(4,0))
    try:
        _sty2 = _ttk2.Style(sp)
        _sty2.configure("Splash.Horizontal.TProgressbar",
                         troughcolor="#1e1e2e", background="#cba6f7",
                         darkcolor="#cba6f7", lightcolor="#cba6f7", thickness=6)
        pbar.configure(style="Splash.Horizontal.TProgressbar")
    except Exception: pass

    def _finish():
        sp.destroy()
        if _RECOVERY_MODE:
            return
        try:    root.state("zoomed")
        except Exception:
            try:    root.attributes("-zoomed", True)
            except Exception: root.geometry("1500x900")
        root.deiconify()
        root.lift()
        root.focus_force()
        root.update()


    sp.update()
    time.sleep(0.1)
    for i, (line_text, color, delay_ms) in enumerate(_SPLASH_LINES):
        tag = "text"
        if color == "#89b4fa":   tag = "blue"
        elif color == "#a6e3a1": tag = "green"
        elif color == "#fab387": tag = "yellow"
        elif color == "#cba6f7": tag = "mauve"
        elif color == "#6c7086": tag = "dim"
        txt.config(state="normal")
        txt.insert(tk.END, line_text + "\n", tag)
        txt.see(tk.END)
        txt.config(state="disabled")
        pbar.config(value=i+1)
        if line_text.strip():
            prog_lbl.set(line_text.strip()[:55])
        sp.update()
        time.sleep(delay_ms / 1000.0)

    prog_lbl.set("Launching interface...")
    pbar.config(value=len(_SPLASH_LINES))
    sp.update()
    time.sleep(0.4)
    _finish()

