_SCAN_STEPS = {
    "": (0, C["overlay0"]),
    "HASH":     (10, C["blue"]),
    "YARA":     (30, C["peach"]),
    "IOC":      (50, C["yellow"]),
    "VT":       (65, C["mauve"]),
    "PE":       (85, C["sapphire"]),
    "REPORT":   (95, C["teal"]),
    "DONE":    (100, C["green"]),
}

def _scan_step(step: str, fname: str = ""):
    val, color = _SCAN_STEPS.get(step, (0, C["overlay0"]))
    label = f"▶ {step}" if step else ""
    def _do():
        _scan_step_sv.set(label)
        _scan_file_sv.set(f"  {fname[:60]}" if fname else "")
        _scan_pbar_val.set(val)
        try:
            _sty.configure("ScanBar.Horizontal.TProgressbar", background=color, lightcolor=color, darkcolor=color)
        except Exception:
            pass
        if step in ("DONE", ""):
            root.after(1200, lambda: (_scan_step_sv.set(""), _scan_file_sv.set(""), _scan_pbar_val.set(0)))
    root.after(0, _do)

