def _dash_card(parent, title, sv, color, click_fn=None):
    f = tk.Frame(parent, bg=C["surface0"], padx=14, pady=10)
    tk.Label(f, text=title, font=("Consolas",7), bg=C["surface0"], fg=C["overlay0"]).pack(anchor="w")
