    lbl = tk.Label(f, textvariable=sv, font=("Consolas",22,"bold"), bg=C["surface0"], fg=color)
    lbl.pack(anchor="w")
    if click_fn:
        f.config(cursor="hand2"); lbl.config(cursor="hand2")
        for w in (f, lbl): w.bind("<Button-1>", lambda e, fn=click_fn: fn())
    f.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=2)
    return f

