def _dash_update_threat():
    try:
        rows = _db_query("SELECT COUNT(*), SUM(malicious) FROM scans")
        total, mal = (rows[0][0] or 0), (rows[0][1] or 0)
        if total == 0:
            _dash_threat_lbl.config(text="—  No scans yet", fg=C["overlay0"])
            _dash_threat_canvas.delete("all"); return
        ratio = mal / total
        if ratio == 0:      color, label, lvl = C["green"],  "LOW — No threats detected",                 0.06
        elif ratio < 0.05:  color, label, lvl = C["teal"],   f"GUARDED — {mal} threat(s) in {total}",    0.24
        elif ratio < 0.15:  color, label, lvl = C["yellow"], f"ELEVATED — {mal} threats ({ratio*100:.1f}%)", 0.50
        elif ratio < 0.35:  color, label, lvl = C["peach"],  f"HIGH — {mal} threats ({ratio*100:.1f}%)",  0.72
        else:               color, label, lvl = C["red"],    f"CRITICAL — {mal}/{total} malicious",       min(ratio, 1.0)
        _dash_threat_lbl.config(text=f"  {label}", fg=color)
        _dash_threat_canvas.delete("all")
        w = _dash_threat_canvas.winfo_width() or 700
        _dash_threat_canvas.create_rectangle(0, 0, w, 18, fill=C["crust"], outline="")
        _dash_threat_canvas.create_rectangle(0, 0, int(w*lvl), 18, fill=color, outline="")
        for pct in (0.25, 0.5, 0.75):
            _dash_threat_canvas.create_line(int(w*pct), 0, int(w*pct), 18, fill=C["surface2"])
    except Exception: pass
_dash_threat_canvas.bind("<Configure>", lambda e: root.after(50, _dash_update_threat))
root.after(1000, _dash_update_threat)
root.after(2000, _dash_update_threat)


