_chart_last_update = 0.0
_chart_update_pending = False

def _update_charts():
    global _chart_last_update, _chart_update_pending
    now = time.monotonic()
    if now - _chart_last_update < 2.0:
        if not _chart_update_pending:
            _chart_update_pending = True
            delay = max(50, int((2.0-(now-_chart_last_update))*1000)+50)
            root.after(delay, _update_charts)
        return
    _chart_last_update = now
    _chart_update_pending = False
    _chart_fig.clear(); _chart_fig.set_facecolor(C["surface0"])
    rows = _db_query("SELECT malicious,suspicious,undetected,file,timestamp,yara_hits,entropy FROM scans ORDER BY timestamp DESC LIMIT 30")

    ax_style = dict(facecolor=C["mantle"])
    def _ax_clean(ax, title):
        ax.set_facecolor(C["mantle"]); ax.set_title(title, color=C["subtext"], fontsize=9, pad=6)
        ax.tick_params(colors=C["overlay0"], labelsize=8)
        for sp in ax.spines.values(): sp.set_color(C["surface2"])

    if not rows:
        ax = _chart_fig.add_subplot(111, **ax_style)
        _ax_clean(ax, "No scans yet")
        ax.set_xticks([]); ax.set_yticks([])
        for sp in ax.spines.values(): sp.set_visible(False)
        ax.text(0.5, 0.5, "Drop files or use Add File to start scanning",
                ha="center", va="center", color=C["overlay0"], fontsize=12,
                transform=ax.transAxes)
        _chart_canvas.draw_idle(); return


    ax1 = _chart_fig.add_subplot(221)
    total_mal = sum(r[0] for r in rows)
    total_sus = sum(r[1] for r in rows)
    total_cln = sum(r[2] for r in rows)
    total_all = total_mal + total_sus + total_cln
    vals_raw  = [total_mal, total_sus, total_cln]
    lbls_all  = ["Malicious", "Suspicious", "Clean"]
    cols_all  = [C["red"], C["yellow"], C["green"]]
    vals = [v for v in vals_raw if v > 0]
    lbls = [l for l,v in zip(lbls_all, vals_raw) if v > 0]
    cols = [c for c,v in zip(cols_all, vals_raw) if v > 0]
    if vals:
        wedges, _ = ax1.pie(
            vals, labels=None, colors=cols,
            wedgeprops=dict(width=0.52, edgecolor=C["surface0"], linewidth=2),
            startangle=90)

        ax1.text(0, 0, str(total_all), ha="center", va="center",
                 fontsize=14, fontweight="bold", color=C["text"])
        ax1.text(0, -0.22, "files", ha="center", va="center",
                 fontsize=7, color=C["overlay0"])

        legend_labels = [f"{l}  {v}" for l,v in zip(lbls,vals)]
        ax1.legend(wedges, legend_labels,
                   loc="lower center", bbox_to_anchor=(0.5, -0.18),
                   ncol=len(vals), frameon=False,
                   labelcolor=C["text"], fontsize=8,
                   handlelength=1.2, handleheight=0.8)
    else:
        ax1.text(0.5, 0.5, "No data", ha="center", va="center",
                 color=C["overlay0"], transform=ax1.transAxes)
    _ax_clean(ax1, "Verdict Distribution")


    ax2 = _chart_fig.add_subplot(222)
    recent = rows[:10][::-1]
    fnames = [os.path.basename(r[3])[:16]+"…" if len(os.path.basename(r[3]))>16
              else os.path.basename(r[3]) for r in recent]
    m_vals = [r[0] for r in recent]
    s_vals = [r[1] for r in recent]
    x = range(len(fnames))
    ax2.barh(list(x), m_vals, color=C["red"],    alpha=0.9, label="Malicious", height=0.6)
