def _rep_sniff_verdict(txt_path):
    try:
        with open(txt_path, encoding="utf-8", errors="replace") as f:
            head = f.read(600)

        import re
        m = re.search(r'"malicious":\s*(\d+)', head)
        mal = int(m.group(1)) if m else 0
        s = re.search(r'"suspicious":\s*(\d+)', head)
        sus = int(s.group(1)) if s else 0
        if mal > 0: return "malicious"
        if sus > 0: return "suspicious"
        return "clean"
    except Exception:
        return "file"

def _rep_refresh():
    _rep_tree.delete(*_rep_tree.get_children())
    _rep_iid_map.clear()
    _rep_crumb.set("")
    if not os.path.isdir(REPORTS_DIR): return

    def _is_file_report(d):
        return os.path.exists(os.path.join(d, "report.txt"))

    def _is_folder_scan(d):
        try:
            return any(
                os.path.isdir(os.path.join(d, s)) and _is_file_report(os.path.join(d, s))
                for s in os.listdir(d)
            )
        except Exception: return False

    try:
        entries = sorted(os.listdir(REPORTS_DIR), reverse=True)
    except Exception: return

    for entry in entries:
        full = os.path.join(REPORTS_DIR, entry)
        if not os.path.isdir(full): continue

        if _is_folder_scan(full):
            sub_dirs = sorted([
                s for s in os.listdir(full)
                if os.path.isdir(os.path.join(full, s))
                and _is_file_report(os.path.join(full, s))
            ])
            folder_txt  = os.path.join(full, "folder_report.txt")
            folder_html = os.path.join(full, "folder_report.html")

            iid = _rep_tree.insert("", tk.END,
                text=f"  \U0001f4c1 {entry}  [{len(sub_dirs)} files]",
                open=False, tags=("folder",))

            if os.path.exists(folder_txt):
                riid = _rep_tree.insert(iid, tk.END,
                    text="    \U0001f4cb  Folder Summary Report",
                    tags=("folder_rpt",))
                _rep_iid_map[riid] = (full, folder_txt, folder_html)

            for sub in sub_dirs:
                sub_full  = os.path.join(full, sub)
                txt_path  = os.path.join(sub_full, "report.txt")
                html_path = os.path.join(sub_full, "report.html")
                tag = _rep_sniff_verdict(txt_path)
                icon = "\U0001f6a8" if tag=="malicious" else ("\u26a0\ufe0f" if tag=="suspicious" else "\U0001f4c4")
                fiid = _rep_tree.insert(iid, tk.END,
                    text=f"    {icon}  {sub}",
                    tags=(tag,))
                _rep_iid_map[fiid] = (sub_full, txt_path, html_path)

        elif _is_file_report(full):
            txt_path  = os.path.join(full, "report.txt")
            html_path = os.path.join(full, "report.html")
            tag  = _rep_sniff_verdict(txt_path)
            icon = "\U0001f6a8" if tag=="malicious" else ("\u26a0\ufe0f" if tag=="suspicious" else "\U0001f4c4")
            iid = _rep_tree.insert("", tk.END,
                text=f"  {icon}  {entry}",
                tags=(tag,))
            _rep_iid_map[iid] = (full, txt_path, html_path)

def _rep_load(event=None):
    sel = _rep_tree.selection()
    if not sel: return
    iid = sel[0]
    if iid not in _rep_iid_map: return
    folder_path, txt_path, html_path = _rep_iid_map[iid]
    parent = _rep_tree.parent(iid)
    if parent:
        ptext = _rep_tree.item(parent, "text").strip()
        ctext = _rep_tree.item(iid,    "text").strip()
        _rep_crumb.set(f"{ptext}  /  {ctext}")
    else:
        _rep_crumb.set(_rep_tree.item(iid, "text").strip())
    _rep_viewer.config(state="normal")
    _rep_viewer.delete("1.0", tk.END)
    if os.path.exists(txt_path):
        with open(txt_path, encoding="utf-8", errors="replace") as f:
            _rep_viewer.insert(tk.END, f.read())
    else:
        _rep_viewer.insert(tk.END, "No report found for this entry.")
    _rep_viewer.config(state="disabled")

def _rep_open_html():
    sel = _rep_tree.selection()
    if not sel or sel[0] not in _rep_iid_map: return
    _, _, html_path = _rep_iid_map[sel[0]]
    if os.path.exists(html_path): webbrowser.open("file://" + html_path)
    else: messagebox.showinfo("Not found", "HTML report not found.")

def _rep_open_folder():
    sel = _rep_tree.selection()
    if not sel: return
    iid = sel[0]
    if iid in _rep_iid_map:
        folder_path = _rep_iid_map[iid][0]
    else:

        raw = _rep_tree.item(iid, "text").strip().lstrip("\U0001f4c1 ").split("[")[0].strip()
        folder_path = os.path.join(REPORTS_DIR, raw)
    if os.path.isdir(folder_path):
        if sys.platform == "win32": subprocess.Popen(["explorer", folder_path])
        elif sys.platform == "darwin": subprocess.Popen(["open", folder_path])
        else: subprocess.Popen(["xdg-open", folder_path])

