def _easy_read_popup():
    sel = _rep_tree.selection()
    if not sel or sel[0] not in _rep_iid_map:
        messagebox.showinfo("Easy Read", "Select a scan report first."); return
    _, txt_path, _ = _rep_iid_map[sel[0]]
    if not os.path.exists(txt_path):
        messagebox.showinfo("Easy Read", "No report.txt found."); return

    try:
        with open(txt_path, encoding="utf-8", errors="replace") as f:
            raw = f.read()
    except Exception as e:
        messagebox.showerror("Error", str(e)); return


    fname    = re.search(r'  (.+?)\n  20', raw)
    fname    = fname.group(1).strip() if fname else "Unknown"
    ts       = re.search(r'  (\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})', raw)
    ts       = ts.group(1) if ts else "?"
    md5      = re.search(r'MD5:\s+([\w]+)', raw)
    md5      = md5.group(1) if md5 else "?"
    sha256   = re.search(r'SHA256:\s+([\w]+)', raw)
    sha256   = sha256.group(1)[:16]+"…" if sha256 else "?"
    ftype    = re.search(r'File Type:\s+(.+)', raw)
    ftype    = ftype.group(1).strip() if ftype else "?"
    entropy  = re.search(r'Entropy:\s+([\d.]+)', raw)
    entropy  = float(entropy.group(1)) if entropy else 0.0
    mal      = re.search(r'"malicious":\s*(\d+)', raw)
    mal      = int(mal.group(1)) if mal else 0
    sus      = re.search(r'"suspicious":\s*(\d+)', raw)
    sus      = int(sus.group(1)) if sus else 0
    cln      = re.search(r'"undetected":\s*(\d+)', raw)
    cln      = int(cln.group(1)) if cln else 0
    yara_line= re.search(r'YARA:\s*(.+)', raw)
    yara_hits= yara_line.group(1).strip() if yara_line else "None"
    ips_line = re.search(r'IPS:\s*(.+)', raw, re.IGNORECASE)
    ips_val  = ips_line.group(1)[:80] if ips_line else "None"

    verdict = "🔴 MALICIOUS" if mal>0 else ("🟡 SUSPICIOUS" if sus>0 else "🟢 CLEAN")
    vc      = C["red"] if mal>0 else (C["yellow"] if sus>0 else C["green"])
    ent_col = C["red"] if entropy>7 else (C["yellow"] if entropy>6 else C["green"])
    ent_note= "⚠ Very high (packed/encrypted)" if entropy>7 else ("⚠ High (suspicious)" if entropy>6 else "Normal")


    pop = tk.Toplevel(root)
    pop.title(f"Easy Read — {fname[:40]}")
    pop.configure(bg=C["base"]); pop.resizable(True, True)
    pop.geometry("560x620"); pop.transient(root)
    root.update_idletasks()
    x = root.winfo_x() + root.winfo_width()//2 - 280
    y = root.winfo_y() + root.winfo_height()//2 - 310
    pop.geometry(f"+{x}+{y}")


    tk.Frame(pop, bg=vc, height=4).pack(fill=tk.X)
    hdr = tk.Frame(pop, bg=C["surface0"], pady=14, padx=20); hdr.pack(fill=tk.X)
    tk.Label(hdr, text=verdict, font=("Consolas",20,"bold"),
             bg=C["surface0"], fg=vc).pack(anchor="w")
    tk.Label(hdr, text=fname, font=FB, bg=C["surface0"], fg=C["text"]).pack(anchor="w")
    tk.Label(hdr, text=ts,    font=FS, bg=C["surface0"], fg=C["overlay0"]).pack(anchor="w")

    def _section(title, color=C["blue"]):
        f = tk.Frame(pop, bg=C["surface0"], padx=20, pady=8); f.pack(fill=tk.X, padx=12, pady=4)
        tk.Label(f, text=title, font=FB, bg=C["surface0"], fg=color).pack(anchor="w")
        tk.Frame(f, bg=color, height=1).pack(fill=tk.X, pady=(3,6))
        return f

    def _row(parent, label, val, val_color=C["text"]):
        row = tk.Frame(parent, bg=C["surface0"]); row.pack(fill=tk.X, pady=1)
        tk.Label(row, text=label, font=FS, bg=C["surface0"],
                 fg=C["overlay0"], width=16, anchor="w").pack(side=tk.LEFT)
        tk.Label(row, text=val,   font=FM, bg=C["surface0"],
                 fg=val_color, anchor="w").pack(side=tk.LEFT, padx=6)


    vt_sec = _section("🛡  VirusTotal", C["blue"])
    total = mal+sus+cln
    _row(vt_sec, "Malicious",  f"{mal} / {total}", C["red"]    if mal>0 else C["green"])
    _row(vt_sec, "Suspicious", f"{sus} / {total}", C["yellow"] if sus>0 else C["green"])
    _row(vt_sec, "Clean",      f"{cln} / {total}", C["green"])


    fi_sec = _section("📄  File Info", C["teal"])
    _row(fi_sec, "Type",    ftype)
    _row(fi_sec, "Entropy", f"{entropy:.3f}/8.0  — {ent_note}", ent_col)
    _row(fi_sec, "MD5",     md5,    C["sapphire"])
    _row(fi_sec, "SHA256",  sha256, C["sapphire"])


    yc = C["red"] if yara_hits not in ("None","") else C["green"]
    ya_sec = _section("🔬  YARA", C["mauve"])
    _row(ya_sec, "Hits", yara_hits if yara_hits else "None", yc)


    io_sec = _section("🌐  IOCs", C["peach"])
    _row(io_sec, "IP", ips_val)


    tk.Button(pop, text="  Close  ", command=pop.destroy,
              bg=C["surface2"], fg=C["text"], font=FB,
              relief="flat", padx=14, pady=8, cursor="hand2", bd=0).pack(pady=12)

def _export_pdf():
    sel = _rep_tree.selection()
    if not sel or sel[0] not in _rep_iid_map:
        messagebox.showinfo("PDF Export", "Select a scan report first."); return
    _, txt_path, _ = _rep_iid_map[sel[0]]
    if not os.path.exists(txt_path):
        messagebox.showinfo("PDF Export", "No report.txt found."); return
    if _FPDF is None:
        messagebox.showerror("PDF Export", "fpdf2 not installed.\npip install fpdf2"); return
    dest = filedialog.asksaveasfilename(
        defaultextension=".pdf",
        initialfile=os.path.basename(txt_path).replace(".txt",".pdf"),
        filetypes=[("PDF", "*.pdf"), ("All", "*.*")])
    if not dest: return
    try:
        with open(txt_path, encoding="utf-8", errors="replace") as f:
            lines = f.readlines()
        pdf = _FPDF()
        pdf.set_margins(15, 15, 15)
        pdf.add_page()
        pdf.set_auto_page_break(auto=True, margin=15)
        pdf.set_font("Courier", "B", 14)
        pdf.cell(0, 10, "V0RTEX  |  Scan Report", ln=True, align="C")
        pdf.set_font("Courier", "", 8)
        pdf.ln(3)
        for line in lines:
            line = line.rstrip("\n").encode("latin-1", errors="replace").decode("latin-1")
            if line.startswith("="*10):
                pdf.set_font("Courier","B",9)
                pdf.cell(0, 6, line[:100], ln=True)
                pdf.set_font("Courier","",8)
            elif line.startswith("-"*10):
                pdf.set_draw_color(100,100,120)
                pdf.line(15, pdf.get_y(), 195, pdf.get_y())
                pdf.ln(2)
            else:
                pdf.multi_cell(0, 5, line[:200] if line else " ")
        pdf.output(dest)
        messagebox.showinfo("PDF Exported", f"Saved to:\n{dest}")
        _auto_gc("export_pdf")
    except Exception as e:
        messagebox.showerror("PDF Error", str(e))

def _export_stix():
    sel = _rep_tree.selection()
    if not sel or sel[0] not in _rep_iid_map:
        messagebox.showinfo("STIX Export", "Select a scan report first."); return
    _, txt_path, _ = _rep_iid_map[sel[0]]
    if not os.path.exists(txt_path): return
    dest = filedialog.asksaveasfilename(
        defaultextension=".json",
        initialfile="iocs_stix21.json",
        filetypes=[("JSON STIX 2.1", "*.json"), ("All","*.*")])
    if not dest: return
    try:
        with open(txt_path, encoding="utf-8", errors="replace") as f: raw = f.read()
        sha256 = re.search(r'SHA256:\s+(\S+)', raw)
        sha256 = sha256.group(1) if sha256 else ""
        md5    = re.search(r'MD5:\s+(\S+)', raw)
        md5    = md5.group(1) if md5 else ""
        ips    = re.findall(r'\b(?:\d{1,3}\.){3}\d{1,3}\b', raw)
        urls   = re.findall(r"https?://[^\s\"'<>\]]+", raw)
        now    = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
        bundle_id = "bundle--" + hashlib.md5(sha256.encode()).hexdigest()
        objects = []
        if sha256 or md5:
            hashes = {}
            if sha256: hashes["SHA-256"] = sha256
            if md5:    hashes["MD5"]     = md5
            objects.append({
                "type": "file", "spec_version": "2.1",
                "id":   "file--" + hashlib.md5((sha256+md5).encode()).hexdigest(),
                "hashes": hashes
            })
        for ip in list(set(ips))[:20]:
            objects.append({
                "type": "ipv4-addr", "spec_version": "2.1",
                "id":  "ipv4-addr--" + hashlib.md5(ip.encode()).hexdigest(),
                "value": ip
            })
        for url in list(set(urls))[:20]:
            objects.append({
                "type": "url", "spec_version": "2.1",
                "id":  "url--" + hashlib.md5(url.encode()).hexdigest(),
                "value": url
            })
        bundle = {
            "type": "bundle", "id": bundle_id,
            "spec_version": "2.1",
            "created": now, "modified": now,
            "objects": objects
        }
        with open(dest, "w", encoding="utf-8") as f:
            json.dump(bundle, f, indent=2)
        messagebox.showinfo("STIX Exported",
            f"Exported {len(objects)} STIX objects\n{dest}")
        _auto_gc("export_stix")
    except Exception as e:
        messagebox.showerror("STIX Error", str(e))

def _diff_scans():
    path1 = filedialog.askopenfilename(
        title="Select FIRST report.txt",
        filetypes=[("Text","*.txt"),("All","*.*")])
    if not path1: return
    path2 = filedialog.askopenfilename(
        title="Select SECOND report.txt",
        filetypes=[("Text","*.txt"),("All","*.*")])
    if not path2: return
    pop = tk.Toplevel(root)
    pop.title("Scan Diff")
    pop.configure(bg=C["base"]); pop.geometry("1100x700"); pop.transient(root)
    tk.Label(pop, text="SCAN DIFFERENCES", font=FB, bg=C["base"],
             fg=C["blue"], pady=8).pack()
    panes = tk.Frame(pop, bg=C["base"]); panes.pack(fill=tk.BOTH, expand=True, padx=8)
    for path, title in [(path1, os.path.basename(path1)), (path2, os.path.basename(path2))]:
        col = tk.Frame(panes, bg=C["surface0"]); col.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=4)
        tk.Label(col, text=title, font=FS, bg=C["surface0"],
                 fg=C["mauve"], pady=4).pack()
        sc = tk.Scrollbar(col, orient="vertical", bg=C["surface1"],
                          troughcolor=C["mantle"], relief="flat", bd=0, width=7)
        txt = tk.Text(col, bg=C["mantle"], fg=C["text"], font=("Consolas",8),
                      yscrollcommand=sc.set, relief="flat", bd=0, padx=8, pady=6,
                      wrap="none", state="normal")
        sc.config(command=txt.yview); sc.pack(side=tk.RIGHT, fill=tk.Y)
        txt.pack(fill=tk.BOTH, expand=True)
        try:
            with open(path, encoding="utf-8", errors="replace") as f: content = f.read()
        except Exception: content = "Error reading file."
        txt.insert(tk.END, content); txt.config(state="disabled")
    tk.Button(pop, text="Close", command=pop.destroy,
              bg=C["surface2"], fg=C["text"], font=FS,
              relief="flat", padx=12, pady=6, bd=0, cursor="hand2").pack(pady=6)
