_ym_dl_running = threading.Event()
_ym_dl_cancel  = threading.Event()
_ym_dl_paused  = threading.Event()

def _ym_fetch_counts():
    def _do():
        for label, owner, repo, path, cat in YARA_REPOS:
            files = _github_list_yar_new(owner, repo, path)
            root.after(0, lambda l=label, n=len(files): _repo_counts[l].set(f"[{n}]"))
    threading.Thread(target=_do, daemon=True).start()

def _ym_download_checked():
    from concurrent.futures import ThreadPoolExecutor, as_completed
    selected = [(l,o,r,p,c) for l,o,r,p,c in YARA_REPOS if _repo_vars[l].get()]
    if not selected:
        _yara_log("Select at least one repo!", "WARNING"); return
    if _ym_dl_running.is_set():
        _yara_log("Download already in progress!", "WARNING"); return
    _ym_dl_running.set()
    _ym_dl_cancel.clear()
    _ym_dl_paused.clear()

    root.after(0, _ym_dl_btn_update)

    def _do():
        _bg_nice()
        root.after(0, lambda: _dl_progress_var.set("Fetching file lists..."))
        all_files = []
        with ThreadPoolExecutor(max_workers=len(selected)) as ex:
            futures = {ex.submit(_github_list_yar_new, o, r, p): (l, c)
                       for l,o,r,p,c in selected}
            for fut in as_completed(futures):
                if _ym_dl_cancel.is_set():
                    break
                label, cat = futures[fut]
                try:
                    files = fut.result()
                    for name, url in files:
                        all_files.append((name, url, cat))
                    root.after(0, lambda l=label, n=len(files):
                               _yara_log(f"  {l}: {n} file(s)", "INFO"))
                except Exception as e:
                    root.after(0, lambda l=label, e=e:
                               _yara_log(f"  {l}: fetch error - {e}", "WARNING"))

        if _ym_dl_cancel.is_set():
            root.after(0, lambda: _dl_progress_var.set("❌ Cancelled by user"))
            root.after(0, lambda: _dl_progress_num.set(""))
            _yara_log("Download CANCELLED.", "WARNING")
            _ym_dl_running.clear(); _ym_dl_cancel.clear()
            root.after(0, _ym_dl_btn_update); return

        total = len(all_files)
        if total == 0:
            _yara_log("No files found.", "WARNING")
            root.after(0, lambda: _dl_progress_var.set("No files found."))
            _ym_dl_running.clear(); root.after(0, _ym_dl_btn_update); return

        _yara_log(f"Downloading {total} file(s) — 25 parallel workers...", "INFO")
        root.after(0, lambda t=total: _ym_progbar.config(maximum=t, value=0))


        ok_count   = [0]
        done_count = [0]
        lock       = threading.Lock()

        def _dl_one(args):
            name, url, cat = args

            if _ym_dl_cancel.is_set():
                return False, name

            while _ym_dl_paused.is_set():
                if _ym_dl_cancel.is_set():
                    return False, name
                _time_crash.sleep(0.2)
            return _download_yar_new(name, url, cat, _yara_log), name

        with ThreadPoolExecutor(max_workers=25) as ex:
            futures = {ex.submit(_dl_one, item): item for item in all_files}
            for fut in as_completed(futures):
                if _ym_dl_cancel.is_set():
                    break
                try:
                    success, name = fut.result()
                except Exception:
                    success, name = False, "?"
                with lock:
                    done_count[0] += 1
                    if success: ok_count[0] += 1
                    d = done_count[0]; o = ok_count[0]
                root.after(0, lambda d=d, t=total, n=name, o=o: [
                    _dl_progress_var.set(f"  {n}"),
                    _dl_progress_num.set(f"{d}/{t}  ({o} OK)"),
                    _ym_progbar.config(value=d),
                ])

        if _ym_dl_cancel.is_set():
            root.after(0, lambda: _dl_progress_var.set(f"❌ Cancelled — {ok_count[0]}/{total} saved"))
            _yara_log(f"Download CANCELLED — {ok_count[0]}/{total} saved", "WARNING")
            _checkpoint("RULES", f"YARA download CANCELLED — {ok_count[0]}/{total} rules saved before cancel")
        else:
            root.after(0, lambda: _dl_progress_var.set(f"Done: {ok_count[0]}/{total} OK"))
            _yara_log(f"Download complete: {ok_count[0]}/{total} rules saved", "INFO")
            _checkpoint("RULES", f"YARA download complete — {ok_count[0]}/{total} rules saved to rules/external/")
        root.after(0, lambda: _dl_progress_num.set(""))
        root.after(0, _ym_library_refresh)
        _ym_dl_running.clear(); _ym_dl_cancel.clear(); _ym_dl_paused.clear()
        root.after(0, _ym_dl_btn_update)

    threading.Thread(target=_do, daemon=True).start()

def _ym_download_all():
    for var in _repo_vars.values(): var.set(True)
    _ym_download_checked()

def _ym_uninstall_all():
    if not messagebox.askyesno("Uninstall All YARA",
        "Delete ALL downloaded YARA rules from rules/external/?\n\nThis cannot be undone."):
        return
    deleted = 0
    for fn in os.listdir(RULES_EXTERN_DIR):
        if fn.lower().endswith((".yar",".yara")):
            try: os.remove(os.path.join(RULES_EXTERN_DIR, fn)); deleted += 1
            except Exception: pass
    with _rules_state_lock:
        keys = [k for k in list(_rules_state.keys())
                if _rules_state[k].get("category","local") != "local"]
        for k in keys: _rules_state.pop(k, None)
        _state_save(dict(_rules_state))
    global _yara_rules; _yara_rules = None
    _yara_log(f"Uninstalled {deleted} external YARA rules", "WARNING")
    _ym_library_refresh()

def _ym_sanitize():
    removed = 0; kept = 0
    suspicious_patterns = [
        b"MZ",
        b"\x7fELF",
        b"TVqQAAMAAAAEAAAA",
        b"<script",
    ]
    for folder in (RULES_DIR, RULES_EXTERN_DIR):
        for fn in list(os.listdir(folder)):
            if not fn.lower().endswith((".yar",".yara")): continue
            full = os.path.join(folder, fn)
            try:
                with open(full, "rb") as f: raw = f.read()
                flagged = any(p in raw for p in suspicious_patterns)
                if flagged:
                    os.remove(full)
                    with _rules_state_lock: _rules_state.pop(fn, None)
                    _yara_log(f"  REMOVED (binary content): {fn}", "WARNING")
                    removed += 1
                else:
                    kept += 1
            except Exception: pass
    with _rules_state_lock: _state_save(dict(_rules_state))
    _yara_log(f"Sanitize complete: {removed} removed, {kept} kept", "INFO")
    _ym_library_refresh()

