_YE_OPERATORS = r"\b(and|or|not|any|all|none|true|false)\b"
_YE_MODIFIERS = r"\b(filesize|entrypoint|uint8|uint16|uint32|uint64|uint8be|uint16be|uint32be|uint64be|int8|int16|int32|int64|int8be|int16be|int32be|int64be)\b"

def _ye_highlight(*_):

    for tag in _ye_hl_tags:
        _ye_ed.tag_remove(tag, "1.0", tk.END)
    content = _ye_ed.get("1.0", tk.END)

    def _apply(pattern, tag, flags=re.MULTILINE):
        for m in re.finditer(pattern, content, flags):
            s = f"1.0+{m.start()}c"; e2 = f"1.0+{m.end()}c"
            _ye_ed.tag_add(tag, s, e2)


    _apply(r"//[^\n]*",              "cmt")
    _apply(r"/\*.*?\*/",            "cmt", re.DOTALL)
    _apply(r"\"[^\"]*\"",           "str")
    _apply(r"\{[^}]*\}",            "str")
    _apply(r"/[^/\n]+/[isw]*",       "str")
    _apply(_YE_KEYWORDS,              "kw")
    _apply(_YE_OPERATORS,             "op")
    _apply(_YE_MODIFIERS,             "mod")
    _apply(r"\$\w+|@\w+|#\w+",   "type")
    _apply(r"\b\d+(\.\d+)?(KB|MB|GB)?\b", "num")


    _ye_update_nums()

