        _checkpoint("IOC", f"{fname} — total: {total_ioc}  IPs: {len(iocs.get('ips',[]))}  domains: {len(iocs.get('domains',[]))}  URLs: {len(iocs.get('urls',[]))}")

        _scan_step("VT", fname)
        lo("Uploading to VirusTotal …", "NORM")
        _checkpoint("VT", f"{fname} — submitting to VirusTotal (hash lookup first)")
        vt_stats, _ = _vt_scan(path, lf)
