def _notify(title, message):
    def _do():
        try:
            if sys.platform == "win32":
                ps = ("Add-Type -AssemblyName System.Windows.Forms;"
                      f"$n=[System.Windows.Forms.NotifyIcon]::new();"
                      "$n.Icon=[System.Drawing.SystemIcons]::Information;"
                      "$n.Visible=$true;"
                      f"$n.ShowBalloonTip(4000,'{title}','{message[:100]}',0);"
                      "Start-Sleep -s 5; $n.Dispose()")
                subprocess.Popen(["power" + "shell","-WindowStyle","Hidden","-Command", ps],
                                 creationflags=0x08000000)
            elif sys.platform == "darwin":
                subprocess.Popen(["osascript","-e",
                    f'display notification "{message}" with title "{title}"'])
            else:
                subprocess.Popen(["notify-send", title, message], creationflags=0x08000000 if sys.platform=="win32" else 0)
        except Exception: pass
    threading.Thread(target=_do, daemon=True).start()

_watcher_observer = [None]
_watcher_path     = [None]

class _ScanOnCreate(_WatchHandler):
    def on_created(self, event):
        if event.is_directory: return
        path = event.src_path
        time.sleep(0.6)
        root.after(0, lambda p=path: _enqueue(p))
        root.after(0, lambda p=path: _log_ops(f"[AutoScan] {p}", "DIM"))
        _notify("V0RTEX", f"Auto-scanning: {os.path.basename(path)}")

def _watcher_start(folder):
    if _WatchObserver is None:
        messagebox.showerror("Auto-Scan", "watchdog not installed."); return
    _watcher_stop()
    try:
        obs = _WatchObserver()
        obs.schedule(_ScanOnCreate(), folder, recursive=False)
        obs.start()
        _watcher_observer[0] = obs
        _watcher_path[0]     = folder
        root.after(0, lambda: _sv_watcher.set(f"Watch: {os.path.basename(folder)[:20]}"))
        _log_ops(f"[AutoScan] Watching: {folder}", "GOOD")
        _notify("V0RTEX", f"Auto-scan: {folder}")
    except Exception as e:
        messagebox.showerror("Auto-Scan", str(e))

def _watcher_stop():
    obs = _watcher_observer[0]
    if obs:
        try: obs.stop(); obs.join(timeout=3)
        except Exception: pass
        _watcher_observer[0] = None
        root.after(0, lambda: _sv_watcher.set("Watch: OFF"))
        _log_ops("[AutoScan] Stopped", "DIM")

def _watcher_toggle():
    _sl("Watcher toggled", "WATCH")
    if _watcher_observer[0]:
        _watcher_stop()
    else:
        folder = filedialog.askdirectory(title="Choose folder to watch")
        if folder: _watcher_start(folder)

def _notify(title, msg, urgent=False):
    try:
        toast = tk.Toplevel(root)
        toast.overrideredirect(True)
        toast.attributes("-topmost", True)
        toast.configure(bg=C["red"] if urgent else C["surface1"])
        icon = "🚨" if urgent else "ℹ"
        tk.Label(toast, text=f"{icon}  {title}", font=FB,
                 bg=C["red"] if urgent else C["surface1"],
                 fg=C["base"] if urgent else C["text"],
                 padx=14, pady=6).pack(anchor="w")
        tk.Label(toast, text=msg[:80], font=FS,
                 bg=C["red"] if urgent else C["surface1"],
                 fg=C["base"] if urgent else C["subtext"],
                 padx=14, pady=4).pack(anchor="w")
        root.update_idletasks()
        sw = root.winfo_screenwidth(); sh = root.winfo_screenheight()
        toast.update_idletasks()
        tw = toast.winfo_width(); th = toast.winfo_height()
        toast.geometry(f"+{sw - tw - 24}+{sh - th - 64}")
        toast.after(4500, toast.destroy)
    except Exception: pass


_tray_icon = None

def _make_tray_image():
    try:
        img  = _PilImage.new("RGBA", (64,64), (0,0,0,0))
        draw = _PilDraw.Draw(img)
        draw.ellipse([4,4,60,60], fill=(137,180,250,255))
        draw.ellipse([16,16,48,48], fill=(13,13,20,230))
        return img
    except Exception:
        try:
            img = _PilImage.new("RGB", (64,64), color=(13,13,20))
            d   = _PilDraw.Draw(img)
            d.ellipse([8,8,56,56], fill=(203,166,247))
            d.text((18,14), "V0RTEX", fill=(13,13,20))
            return img
        except Exception: return None

def _tray_show():
    try: root.after(0, root.deiconify)
    except Exception: pass

def _tray_exit():
    global _tray_icon
    if _tray_icon:
        try: _tray_icon.stop()
        except Exception: pass
    try: root.after(0, root.destroy)
    except Exception: pass


def _start_tray():
    global _tray_icon
    if not _TRAY_OK: return
    if _tray_icon is not None:
        try: _tray_icon.stop()
        except Exception: pass
        _tray_icon = None
    try:
        img = _make_tray_image()
        if not img: return
        def _show(icon, item):  root.after(0, root.deiconify)
        def _hide(icon, item):  root.after(0, root.withdraw)
        def _quit(icon, item):  icon.stop(); root.after(0, _safe_destroy_root)
        menu = _pystray.Menu(
            _pystray.MenuItem("Show",  _show, default=True),
            _pystray.MenuItem("Hide",  _hide),
            _pystray.Menu.SEPARATOR,
            _pystray.MenuItem("Quit",  _quit),
        )
        _tray_icon = _pystray.Icon("V0RTEX", img, f"{_VX_NAME} v{_VX_VER} by {_VX_AUTH}", menu)
        threading.Thread(target=_tray_icon.run, daemon=True).start()
        _log_debug("Tray icon started", "DEBUG")
    except Exception as e:
        _log_debug(f"Tray: {e}", "WARNING")

def _on_minimize(event):
    try:
        _do_minimize_tray = _gs_v_minimize_tray.get() if "minimize_tray" not in str(event) else False
    except Exception:
        _do_minimize_tray = CONFIG.get("ui_minimize_tray", False)
    if root.state() == "iconic" and _TRAY_OK and _do_minimize_tray:
        root.withdraw()
        _notify("V0RTEX", "Minimized to tray — double-click the icon to restore")

root.bind("<Unmap>", _on_minimize)


