_SP_MAX_LINES = 500

def _sp_log(msg, tag="DIM"):
    def _do():
        _sp_out.config(state="normal")
        _sp_out.insert(tk.END, "["+time.strftime("%H:%M:%S")+"]  "+msg+"\n", tag)
        try:
            lines = int(_sp_out.index("end-1c").split(".")[0])
            if lines > _SP_MAX_LINES:
                _sp_out.delete("1.0", f"{lines - _SP_MAX_LINES + 1}.0")
        except Exception:
            pass
        _sp_out.config(state="disabled")
    root.after(0, _do)

_sp_running = threading.Event()
_sp_current_proc = [None]

def _sp_kill():
    p = _sp_current_proc[0]
    if p and _sp_running.is_set():
        try:
            if _psutil:
                try:
                    par = _psutil.Process(p.pid)
                    for ch in par.children(recursive=True):
                        try: ch.kill()
                        except Exception: pass
                    par.kill()
                except Exception: p.kill()
            else:
                p.kill()
            _sp_log("  \u26a1 PROCESS TERMINATED BY USER", "WARN")
        except Exception as e:
            _sp_log(f"  Kill failed: {e}", "BAD")
    _sp_running.clear()
    root.after(0, lambda: _sp_status_var.set("\u23f9 Stopped"))

def _sp_run():
    if _sp_running.is_set():
        _sp_status_var.set("Already running!"); return
    target = _sp_file_var.get().strip()
    if not target:
        _sp_status_var.set("No file selected."); return
    if not os.path.exists(target):
        messagebox.showerror("Sandbox", f"File not found:\n{target}"); return
    try:
        timeout = int(_sp_timeout_var.get())
    except ValueError:
        timeout = 10
    _sp_running.set()
    _sp_status_var.set(f"\u25ba Running (timeout {timeout}s)\u2026")
    _sp_out.config(state="normal"); _sp_out.delete("1.0", tk.END); _sp_out.config(state="disabled")

    def _do():
        _sp_log(f">_ Sandbox: {os.path.basename(target)}", "PROC")
        _sp_log(f"   Timeout: {timeout}s", "DIM")
        monitor_fs   = _sp_opt_fs.get()
        monitor_net  = _sp_opt_net.get()
        monitor_proc = _sp_opt_proc.get()
        snap_before = _fs_snapshot(os.path.dirname(target)) if monitor_fs else set()
        net_before  = (_net_snapshot() if monitor_net else set())
        proc_names  = set()
        snap_after  = set(); net_after = set()
        isolate = _sp_opt_isolate.get()
        _sandbox_drop_dir = [None]

        def _launch_isolated(cmd, cwd):
            import ctypes, uuid, shutil, tempfile
            _sp_log("  ⬡ Isolation mode: active", "PROC")
            if sys.platform == "win32":
                PROCESS_ALL_ACCESS = 0x1FFFFF
                JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE  = 0x00002000
                JOB_OBJECT_LIMIT_PROCESS_MEMORY     = 0x00000100
                JOB_OBJECT_LIMIT_ACTIVE_PROCESS     = 0x00000008
                JOB_OBJECT_UILIMIT_DESKTOP          = 0x0010
                JOB_OBJECT_UILIMIT_HANDLES          = 0x0001
                JOB_OBJECT_UILIMIT_EXITWINDOWS      = 0x0040
                try:
                    p = subprocess.Popen(
                        cmd, cwd=cwd,
                        stdout=subprocess.DEVNULL,
                        stderr=subprocess.DEVNULL,
                        creationflags=0x00000004 | 0x00000200,
                    )
                    k32 = ctypes.windll.kernel32
                    hjob = k32.CreateJobObjectW(None, None)
                    if hjob:
                        class JOBOBJECT_BASIC_LIMIT_INFORMATION(ctypes.Structure):
                            _fields_ = [
                                ("PerProcessUserTimeLimit", ctypes.c_longlong),
                                ("PerJobUserTimeLimit",     ctypes.c_longlong),
                                ("LimitFlags",             ctypes.c_ulong),
                                ("MinimumWorkingSetSize",  ctypes.c_size_t),
                                ("MaximumWorkingSetSize",  ctypes.c_size_t),
                                ("ActiveProcessLimit",     ctypes.c_ulong),
                                ("Affinity",               ctypes.c_ulong),
                                ("PriorityClass",          ctypes.c_ulong),
                                ("SchedulingClass",        ctypes.c_ulong),
                            ]
                        class JOBOBJECT_EXTENDED_LIMIT_INFORMATION(ctypes.Structure):
                            _fields_ = [
                                ("BasicLimitInformation",  JOBOBJECT_BASIC_LIMIT_INFORMATION),
                                ("IoInfo",                 ctypes.c_byte * 16),
                                ("ProcessMemoryLimit",     ctypes.c_size_t),
                                ("JobMemoryLimit",         ctypes.c_size_t),
                                ("PeakProcessMemoryUsed",  ctypes.c_size_t),
                                ("PeakJobMemoryUsed",      ctypes.c_size_t),
                            ]
                        jeli = JOBOBJECT_EXTENDED_LIMIT_INFORMATION()
                        jeli.BasicLimitInformation.LimitFlags = (
                            JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE |
                            JOB_OBJECT_LIMIT_PROCESS_MEMORY    |
                            JOB_OBJECT_LIMIT_ACTIVE_PROCESS
                        )
                        jeli.BasicLimitInformation.ActiveProcessLimit = 8
                        jeli.ProcessMemoryLimit = 256 * 1024 * 1024
                        k32.SetInformationJobObject(hjob, 9,
                            ctypes.byref(jeli), ctypes.sizeof(jeli))
                        class JOBOBJECT_BASIC_UI_RESTRICTIONS(ctypes.Structure):
                            _fields_ = [("UIRestrictionsClass", ctypes.c_ulong)]
                        juir = JOBOBJECT_BASIC_UI_RESTRICTIONS()
                        juir.UIRestrictionsClass = JOB_OBJECT_UILIMIT_HANDLES | JOB_OBJECT_UILIMIT_EXITWINDOWS
                        k32.SetInformationJobObject(hjob, 4,
                            ctypes.byref(juir), ctypes.sizeof(juir))
                        hproc = k32.OpenProcess(PROCESS_ALL_ACCESS, False, p.pid)
                        k32.AssignProcessToJobObject(hjob, hproc)
                        k32.CloseHandle(hproc)
                        import ctypes.wintypes as _wt
                        try:
                            hthread = k32.OpenThread(0x0002, False,
                                         k32.GetThreadId(ctypes.c_void_p(p._handle)))
                            k32.ResumeThread(hthread)
                            k32.CloseHandle(hthread)
                        except Exception:
                            pass
                        _sp_log("  ⬡ Job Object: kill-on-close | 256MB RAM cap | max 8 child procs", "PROC")
                    else:
                        pass
                        _sp_log("  ⬡ Job Object unavailable — running in temp dir only", "WARN")
                    return p
                except Exception as _je:
                    _sp_log(f"  ⬡ Job Object error: {_je} — fallback to plain run", "WARN")
                    return subprocess.Popen(cmd, cwd=cwd,
                        stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            else:
                for _iso_tool in ["firejail", "bwrap", "unshare"]:
                    try:
                        if _iso_tool == "firejail":
                            wrapped = ["firejail", "--quiet", "--noprofile",
                                       "--private", f"--whitelist={cwd}",
                                       "--net=none", "--caps.drop=all",
                                       "--noroot"] + cmd
                        elif _iso_tool == "bwrap":
                            wrapped = ["bwrap", "--ro-bind", "/usr", "/usr",
                                       "--ro-bind", "/lib", "/lib",
                                       "--ro-bind", "/lib64", "/lib64",
                                       "--bind", cwd, cwd,
                                       "--proc", "/proc",
                                       "--dev", "/dev",
                                       "--unshare-net", "--unshare-pid",
                                       "--die-with-parent"] + cmd
                        else:
                            wrapped = ["unshare", "--net", "--pid", "--fork",
                                       "--mount-proc"] + cmd
                        import shutil as _sh
                        if not _sh.which(wrapped[0]):
                            continue
                        p = subprocess.Popen(wrapped, cwd=cwd,
                            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
                        _sp_log(f"  ⬡ Isolation via {_iso_tool}", "PROC")
                        return p
                    except Exception:
                        continue
                _sp_log("  ⬡ No isolation tool found (firejail/bwrap/unshare) — running in temp dir", "WARN")
                return subprocess.Popen(cmd, cwd=cwd,
                    stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)

        try:
            import uuid as _uuid, shutil as _shutil
            if isolate:
                _tmp_dir = os.path.join(BASE_DIR, "sandbox_env", "drop",
                                        "run_" + _uuid.uuid4().hex[:8])
                os.makedirs(_tmp_dir, exist_ok=True)
                _sandbox_drop_dir[0] = _tmp_dir
                _tmp_target = os.path.join(_tmp_dir, os.path.basename(target))
                _shutil.copy2(target, _tmp_target)
                _sp_log(f"  ⬡ Copied to: {_tmp_dir}", "DIM")
                run_target = _tmp_target
                run_cwd    = _tmp_dir
            else:
                run_target = target
                run_cwd    = os.path.dirname(target) or None

            cmd = [sys.executable, run_target] if run_target.lower().endswith(".py") else [run_target]
            if isolate:
                proc = _launch_isolated(cmd, run_cwd)
            else:
                proc = subprocess.Popen(cmd, cwd=run_cwd,
                    stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            _sp_current_proc[0] = proc
            _sp_log(f">_ PID {proc.pid} started", "PROC")
            deadline = time.time() + timeout
            while time.time() < deadline and _sp_running.is_set():
                time.sleep(0.5)
                if proc.poll() is not None:
                    _sp_log(f"   Terminated (exit={proc.returncode})", "OK"); break
                if not _psutil or not monitor_proc: continue
                try:
                    parent = _psutil.Process(proc.pid)
                    for pp in [parent] + parent.children(recursive=True):
                        try:
                            key = f"{pp.name()}:{pp.pid}"
                            if key not in proc_names:
                                proc_names.add(key)
                                try:
                                    mem_mb = pp.memory_info().rss / 1048576
                                    _sp_log(f"  PROC  {pp.name():<22} PID={pp.pid:<6} MEM={mem_mb:.1f}MB", "PROC")
                                except Exception:
                                    _sp_log(f"  PROC  {pp.name():<22} PID={pp.pid}", "PROC")
                        except Exception: pass
                except Exception: pass
            try:
                if proc.poll() is None:
                    proc.terminate(); proc.wait(timeout=3)
            except Exception: pass
        except PermissionError:
            _sp_log("  \u26a0 PermissionError — run as admin", "BAD")
        except FileNotFoundError:
            _sp_log(f"  \u2717 File not found: {target}", "BAD")
        except Exception as e:
            _sp_log(f"  \u2717 Error: {e}", "BAD")
        finally:
            if _sandbox_drop_dir[0] and os.path.isdir(_sandbox_drop_dir[0]):
                try:
                    import shutil as _sh2
                    _sh2.rmtree(_sandbox_drop_dir[0], ignore_errors=True)
                    _sp_log("  \u29e1 Temp dir cleaned up", "DIM")
                except Exception: pass
        _sp_current_proc[0] = None
        if monitor_fs:
            snap_after = _fs_snapshot(os.path.dirname(target))
            new_files = snap_after - snap_before
            del_files = snap_before - snap_after
            if new_files:
                _sp_log(f"\n>_ FILES CREATED ({len(new_files)}):", "FILE")
                for ff in sorted(new_files)[:30]:
                    sus = any(x in ff.upper() for x in ["TEMP","TMP","APPDATA","\\RUN","\\STARTUP"])
                    _sp_log(f"  {(chr(9888)+' ') if sus else '+ '}{ff}", "WARN" if sus else "FILE")
            if del_files:
                _sp_log(f">_ FILES DELETED ({len(del_files)}):", "WARN")
                for ff in sorted(del_files)[:10]: _sp_log(f"  - {ff}", "WARN")
        if monitor_net:
            net_after = _net_snapshot()
            new_conns = net_after - net_before
            if new_conns:
                _sp_log(f"\n>_ CONNECTIONS ({len(new_conns)}):", "NET")
                for c in sorted(new_conns)[:20]:
                    try: port = int(c.rsplit(":",1)[-1])
                    except Exception: port = 0
                    sus_port = port in (4444,1337,8888,9999,31337,5555,6667,6666,3389)
                    _sp_log(f"  {(chr(9888)+' ') if sus_port else '  '}{c}", "BAD" if sus_port else "NET")
        nf = len((snap_after - snap_before) if monitor_fs else set())
        nc = len((net_after - net_before) if monitor_net else set())
        if not nf and not nc:
            _sp_log(f"\n>_ CLEAN — No file/network changes detected in {os.path.dirname(target) if monitor_fs else '(fs monitoring off)'}", "OK")
        else:
            _sp_log(f"\n>_ SUMMARY: {len(proc_names)} processes | {nf} file | {nc} connections", "WARN")
            if nf or nc:
                _notify("Sandbox Alert", f"{nf} new files, {nc} connections", urgent=True)
        root.after(0, lambda: _sp_status_var.set("\u2713 Completed"))
        _sp_running.clear()

    threading.Thread(target=_do, daemon=True).start()

def _fs_snapshot(folder, max_files=2000):
    """Snapshot filesystem — capped at max_files to avoid timeout on large dirs."""
    result = set()
    count = 0
    try:
        for dirpath, dirs, files in os.walk(folder):

            dirs[:] = [d for d in dirs if d not in ('__pycache__', '.git', 'node_modules', '.tox')]
            for fn in files:
                try:
                    result.add(os.path.join(dirpath, fn))
                    count += 1
                    if count >= max_files:
                        return result
                except Exception: pass
    except Exception: pass
    return result

def _net_snapshot():
    if not _psutil: return set()
    result = set()
    try:
        for c in _psutil.net_connections(kind="inet"):
            if c.raddr:
                result.add(f"{c.raddr.ip}:{c.raddr.port}")
    except Exception: pass
    return result

