def _sb_log(msg, tag="DIM"):
    ts = time.strftime("%H:%M:%S")
    line = f"[{ts}]  {msg}"
    _sb_log_lines.append(line)
    def _do():
        w = _sb_log_text_ref[0]
        if w is None: return
        w.config(state="normal")
        w.insert(tk.END, line + "\n", tag)
        w.see(tk.END)
        w.config(state="disabled")
    root.after(0, _do)


