_sandbox_build_lock = [False]
def _sandbox_build():
    if _sandbox_build_lock[0]: return
    _sandbox_build_lock[0] = True
    try:
        _sandbox_build_real()
    finally:
        _sandbox_build_lock[0] = False

def _sandbox_build_real():
    sdir = _sandbox_dir_var.get().strip()
    drop = os.path.join(sdir, "drop")
    try:
        os.makedirs(drop, exist_ok=True)
        readme_text = (
            f"{_VX_TITLE} — Sandbox Environment\n"
            "=" * 50 + "\n"
            f"Built: {time.strftime('%Y-%m-%d %H:%M:%S')}\n\n"
            "Drop folder:  sandbox_env/drop/\n"
            "Place suspicious files in drop/ — V0RTEX will detect\n"
            "and auto-scan them if the watchdog is enabled.\n\n"
            "WARNING\n"
            "-------\n"
            "This environment provides FILE MONITORING only.\n"
            "It does NOT provide process isolation or memory sandboxing.\n"
            "Never execute untrusted malware outside a dedicated VM.\n"
        )
        readme_path = os.path.join(sdir, "README.txt")
        with open(readme_path, "w", encoding="utf-8") as f:
            f.write(readme_text)
        _sandbox_built_var.set(True)
        _sb_status_sv.set("BUILT")
        _sbs_ind.config(fg=C["green"])
        _sb_log(f"Sandbox built: {sdir}", "OK")
        _sb_log(f"Drop folder: {drop}", "OK")
        _sb_log(f"README written: {readme_path}", "OK")
        if _sb_watch_drop_var.get():
            _sandbox_start_drop_watch(drop)

        _pop = tk.Toplevel(root)
        _pop.title("Sandbox Built — README")
        _pop.configure(bg=C["base"]); _pop.resizable(False, False)
        _pop.transient(root); _pop.grab_set()
        _pop.geometry("520x340")
        _px = root.winfo_x() + root.winfo_width()//2 - 260
        _py = root.winfo_y() + root.winfo_height()//2 - 170
        _pop.geometry(f"+{_px}+{_py}")
        tk.Label(_pop, text="✅  Sandbox Environment Built",
                 font=("Consolas", 11, "bold"), bg=C["base"], fg=C["green"]).pack(pady=(14, 4), padx=16, anchor="w")
        tk.Frame(_pop, bg=C["green"], height=1).pack(fill=tk.X, padx=16)
        _rtxt = tk.Text(_pop, bg=C["mantle"], fg=C["text"], font=("Consolas", 9),
                        relief="flat", bd=0, padx=12, pady=10,
                        state="normal", wrap="word", height=10)
        _rtxt.pack(fill=tk.BOTH, expand=True, padx=16, pady=8)
        _rtxt.insert("1.0", readme_text)
        _rtxt.config(state="disabled")
        tk.Button(_pop, text="  OK  ", command=_pop.destroy,
                  bg=C["green"], fg=C["base"], font=("Consolas", 9, "bold"),
                  relief="flat", padx=14, pady=4, cursor="hand2", bd=0
                  ).pack(pady=(0, 12))
    except Exception as e:
        _sb_log(f"Build error: {e}", "BAD")
        messagebox.showerror("Sandbox", f"Build error:\n{e}")

def _sandbox_dismantle():
    global _sb_drop_observer
    sdir = _sandbox_dir_var.get().strip()
    if not _sandbox_built_var.get():
        _sb_log("Sandbox not built", "WARN"); return
    if not messagebox.askyesno("Dismantle", f"Remove the sandbox?\n{sdir}"):
        return

    if _sb_drop_observer:
        try: _sb_drop_observer.stop(); _sb_drop_observer.join(timeout=2)
        except Exception: pass
        _sb_drop_observer = None
    try:
        import shutil
        shutil.rmtree(sdir, ignore_errors=True)
        _sandbox_built_var.set(False)
        _sb_status_sv.set("NOT BUILT")
        _sbs_ind.config(fg=C["red"])
        _sb_log("Sandbox removed", "WARN")
    except Exception as e:
        _sb_log(f"Dismantle error: {e}", "BAD")

def _sandbox_start_drop_watch(drop_folder):
    global _sb_drop_observer
    if _WatchObserver is None:
        _sb_log("watchdog not installed (pip install watchdog)", "BAD"); return
    if _sb_drop_observer:
        try: _sb_drop_observer.stop(); _sb_drop_observer.join(timeout=2)
        except Exception: pass
    class _DropHandler(_WatchHandler):
        def on_created(self, event):
            if event.is_directory: return
            p = event.src_path
            if os.path.basename(p).startswith((".", "~", "$")): return
            _sb_log(f"Drop: {os.path.basename(p)}", "WARN")
            if _wd_autoscan_var.get():
                try: delay = float(_wd_delay_var.get())
                except ValueError: delay = 1.0
                time.sleep(delay)
                _enqueue(p)
    obs = _WatchObserver()
    obs.schedule(_DropHandler(), drop_folder, recursive=False)
    obs.start()
    _sb_drop_observer = obs
    _sb_log(f"Drop watch active: {drop_folder}", "OK")

