def _exp_csv():
    path = filedialog.asksaveasfilename(defaultextension=".csv",
           filetypes=[("CSV","*.csv"),("All","*.*")], title="Save CSV")
    if not path: return
    def _do():
        try:
            rows = _db_query("SELECT * FROM scans ORDER BY timestamp DESC")
            import csv
            with open(path, "w", newline="", encoding="utf-8") as f:
                w = csv.writer(f)
                w.writerow(["timestamp","filename","md5","sha1","sha256",
                             "malicious","suspicious","undetected","yara","filetype","entropy"])
                for r in rows:
                    try:
                        vt = json.loads(r[5]) if r[5] else {}
                        w.writerow([r[1],r[2],r[3],r[4],r[5],
                                    vt.get("malicious",0),vt.get("suspicious",0),
                                    vt.get("undetected",0),r[6],r[9],r[10]])
                    except Exception: pass
            root.after(0, lambda: _exp_status.set(f"✓ CSV: {path}  ({len(rows)} rows)"))
        except Exception as e: root.after(0, lambda: _exp_status.set(f"✗ {e}"))
    threading.Thread(target=_do, daemon=True).start()

def _exp_json():
    path = filedialog.asksaveasfilename(defaultextension=".json",
           filetypes=[("JSON","*.json"),("All","*.*")], title="Save JSON")
    if not path: return
    def _do():
        try:
            rows = _db_query("SELECT * FROM scans ORDER BY timestamp DESC")
            out = []
            for r in rows:
                try:
                    vt = json.loads(r[5]) if r[5] else {}
                    out.append({"ts":r[1],"file":r[2],"md5":r[3],"sha1":r[4],
                                "vt":vt,"yara":r[6],"filetype":r[9],"entropy":r[10]})
                except Exception: pass
            with open(path, "w", encoding="utf-8") as f: json.dump(out, f, indent=2)
            root.after(0, lambda: _exp_status.set(f"✓ JSON: {path}  ({len(out)} scans)"))
        except Exception as e: root.after(0, lambda: _exp_status.set(f"✗ {e}"))
    threading.Thread(target=_do, daemon=True).start()

def _exp_zip():
    path = filedialog.asksaveasfilename(defaultextension=".zip",
           filetypes=[("ZIP","*.zip"),("All","*.*")], title="Save ZIP backup")
    if not path: return
    def _do():
        import zipfile
        try:
            count = 0
            with zipfile.ZipFile(path, "w", zipfile.ZIP_DEFLATED) as zf:
                zf.write(DB_PATH, "scan_history.db")
                zf.write(CONFIG_PATH, "config.json")
                if os.path.exists(WHITELIST_PATH): zf.write(WHITELIST_PATH, "whitelist.txt")
                for fn in os.listdir(RULES_DIR):
                    if fn.endswith((".yar",".yara")):
                        zf.write(os.path.join(RULES_DIR,fn), os.path.join("rules",fn))
                for dn in os.listdir(REPORTS_DIR):
                    dp = os.path.join(REPORTS_DIR, dn)
                    if os.path.isdir(dp):
                        for fn in os.listdir(dp):
                            zf.write(os.path.join(dp,fn), os.path.join("reports",dn,fn)); count+=1
            root.after(0, lambda: _exp_status.set(f"✓ ZIP: {path}  ({count} report)"))
        except Exception as e: root.after(0, lambda: _exp_status.set(f"✗ {e}"))
    threading.Thread(target=_do, daemon=True).start()

