def _ckpt_clear():
    try:
        w = _ckpt_txt_ref[0]
        if w:
            w.config(state="normal"); w.delete("1.0", "end"); w.config(state="disabled")
        _ckpt_buffer.clear(); _ckpt_counter[0] = 0
        _ckpt_count_sv.set("0 checkpoints")
    except Exception: pass

def _ckpt_export():
    try:
        import tkinter.filedialog as _fd
        path = _fd.asksaveasfilename(defaultextension=".txt",
               filetypes=[("Text","*.txt"),("All","*.*")], title="Export Checkpoints")
        if not path: return
        lines = [f"{_VX_TITLE} — CHECKPOINT EXPORT\n{'='*70}\n"]
        for ts, n, ph, det in _ckpt_buffer:
            lines.append(f"[{ts}] #{n:04d} [{ph:<8}] {det}")
        with open(path, "w", encoding="utf-8") as f:
            f.write("\n".join(lines))
        _ckpt_count_sv.set(f"Exported {len(_ckpt_buffer)} checkpoints → {os.path.basename(path)}")
    except Exception as e:
        _ckpt_count_sv.set(f"Export error: {e}")

