def _defense_log(msg, tag="DIM"):
    import datetime as _dtt
    ts = _dtt.datetime.now().strftime("%H:%M:%S")
    def _do():
        _def_log_txt.config(state="normal")
        _def_log_txt.insert(tk.END, f"[{ts}] {msg}\n", tag)
        _def_log_txt.see(tk.END)
        _def_log_txt.config(state="disabled")
    root.after(0, _do)


