def _defense_scan_now():
    folder = filedialog.askdirectory(title="Choose folder to analyze")
    if folder: _defense_scan_folder(folder)

def _defense_scan_running():
    if not _psutil:
        messagebox.showwarning("Processes", "psutil not available"); return
    _defense_log(">_ Scanning running processes...", "PROMPT")
    def _worker():
        count = threats = 0
        for proc in _psutil.process_iter(["pid","name","exe"]):
            try:
                exe = proc.info.get("exe")
                if not exe or not os.path.exists(exe): continue
                count += 1
                score, reasons = _defense_score_file(exe)
                if score > 0:
                    threats += 1
                    root.after(0, lambda n=proc.info["name"],s=score,r=reasons:
                        _defense_log(f"  ⚠ PROCESS: {n} score={s}", "BAD"))
                    for reason in reasons:
                        root.after(0, lambda r=reason: _defense_log(f"     • {r}", "WARN"))
            except Exception: pass
        root.after(0, lambda: _defense_log(
            f">_ Processes scanned: {count}, suspicious: {threats}", "PROMPT"))
        _auto_gc("defense_scan_processes")
    threading.Thread(target=_worker, daemon=True).start()

