def _quarantine_refresh():
    _quar_tree.delete(*_quar_tree.get_children())
    items = _quar_list()
    _dsv_quarantine_count.set(str(len(items)))
    for m in items:
        size = f"{m.get('size',0)//1024} KB"
        ts   = m.get("timestamp","")[:19].replace("T"," ")
        reason = m.get("reason","—")[:40]
        _quar_tree.insert("", tk.END, values=(m.get("filename","?"), reason, size, ts, m.get("qid","?")))

def _quar_action(action):
    sel = _quar_tree.selection()
    if not sel: messagebox.showinfo("Quarantine","Select a file"); return
    qid = _quar_tree.item(sel[0], "values")[4]
    fname = _quar_tree.item(sel[0], "values")[0]
    if action == "restore":
        if messagebox.askyesno("Restore", f"Restore '{fname}' to its original path?"):
            if _quar_restore(qid): messagebox.showinfo("OK","File restored.")
            else: messagebox.showerror("Error","Restore failed — check the log")
    elif action == "delete":
        if messagebox.askyesno("Delete", f"Permanently delete '{fname}'?\nThis cannot be undone."):
            _quar_delete(qid); messagebox.showinfo("OK","File deleted.")
    elif action == "info":
        try:
            qmeta = os.path.join(QUARANTINE_DIR, f"{qid}.json")
            with open(qmeta,"r",encoding="utf-8") as f: m = json.load(f)
            info = "\n".join(f"{k}: {v}" for k,v in m.items())
            messagebox.showinfo("Quarantine Info", info)
        except Exception: messagebox.showerror("Error","Cannot read metadata")
