def _gs_section(parent, title, color=C["blue"]):
    f = tk.Frame(parent, bg=C["surface0"], padx=16, pady=12); f.pack(fill=tk.X, padx=12, pady=6)
    tk.Label(f, text=title, font=FB, bg=C["surface0"], fg=color).pack(anchor="w")
    tk.Frame(f, bg=color, height=1).pack(fill=tk.X, pady=(4,8))
    return f

def _gs_row(parent, label, var, hint="", width=30, show=None):
    r = tk.Frame(parent, bg=C["surface0"]); r.pack(fill=tk.X, pady=3)
    tk.Label(r, text=label, font=FS, bg=C["surface0"], fg=C["text"], width=36, anchor="w").pack(side=tk.LEFT)
    kw = dict(textvariable=var, font=("Consolas",9), bg=C["mantle"], fg=C["text"],
              insertbackground=C["text"], relief="flat", bd=3, width=width)
    if show: kw["show"] = show
    tk.Entry(r, **kw).pack(side=tk.LEFT)
    if hint: tk.Label(r, text=f"  {hint}", font=("Consolas",7),
                       bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.LEFT)

def _gs_check(parent, label, var, hint=""):
    r = tk.Frame(parent, bg=C["surface0"]); r.pack(fill=tk.X, pady=2)
    tk.Checkbutton(r, text=label, variable=var, font=FS,
                   bg=C["surface0"], fg=C["text"], activebackground=C["surface0"],
                   selectcolor=C["mantle"], relief="flat").pack(side=tk.LEFT)
    if hint: tk.Label(r, text=f"  {hint}", font=("Consolas",7),
                       bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.LEFT)


