def _open_recovery_from_settings():
    if not messagebox.askyesno("Recovery UI",
        "Launch the Recovery UI?\n\n"
        "The main window will be closed.\n"
        "After closing Recovery you can restart the app.",
        parent=root
    ): return

    def _do():
        try:
            for _a in [0.8, 0.5, 0.2, 0.0]:
                try: root.attributes("-alpha", _a); root.update_idletasks()
                except Exception: pass
                import time as _ts2; _ts2.sleep(0.04)
        except Exception: pass
        _RECOVERY_REQUESTED[0] = True
        try: root.quit()
        except Exception: pass

        try:
            import time as _ts3; _ts3.sleep(0.3)
            if not _APP_DYING[0]:
                _APP_DYING[0] = True
                _unified_recovery_ui(tb_str="Launched manually from Settings")
        except Exception: pass
    threading.Thread(target=_do, daemon=True).start()

def _open_recovery_as_admin_from_settings():
    if not messagebox.askyesno("Recovery UI — Administrator",
        "Launch the Recovery UI with ADMINISTRATOR privileges?\n\n"
        "⚠  " + _ADM_BADGE_S + " will be active.\n"
        "This unlocks advanced troubleshooting tabs (Registry,\n"
        "Hosts & Firewall, Process Killer, Defender, Permissions,\n"
        "Services).\n\n"
        "The main window will close. Proceed?"
    ): return
    _log_admin_event("User requested Recovery UI as Administrator from Settings tab")
    try:
        import json as _rjsent2
        import datetime as _dtsen2
        _sent_path2 = os.path.join(BASE_DIR, "Recovery_As_Admin")
        with open(_sent_path2, "w", encoding="utf-8") as _sf2:
            _rjsent2.dump({
                "requested_at": _dtsen2.datetime.now().isoformat(),
                "pid": os.getpid(),
                "reason": "admin relaunch from Settings tab"
            }, _sf2, indent=2)
    except Exception as _se2:
        messagebox.showerror("Error", f"Could not write sentinel: {_se2}")
        return
    def _do():
        try:
            for _a in [0.8, 0.5, 0.2, 0.0]:
                try: root.attributes("-alpha", _a); root.update_idletasks()
                except Exception: pass
                import time as _ts3; _ts3.sleep(0.04)
        except Exception: pass
        try: root.quit()
        except Exception: pass
        try:
            if sys.platform == "win32":
                import ctypes as _cra, subprocess as _spra
                params = " ".join(f'"{a}"' for a in sys.argv[1:])
                ret = _cra.windll.shell32.ShellExecuteW(
                    None, "runas", sys.executable, params.strip() or None, None, 1)
                if ret <= 32:
                    try: os.remove(os.path.join(BASE_DIR, "Recovery_As_Admin"))
                    except Exception: pass
                    _log_admin_event(f"UAC denied from Settings — ShellExecuteW returned {ret}")
            else:
                import subprocess as _spra2
                _spra2.Popen(["sudo", sys.executable] + sys.argv[1:])
        except Exception as _era:
            try: os.remove(os.path.join(BASE_DIR, "Recovery_As_Admin"))
            except Exception: pass
            _log_admin_event(f"Admin Recovery launch error from Settings: {_era}")
    root.after(0, _do)

