def _write_crash_log(code, reason, tb=""):
    _sl(f"CRASH LOG [{code}]: {reason}", "CRASH")
    if tb: _sl(f"TRACEBACK: {tb[:200]}", "CRASH")
    try:
        ts = time.strftime("%Y-%m-%d %H:%M:%S")
        desc = SOC_ERROR_CODES.get(code, SOC_ERROR_CODES[0])
        with open(_crash_log_path, "a", encoding="utf-8") as _f:
            _f.write("=" * 72 + "\n")
            _f.write(f"  {_VX_TITLE} — CRASH REPORT\n")
            _f.write(f"  Timestamp  : {ts}\n")
            _f.write(f"  Error Code : {code}\n")
            _f.write(f"  Code Name  : {desc}\n")
            _f.write(f"  Reason     : {reason}\n")
            if tb:
                _f.write(f"  Traceback  :\n{tb}\n")
            _f.write("=" * 72 + "\n\n")
    except Exception:
        pass

def _crash_popup(code, reason, tb=""):
    _write_crash_log(code, reason, tb)
    desc = SOC_ERROR_CODES.get(code, SOC_ERROR_CODES[0])
    try:
        try:
            popup = tk.Toplevel(root)
        except Exception:
            popup = tk.Toplevel()
        popup.title(f"V0RTEX — Crash  [Code {code}]")
        popup.configure(bg="#0d0d14")
        popup.resizable(True, True)
        popup.attributes("-topmost", True)
        try:
            popup.update_idletasks()
            sw = popup.winfo_screenwidth(); sh = popup.winfo_screenheight()
            pw, ph = 780, 560
            popup.geometry(f"{pw}x{ph}+{(sw-pw)//2}+{(sh-ph)//2}")
        except Exception:
            popup.geometry("780x560")
        try: popup.grab_set()
        except Exception: pass


        hdr = tk.Frame(popup, bg="#f38ba8", pady=8); hdr.pack(fill=tk.X, side=tk.TOP)
        tk.Label(hdr, text=f"  💥  CRASH — Error Code {code}",
                 font=("Consolas",13,"bold"), bg="#f38ba8", fg="#0d0d14").pack(anchor="w", padx=16)


        tk.Frame(popup, bg="#313244", height=1).pack(fill=tk.X, side=tk.BOTTOM)
        btn_f = tk.Frame(popup, bg="#11111b", pady=10); btn_f.pack(fill=tk.X, side=tk.BOTTOM)

        def _exit_app():
            try: popup.destroy()
            except Exception: pass
            _show_kill_terminal()

        def _enter_recovery():
            try: popup.destroy()
            except Exception: pass
            try:
                raise RuntimeError(f"[Code {code}] {reason}")
            except Exception as _re:
                _et, _ev, _etb = type(_re), _re, _re.__traceback__

            def _do_recovery_transition():
                try:
                    for _a in [0.7, 0.4, 0.1, 0.0]:
                        try: root.attributes("-alpha", _a); root.update_idletasks()
                        except Exception: pass
                        import time as _ta; _ta.sleep(0.04)
                except Exception: pass
                _safe_destroy_root()
                import time as _tb2; _tb2.sleep(0.2)

                _unified_recovery_ui(exc_type=_et, exc_val=_ev,
                                     exc_tb=_etb, tb_str=tb or reason)
                import sys as _rsys2; _rsys2.exit(0)
            root.after(0, _do_recovery_transition)

        def _open_logs():
            try:
                log_to_open = _crash_log_path
                if not os.path.exists(log_to_open):

                    dbg = globals().get("DEBUG_DIR", DEBUG_DIR)
                    if os.path.isdir(dbg):
                        logs = sorted([f for f in os.listdir(dbg) if f.endswith(".txt")], reverse=True)
                        if logs: log_to_open = os.path.join(dbg, logs[0])
                if sys.platform == "win32": os.startfile(log_to_open)
                else: subprocess.Popen(["xdg-open", log_to_open])
            except Exception as _le:
                messagebox.showinfo("Logs", f"Log path: {_crash_log_path}\n({_le})")

        tk.Button(btn_f, text="  🛠  ENTER RECOVERY  ",
                  command=_enter_recovery,
                  bg="#1e3a5f", fg="#89b4fa", font=("Consolas",11,"bold"),
                  relief="flat", padx=14, pady=7, cursor="hand2", bd=0
                  ).pack(side=tk.LEFT, padx=(14,4))
        popup.bind("<Return>", lambda e: _enter_recovery())
        tk.Button(btn_f, text="  ⛔  EXIT APPLICATION  ",
                  command=_exit_app,
                  bg="#f38ba8", fg="#0d0d14", font=("Consolas",11,"bold"),
                  relief="flat", padx=14, pady=7, cursor="hand2", bd=0
                  ).pack(side=tk.LEFT, padx=4)
        tk.Button(btn_f, text="  📋  OPEN_LOGS  ",
                  command=_open_logs,
                  bg="#1a2a1a", fg="#a6e3a1", font=("Consolas",11,"bold"),
                  relief="flat", padx=14, pady=7, cursor="hand2", bd=0
                  ).pack(side=tk.LEFT, padx=4)
        tk.Button(btn_f, text=" Close ",
                  command=popup.destroy,
                  bg="#313244", fg="#6c7086", font=("Consolas",9),
                  relief="flat", padx=8, pady=7, cursor="hand2", bd=0
                  ).pack(side=tk.RIGHT, padx=14)


        body = tk.Frame(popup, bg="#1e1e2e", padx=22, pady=10)
        body.pack(fill=tk.BOTH, expand=True, side=tk.TOP)
        tk.Label(body, text="Error Code:", font=("Consolas",9),
                 bg="#1e1e2e", fg="#6c7086").pack(anchor="w")
        tk.Label(body, text=f"  [{code}]  {desc.split('—')[0].strip()}",
                 font=("Consolas",12,"bold"), bg="#1e1e2e", fg="#f38ba8").pack(anchor="w")
        tk.Label(body, text="Description:", font=("Consolas",9),
                 bg="#1e1e2e", fg="#6c7086").pack(anchor="w", pady=(6,0))
        tk.Label(body, text=f"  {desc}", font=("Consolas",9),
                 bg="#1e1e2e", fg="#cdd6f4", wraplength=680, justify="left").pack(anchor="w")
        tk.Label(body, text="Reason:", font=("Consolas",9),
                 bg="#1e1e2e", fg="#6c7086").pack(anchor="w", pady=(6,0))
        tk.Label(body, text=f"  {str(reason)[:200]}", font=("Consolas",9),
                 bg="#1e1e2e", fg="#fab387", wraplength=680, justify="left").pack(anchor="w")
        if tb:
            tk.Label(body, text="Traceback:", font=("Consolas",9),
                     bg="#1e1e2e", fg="#6c7086").pack(anchor="w", pady=(6,0))
            tb_frame = tk.Frame(body, bg="#11111b"); tb_frame.pack(fill=tk.BOTH, expand=True, pady=(2,0))
            tb_sc2 = tk.Scrollbar(tb_frame, orient="vertical", bg="#313244",
                                   troughcolor="#0d0d14", relief="flat", bd=0, width=6)
            tb_txt = tk.Text(tb_frame, bg="#11111b", fg="#f38ba8", font=("Consolas",8),
                              yscrollcommand=tb_sc2.set, relief="flat", bd=0,
                              padx=8, pady=4, wrap="word", state="disabled", height=6)
            tb_sc2.config(command=tb_txt.yview)
            tb_sc2.pack(side=tk.RIGHT, fill=tk.Y); tb_txt.pack(fill=tk.BOTH, expand=True)
            tb_txt.config(state="normal")
            tb_txt.insert(tk.END, tb[-1200:])
            tb_txt.see(tk.END); tb_txt.config(state="disabled")
        tk.Label(body, text=f"  Crash log → crash_log.txt",
                 font=("Consolas",8), bg="#1e1e2e", fg="#45475a").pack(anchor="w", pady=(4,0))
    except Exception:
        try: messagebox.showerror(f"Crash [{code}]", f"{desc}\n\n{str(reason)[:200]}")
        except Exception: pass

def _forced_debug_crash():
    import traceback as _tbmod
    try:
        raise RuntimeError("FORCED_DEBUG_CRASH — triggered manually via Danger Zone [Code -1]")
    except Exception as _e:
        exc_type = type(_e); exc_val = _e; exc_tb = _e.__traceback__
        theater_fn = globals().get("_crash_theater_fn")
        if theater_fn:

            root.after(0, lambda: theater_fn(exc_type, exc_val, exc_tb,
                                             _existing_root=root))
        else:
            tb_s = "".join(_tbmod.format_exception(exc_type, exc_val, exc_tb))
            root.after(0, lambda: _crash_popup(-1, str(_e), tb_s))


def _global_exc_hook(exc_type, exc_val, exc_tb):
    import traceback as _tb
    tb_str = "".join(_tb.format_exception(exc_type, exc_val, exc_tb))
    msg = str(exc_val).lower()
    code = 0
    if "sqlite" in msg or "database" in msg:              code = 1
    elif "yara" in msg:                                   code = 2
    elif "401" in msg or "403" in msg or "apikey" in msg: code = 3
    elif "worker" in msg:                                 code = 4
    elif "config" in msg:                                 code = 5
    elif "report" in msg:                                 code = 6
    elif "tshark" in msg:                                 code = 7
    elif "quarantin" in msg:                              code = 8
    elif "watcher" in msg:                                code = 9
    elif "sandbox" in msg:                                code = 10
    elif "fpdf" in msg or "pdf export" in msg:            code = 11
    elif "stix" in msg:                                   code = 12
    elif "permission" in msg or "access" in msg:          code = 20
    elif "memory" in msg or "memoryerror" in msg:         code = 21
    elif "hash" in msg:                                   code = 22
    elif "429" in msg or "rate" in msg:                   code = 27
    elif "queue" in msg:                                  code = 28
    _write_crash_log(code, str(exc_val)[:400], tb_str[:1200])
    try:
        root.after(0, lambda c=code, m=str(exc_val)[:200], t=tb_str[:800]:
                   _crash_popup(c, m, t))
    except Exception:
        pass

sys.excepthook = _global_exc_hook
_sl("BOOT: L18399", "BOOT")


