def _pd_save_settings():
    try:
        _DEF_SETTINGS["action_on_detect"] = _pd_action_var.get()
        for key in ["auto_quarantine_threshold","entropy_threshold","monitor_interval"]:
            e = getattr(root, f"_pd_entry_{key}", None)
            if e:
                v = e.get().strip()
                if key == "entropy_threshold": _DEF_SETTINGS[key] = float(v)
                else: _DEF_SETTINGS[key] = int(v)
        for key, var in _pd_checks.items():
            _DEF_SETTINGS[key] = var.get()
        _DEF_SETTINGS["scan_extensions"] = _pd_ext_entry.get().split()
        messagebox.showinfo("Settings", "Defense settings saved.")
    except Exception as e: messagebox.showerror("Error", str(e))

