def _ap_bk_write(msg, tag="DIM"):
    import datetime as _dtbk
    ts = _dtbk.datetime.now().strftime("%H:%M:%S")
    def _do():
        _ap_bk_log.config(state="normal")
        _ap_bk_log.insert(tk.END, f"[{ts}] {msg}\n", tag)
        _ap_bk_log.see(tk.END); _ap_bk_log.config(state="disabled")
        try: _ap_bk_status_sv.set(msg[:90])
        except Exception: pass
    root.after(0, _do)

def _ap_bk_create():
    def _w():
        ok, res = _create_full_backup(_ap_bk_write)
        if ok:
            root.after(0, lambda: _ap_bk_write(f">_ ZIP created: {os.path.basename(res)}", "OK"))
            root.after(400, _ap_bk_list)
        else:
            root.after(0, lambda: _ap_bk_write(f">_ ERROR: {res}", "FAIL"))
    threading.Thread(target=_w, daemon=True).start()

def _ap_bk_restore_latest():
    def _w():
        ok, msg = _restore_full_backup(None, _ap_bk_write)
        if ok:
            root.after(0, lambda: _ap_bk_write(f">_ Restore OK: {msg}", "OK"))
            root.after(400, _ap_bk_list)
        else:
            root.after(0, lambda: _ap_bk_write(f">_ ERROR: {msg}", "FAIL"))
    threading.Thread(target=_w, daemon=True).start()

def _ap_bk_restore_choose():
    init_d = BACKUPS_DIR if os.path.isdir(BACKUPS_DIR) else BASE_DIR
    chosen = filedialog.askopenfilename(
        title="Select backup ZIP to restore",
        initialdir=init_d,
        filetypes=[("ZIP backup", "*.zip"), ("All files", "*.*")]
    )
    if chosen:
        def _w():
            ok, msg = _restore_full_backup(chosen, _ap_bk_write)
            if ok:
                root.after(0, lambda: _ap_bk_write(f">_ Restore OK: {msg}", "OK"))
            else:
                root.after(0, lambda: _ap_bk_write(f">_ ERROR: {msg}", "FAIL"))
        threading.Thread(target=_w, daemon=True).start()

def _ap_bk_list():
    _ap_bk_write(">_ Backup disponibili:", "HEAD")
    if os.path.isdir(BACKUPS_DIR):
        bkfiles = sorted([f for f in os.listdir(BACKUPS_DIR) if f.endswith(".zip")], reverse=True)
        if bkfiles:
            for i, bf in enumerate(bkfiles):
                fp = os.path.join(BACKUPS_DIR, bf)
                sz = os.path.getsize(fp) // 1024
                import datetime as _dt_list
                mtime = _dt_list.datetime.fromtimestamp(os.path.getmtime(fp)).strftime("%Y-%m-%d %H:%M")
                marker = " ← LATEST" if i == 0 else ""
                _ap_bk_write(f"  {bf}  [{sz} KB]  {mtime}{marker}", "OK" if i == 0 else "DIM")
        else:
            _ap_bk_write("  No backup found in backups/ — use 'Create Full Backup'", "WARN")
    else:
        _ap_bk_write(f"  backups/ dir not found: {BACKUPS_DIR}", "FAIL")

def _ap_bk_open_dir():
    d = BACKUPS_DIR if os.path.isdir(BACKUPS_DIR) else BASE_DIR
    if sys.platform == "win32": os.startfile(d)
    elif sys.platform == "darwin": subprocess.Popen(["open", d])
    else: subprocess.Popen(["xdg-open", d])

def _ap_bk_emergency_rollback():
    import glob as _glb, zipfile as _zfe, shutil as _shue
    tmp = tempfile.gettempdir()
    candidates = sorted(_glb.glob(os.path.join(tmp, "EMERGENCY_RESTORE_*.zip")), reverse=True)
    if not candidates:
        messagebox.showwarning("Emergency Rollback",
            "No EMERGENCY_RESTORE_*.zip found in temp.\nRun an update first to create one.")
        return
    chosen = candidates[0]
    if not messagebox.askyesno("Emergency Rollback",
        f"Restore from:\n{os.path.basename(chosen)}\n\nThis will overwrite V0rtex_System. Continue?"):
        return
    _ap_bk_write(f"Rolling back from {os.path.basename(chosen)}...", "WARN")
    def _do():
        try:
            vx_sys = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            _shue.rmtree(vx_sys, ignore_errors=True)
            with _zfe.ZipFile(chosen, "r") as _z:
                _z.extractall(vx_sys)
            _ap_bk_write("\u2713 Rollback complete \u2014 restart V0RTEX.", "OK")
            root.after(0, lambda: messagebox.showinfo("Rollback", "Rollback complete.\nPlease restart V0RTEX."))
        except Exception as _re:
            _ap_bk_write(f"\u2717 Rollback failed: {_re}", "FAIL")
    threading.Thread(target=_do, daemon=True).start()

