def _cr_do_encrypt():
    if not _cr_validate(_cr_enc_tgt, _cr_enc_pw, _cr_enc_pw2, "encrypt"): return
    target = _cr_enc_tgt[0]; pw = _cr_enc_pw.get()
    del_src = _cr_enc_del.get()
    def _worker():
        root.after(0, lambda: _cr_enc_status.set("⏳ Encrypting..."))
        root.after(0, lambda: _cr_enc_pbar_val.set(5))
        if os.path.isfile(target):
            try:
                _cr_log(f">_ ENCRYPT: {os.path.basename(target)}", "HEAD")
                root.after(0, lambda: _cr_enc_pbar_val.set(40))
                dst = _crypt_encrypt_file(target, pw, delete_src=del_src)
                sz  = os.path.getsize(dst) // 1024
                root.after(0, lambda: _cr_enc_pbar_val.set(100))
                _cr_log(f"  ✓ → {os.path.basename(dst)}  [{sz} KB]", "OK")
                root.after(0, lambda: _cr_enc_status.set(f"✓ Encrypted: {os.path.basename(dst)}"))
                root.after(1500, lambda: _cr_enc_pbar_val.set(0))
            except Exception as e:
                _cr_log(f"  ✗ Error: {e}", "FAIL")
                root.after(0, lambda: _cr_enc_status.set(f"✗ Error: {e}"))
                root.after(0, lambda: _cr_enc_pbar_val.set(0))
        elif os.path.isdir(target):
            files = [fp2 for r2,_,f2 in os.walk(target) for fp2 in
                     [os.path.join(r2, fn) for fn in f2] if not fp2.endswith(_CRYPT_EXT)]
            total = len(files); ok = 0; fail = 0
            _cr_log(f">_ ENCRYPT FOLDER: {target}  ({total} files)", "HEAD")
            for i, fp2 in enumerate(files):
                try:
                    _crypt_encrypt_file(fp2, pw, delete_src=del_src); ok += 1
                    pct = int((i+1)/max(total,1)*95)+5
                    root.after(0, lambda v=pct: _cr_enc_pbar_val.set(v))
                    root.after(0, lambda ii=i+1, t=total: _cr_enc_prog.set(f"  {ii}/{t} files..."))
                except Exception as e:
                    fail += 1; _cr_log(f"  ✗ {os.path.basename(fp2)}: {e}", "FAIL")
            _cr_log(f">_ Done: {ok} encrypted, {fail} errors", "OK" if fail==0 else "WARN")
            root.after(0, lambda: _cr_enc_status.set(f"✓ Folder: {ok} OK, {fail} err"))
            root.after(0, lambda: _cr_enc_prog.set(""))
            root.after(0, lambda: _cr_enc_pbar_val.set(100))
            root.after(1500, lambda: _cr_enc_pbar_val.set(0))
    threading.Thread(target=_worker, daemon=True).start()


