def _dz_del_external():
    import shutil
    if not messagebox.askyesno("Delete External YARA","Remove all downloaded rules?"): return
    try:
        shutil.rmtree(RULES_EXTERN_DIR); os.makedirs(RULES_EXTERN_DIR, exist_ok=True)
        with _rules_state_lock:
            keys = [k for k,v in list(_rules_state.items()) if v.get("category","local") != "local"]
            for k in keys: _rules_state.pop(k, None)
            _state_save(dict(_rules_state))
        global _yara_rules; _yara_rules = None
        _ym_library_refresh(); messagebox.showinfo("Done","External YARA rules deleted.")
    except Exception as e: messagebox.showerror("Error", str(e))
def _dz_del_all_rules():
    import shutil
    if not messagebox.askyesno("Delete ALL Rules","Delete ALL YARA rules?\nIrreversible."): return
    try:
        for fn in os.listdir(RULES_DIR):
            if fn.lower().endswith((".yar",".yara")): os.remove(os.path.join(RULES_DIR, fn))
        shutil.rmtree(RULES_EXTERN_DIR); os.makedirs(RULES_EXTERN_DIR, exist_ok=True)
        with _rules_state_lock: _rules_state.clear(); _state_save({})
        global _yara_rules; _yara_rules = None
        _ym_library_refresh(); messagebox.showinfo("Done","All YARA rules deleted.")
    except Exception as e: messagebox.showerror("Error", str(e))
