    if not os.path.exists(log_dir):
        messagebox.showinfo("Debug Log", "No log found."); return
    if not messagebox.askyesno("Wipe Debug Logs", "Delete all debug logs?"): return
    shutil.rmtree(log_dir, ignore_errors=True)
