def _sig_browse():
    p=filedialog.askopenfilename(title="Select PE file to verify signature",
        filetypes=[("All files","*.*"),("Executables","*.exe *.dll *.sys *.drv *.ocx *.msi")])
    if p: _sig_path_var.set(p)

def _sig_verify():
    p=_sig_path_var.get().strip()
    if not p or not os.path.isfile(p): messagebox.showwarning("Signature","Select a valid file."); return
    _checkpoint("SIG", f"Signature verification started — file: {os.path.basename(p)}  size: {os.path.getsize(p):,} bytes")
    _sig_out.config(state="normal"); _sig_out.delete("1.0",tk.END); _sig_out.config(state="disabled")
    _sig_set_verdict("⟳","Verifying...",C["yellow"])
    def _do():
        root.after(0,lambda: _sig_log(f"\n  File: {os.path.basename(p)}","HEAD"))
        root.after(0,lambda: _sig_log(f"  Size: {os.path.getsize(p):,} bytes","DIM"))
        if sys.platform=="win32":
            try:
                cmd=["power" + "shell","-NoProfile","-NonInteractive","-WindowStyle","Hidden","-Command",
                     f"$s=Get-AuthenticodeSignature '{p}'; $s|Select Status,SignerCertificate|Format-List; "
                     "$s.SignerCertificate|Select Subject,Issuer,NotBefore,NotAfter,Thumbprint|Format-List"]
                r=subprocess.run(cmd,capture_output=True,text=True,timeout=15)
                out=r.stdout.strip()
                if not out: raise RuntimeError("No output")
                sm=re.search(r"Status\s*:\s*(\S+)",out)
                status=sm.group(1) if sm else "Unknown"
                if status=="Valid":
                    root.after(0,lambda: _sig_set_verdict("✓","SIGNED — Signature Valid",C["green"]))
                    root.after(0,lambda: _sig_log("  ✓ Signature: VALID (Authenticode)","OK"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — VALID Authenticode signature")
                elif status=="NotSigned":
                    root.after(0,lambda: _sig_set_verdict("✗","NOT SIGNED",C["red"]))
                    root.after(0,lambda: _sig_log("  ✗ File is NOT signed","BAD"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — NOT SIGNED")
                elif status=="HashMismatch":
                    root.after(0,lambda: _sig_set_verdict("⚠","TAMPERED — Hash Mismatch",C["red"]))
                    root.after(0,lambda: _sig_log("  ⚠ SIGNATURE TAMPERED — hash mismatch!","BAD"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — ⚠ TAMPERED — hash mismatch")
                else:
                    root.after(0,lambda s=status: _sig_set_verdict("~",f"Status: {s}",C["yellow"]))
                    root.after(0,lambda s=status: _sig_log(f"  ~ Status: {s}","WARN"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — status: {status}")
                root.after(0,lambda o=out: _sig_log("\n  Certificate Details:\n"+o,"INFO"))
                return
            except Exception as e:
                root.after(0,lambda err=str(e): _sig_log(f"  PowerShell: {err}","WARN"))

        try:
            import pefile as _pe3
            pe3=_pe3.PE(p,fast_load=False)
            if not hasattr(pe3,"DIRECTORY_ENTRY_SECURITY"):
                root.after(0,lambda: _sig_set_verdict("✗","NOT SIGNED — No security directory",C["red"]))
                root.after(0,lambda: _sig_log("  ✗ No Authenticode signature (no security directory)","BAD"))
                return
            for entry in pe3.DIRECTORY_ENTRY_SECURITY:
                cert_data=entry.struct.__pack__(); pkcs7=cert_data[8:]
                try:
                    from cryptography.hazmat.primitives.serialization import pkcs7 as _cp7
                    from cryptography import x509
                    certs=_cp7.load_der_pkcs7_certificates(pkcs7)
                    root.after(0,lambda n=len(certs): _sig_set_verdict("✓",f"SIGNED — {n} cert(s) found",C["teal"]))
                    root.after(0,lambda n=len(certs): _sig_log(f"  ✓ PKCS#7 parsed — {n} certificate(s)","OK"))
                    import datetime as _dta
                    for cert in certs:
                        try:
                            subj=cert.subject.rfc4514_string()
                            iss=cert.issuer.rfc4514_string()
                            na=getattr(cert,"not_valid_after_utc",None) or cert.not_valid_after
                            nb=getattr(cert,"not_valid_before_utc",None) or cert.not_valid_before
                            root.after(0,lambda s=subj: _sig_log(f"\n  Subject : {s[:90]}","INFO"))
                            root.after(0,lambda i=iss:  _sig_log(f"  Issuer  : {i[:90]}","DIM"))
                            root.after(0,lambda nb2=str(nb): _sig_log(f"  Valid   : {nb2}  →","DIM"))
                            root.after(0,lambda na2=str(na): _sig_log(f"           {na2}","DIM"))
                            now=_dta.datetime.now(_dta.timezone.utc)
                            expired=now>na.replace(tzinfo=_dta.timezone.utc) if na.tzinfo is None else now>na
                            if expired: root.after(0,lambda: _sig_log("  ⚠  Certificate EXPIRED","BAD"))
                            if cert.subject==cert.issuer: root.after(0,lambda: _sig_log("  ⚠  Self-signed","WARN"))
                        except Exception: pass
                except ImportError:
                    root.after(0,lambda: _sig_set_verdict("~","SIGNED (install cryptography for details)",C["teal"]))
                    root.after(0,lambda: _sig_log("  ✓ Security directory present — pip install cryptography for details","WARN"))
                except Exception as e:
                    root.after(0,lambda err=str(e): _sig_set_verdict("~",f"Cert parse error",C["yellow"]))
                    root.after(0,lambda err=str(e): _sig_log(f"  Certificate parse: {err}","WARN"))
                break
        except ImportError:
            root.after(0,lambda: _sig_set_verdict("~","pefile not installed",C["overlay0"]))
            root.after(0,lambda: _sig_log("  Install pefile: pip install pefile","WARN"))
        except Exception as e:
            root.after(0,lambda err=str(e): _sig_set_verdict("✗","Error",C["red"]))
            root.after(0,lambda err=str(e): _sig_log(f"  Error: {err}","WARN"))
    threading.Thread(target=_do,daemon=True).start()


