_CRED_PATTERNS = {
    "AWS Key":         r"AKIA[0-9A-Z]{16}",
    "GitHub Token":    r"ghp_[A-Za-z0-9]{36}",
    "Private Key":     r"-----BEGIN [A-Z ]+PRIVATE KEY-----",
    "API Key/Secret":  r"(?i)(api[_\-]?key|apikey|api[_\-]?secret)\s*[=:\"']+\s*[A-Za-z0-9\-_]{16,64}",
    "Password Field":  r"(?i)(password|passwd|pwd)\s*[=:\"']+\s*[^\s\"']{6,}",
    "JWT Token":       r"eyJ[A-Za-z0-9_\-]{10,}\.eyJ[A-Za-z0-9_\-]{10,}\.[A-Za-z0-9_\-]{10,}",
    "Google API":      r"AIza[0-9A-Za-z\-_]{35}",
    "Stripe Live Key": r"sk_live_[0-9a-zA-Z]{24}",
    "Connection Str":  r"(?i)password=[^;]{4,}",
    "Bearer Token":    r"(?i)Bearer\s+[A-Za-z0-9\-_\.]{20,}",
}

_scs_results = []
def _scs_run():
    global _scs_results; _scs_results = []
    target = _scs_target_var.get().strip()
    if not target or not os.path.exists(target):
        messagebox.showerror("Secrets","Select a valid file or folder."); return
    files = []
    if os.path.isfile(target): files = [target]
    else:
        for root_d, dirs, fnames in os.walk(target):
            dirs[:] = [d for d in dirs if d not in (".git","node_modules","__pycache__")]
            for fn in fnames:
                if any(fn.endswith(e) for e in [".py",".js",".ts",".php",".rb",".java",".go",
                                                  ".env",".config",".cfg",".ini",".json",".yaml",
                                                  ".yml",".xml",".sh",".bat",".ps1",".txt",".log"]):
                    files.append(os.path.join(root_d,fn))
    _scs_tree.delete(*_scs_tree.get_children())
    _scs_count_sv.set(f"Scanning {len(files)} files…")
    def _do():
        found = 0
        for fp in files:
            try:
                if os.path.getsize(fp) > 5*1024*1024: continue
                with open(fp,"r",encoding="utf-8",errors="ignore") as f:
                    for lno,line in enumerate(f,1):
                        for pname, pat in _CRED_PATTERNS.items():
                            for m in re.finditer(pat,line):
                                match_str = m.group(0)[:80]
                                fname_short = os.path.basename(fp)
                                row = (fname_short, lno, pname, match_str)
                                _scs_results.append((fp,lno,pname,match_str))
                                found += 1
                                tag = "HIGH" if pname in ("AWS Key","Private Key","Stripe Live Key","GitHub Token") else "INFO"
                                root.after(0,lambda r2=row,t=tag:
                                           _scs_tree.insert("","end",values=r2,tags=(t,)))
            except Exception: pass
        root.after(0,lambda n=found: _scs_count_sv.set(f"Done — {n} potential secret(s) found in {len(files)} files"))
    threading.Thread(target=_do,daemon=True).start()

def _scs_export():
    if not _scs_results: return
    p = filedialog.asksaveasfilename(defaultextension=".csv",filetypes=[("CSV","*.csv")])
    if not p: return
    import csv
    with open(p,"w",newline="",encoding="utf-8") as f:
        w=csv.writer(f); w.writerow(["File","Line","Type","Match"])
        w.writerows(_scs_results)
    messagebox.showinfo("Secrets",f"Exported {len(_scs_results)} findings.")


