_arc_stop_flag = [False]
_arc_status_sv  = tk.StringVar(value="Ready.")

_COMMON_PASSWORDS = [
    "","password","123456","admin","infected","malware","sample","virus","test",
    "1234","12345","123456789","password1","pass","letmein","welcome","monkey",
    "dragon","master","abc123","qwerty","iloveyou","sunshine","princess","shadow",
    "malware123","infected123","virus123","sandbox","analysis","reverse","crackme",
    "P@ssw0rd","Password1","Summer2024","Winter2023","Spring2024","Autumn2023",
]

def _arc_run():
    import zipfile as _zf
    fpath = _arc_file_var.get().strip()
    if not fpath or not os.path.isfile(fpath):
        messagebox.showerror("Archive","Select a valid archive."); return
    wl_path = _arc_wl_var.get().strip()
    passwords = list(_COMMON_PASSWORDS)
    if wl_path and os.path.isfile(wl_path):
        try:
            with open(wl_path,"r",errors="ignore") as wf:
                passwords += [l.strip() for l in wf if l.strip()]
        except Exception: pass
    passwords = list(dict.fromkeys(passwords))
    _arc_stop_flag[0] = False
    _arc_log.config(state="normal"); _arc_log.delete("1.0","end"); _arc_log.config(state="disabled")
    _arc_status_sv.set(f"Trying {len(passwords)} passwords…")
    def _do():
        def _log(msg, tag="INFO"):
            colors={"INFO":C["text"],"OK":C["green"],"ERR":C["red"],"WARN":C["yellow"]}
            root.after(0,lambda: (_arc_log.config(state="normal"),
                                   _arc_log.tag_configure(tag,foreground=colors.get(tag,C["text"])),
                                   _arc_log.insert("end",f"{msg}\n",tag),
                                   _arc_log.see("end"),
                                   _arc_log.config(state="disabled")))
        _log(f"Archive: {os.path.basename(fpath)}")
        _log(f"Testing {len(passwords)} password(s)…")
        found = None
        try:
            with _zf.ZipFile(fpath,"r") as z:
                for i,pw in enumerate(passwords):
                    if _arc_stop_flag[0]: _log("Stopped by user.","WARN"); break
                    root.after(0,lambda n=i,t=len(passwords): _arc_status_sv.set(f"{n}/{t} tried…"))
                    try:
                        z.extractall(pwd=pw.encode("utf-8") if pw else None,
                                     path=os.path.join(BASE_DIR,"diff_workspace","extracted"))
                        found = pw
                        _log(f"✅  PASSWORD FOUND: '{pw}'","OK")
                        _log(f"Extracted to: diff_workspace/extracted/","OK")
                        break
                    except (_zf.BadZipFile, RuntimeError): pass
                    except Exception as ex:
                        if "encrypted" in str(ex).lower() or "bad password" in str(ex).lower(): pass
                        else: _log(f"Error at '{pw}': {ex}","WARN")
                if found is None and not _arc_stop_flag[0]:
                    _log("❌  Password not found in wordlist.","ERR")
        except _zf.BadZipFile:
            _log("File is not a valid ZIP archive.","ERR")
        except Exception as ex:
            _log(f"Error: {ex}","ERR")
        root.after(0,lambda f=found: _arc_status_sv.set(f"Done — password: '{f}'" if f else "Done — not found"))
    threading.Thread(target=_do,daemon=True).start()

