def _tf_log(msg, tag="INFO"):
    colors={"INFO":C["text"],"OK":C["green"],"ERR":C["red"],"WARN":C["yellow"]}
    _tf_log_text.config(state="normal")
    _tf_log_text.tag_configure(tag,foreground=colors.get(tag,C["text"]))
    _tf_log_text.insert("end",f"{msg}\n",tag)
    _tf_log_text.see("end")
    _tf_log_text.config(state="disabled")

