tk.Spinbox(_rot_ctrls, from_=1, to=25, textvariable=_rot_shift, width=4,
           font=("Consolas",9), bg=C["mantle"], fg=C["yellow"],
           relief="flat", bd=2, buttonbackground=C["surface2"]).pack(side=tk.LEFT)
