_rot_btnrow = tk.Frame(_tab_rot, bg=C["surface0"], padx=10, pady=6); _rot_btnrow.pack(side=tk.BOTTOM, fill=tk.X)
def _rot_apply():
    txt = _rot_inp.get("1.0", tk.END).rstrip("\n")
    if not txt: return
    def _rot13(s):
        return s.translate(str.maketrans(
            "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz",
            "NOPQRSTUVWXYZABCDEFGHIJKLMnopqrstuvwxyzabcdefghijklm"))
    def _rot47(s):
        return "".join(chr(33+((ord(c)-33+47)%94)) if 33<=ord(c)<=126 else c for c in s)
    def _caesar(s, n):
        res=[]
        for c in s:
            if c.isupper(): res.append(chr((ord(c)-65+n)%26+65))
            elif c.islower(): res.append(chr((ord(c)-97+n)%26+97))
            else: res.append(c)
        return "".join(res)
    m = _rot_mode.get()
    _rot_out.config(state="normal"); _rot_out.delete("1.0",tk.END)
    if m == "ROT13": _rot_out.insert(tk.END, _rot13(txt))
    elif m == "ROT47": _rot_out.insert(tk.END, _rot47(txt))
    elif m == "Caesar": _rot_out.insert(tk.END, _caesar(txt, _rot_shift.get()))
    else:
        for i in range(1,26):
            _rot_out.insert(tk.END, f"[{i:>2}]  {_caesar(txt, i)}\n")
    _rot_out.config(state="disabled")
_mkbtn(_rot_btnrow,"⚡ Apply",lambda:_rot_apply(),C["flamingo"])
_mkbtn(_rot_btnrow,"🗑 Clear",lambda:(_rot_inp.delete("1.0",tk.END),
    _rot_out.config(state="normal"),_rot_out.delete("1.0",tk.END),
    _rot_out.config(state="disabled")),C["surface1"],C["text"])
