_dns_out.tag_configure("HEAD", foreground=C["blue"])
_dns_out.tag_configure("VAL",  foreground=C["green"])
_dns_out.tag_configure("ERR",  foreground=C["red"])
def _dns_run():
    host = _dns_host_v.get().strip()
    if not host: return
    import ipaddress as _ipa
    try:
        _ipa.ip_address(host)
        _dns_out.config(state="normal")
        _dns_out.insert(tk.END, f"  ⚠ {host} is an IP address — DNS type A queries target hostnames.\n"
                        f"  Try PTR (reverse lookup) for IPs, or enter a domain name.\n", "WARN")
        _dns_out.config(state="disabled")
        return
    except ValueError:
        pass
    if not host: return
    rtype = _dns_type_v.get()
    _dns_out.config(state="normal"); _dns_out.delete("1.0",tk.END); _dns_out.config(state="disabled")
    def _do():
        import socket as _sock
        results = []
        try:
            try:
                import dns.resolver as _dnsr
                qtypes = ["A","AAAA","MX","TXT","NS","CNAME"] if rtype=="ALL" else [rtype]
                for qt in qtypes:
                    try:
                        for r in _dnsr.resolve(host, qt, lifetime=5):
                            results.append((qt, str(r)))
                    except Exception: pass
            except ImportError:
                try:
                    ips = _sock.getaddrinfo(host, None)
                    seen = set()
                    for item in ips:
                        ip = item[4][0]
                        if ip not in seen:
                            seen.add(ip); results.append(("A/AAAA", ip))
                except Exception as e:
                    results.append(("ERR", str(e)))
        except Exception as e:
            results.append(("ERR", str(e)))
        def _show():
            _dns_out.config(state="normal")
            _dns_out.insert(tk.END, f"  Lookup: {host}  [{rtype}]\n\n", "HEAD")
            for rt, rv in results:
                _dns_out.insert(tk.END, f"  {rt:<12}", "HEAD")
                _dns_out.insert(tk.END, f"{rv}\n", "VAL")
            if not results:
                _dns_out.insert(tk.END, "  No results.\n", "ERR")
            _dns_out.config(state="disabled")
        root.after(0, _show)
    threading.Thread(target=_do, daemon=True).start()

