def _svc_refresh():
    for row in _svc_tree.get_children(): _svc_tree.delete(row)
    flt = _svc_filter_v.get().strip().lower()
    run_only = _svc_run_only.get()
    def _do():
        rows = []
        if _psutil:
            for p in _psutil.process_iter(["pid","name","status","cpu_percent","memory_info"]):
                try:
                    st = p.info["status"]; nm = p.info["name"] or ""
                    if run_only and st not in ("running","sleeping"): continue
                    if flt and flt not in nm.lower(): continue
                    mem = round(p.info["memory_info"].rss/1048576,1) if p.info["memory_info"] else 0
                    rows.append((p.info["pid"],nm,st,p.info["cpu_percent"],mem))
                except (_psutil.NoSuchProcess, _psutil.AccessDenied): pass
        else:
            rows = [("—","psutil not installed","—","—","—")]
        root.after(0, lambda: [_svc_tree.insert("","end",values=r) for r in rows[:400]])
    threading.Thread(target=_do, daemon=True).start()
