def _hand_refresh():
    for row in _hand_tree.get_children(): _hand_tree.delete(row)
    if _psutil is None:
        _hand_tree.insert("","end",values=("—","psutil not installed","—")); return
    pid_flt = _hand_pid_v.get().strip(); path_flt = _hand_flt_v.get().strip().lower()
    def _do():
        rows = []
        for proc in _psutil.process_iter(["pid","name"]):
            try:
                if pid_flt and str(proc.pid) != pid_flt: continue
                for f in proc.open_files():
                    if path_flt and path_flt not in f.path.lower(): continue
                    rows.append((proc.pid, proc.info["name"], f.path))
                    if len(rows) >= 500: break
            except (_psutil.NoSuchProcess, _psutil.AccessDenied): pass
            if len(rows) >= 500: break
        root.after(0, lambda: [_hand_tree.insert("","end",values=r) for r in rows])
    threading.Thread(target=_do, daemon=True).start()
