def _sig_load(path=None):
    p = path or _sig_path_v.get().strip()
    if not p or not os.path.isfile(p): return
    try:
        with open(p,"r",encoding="utf-8") as f: raw = f.read()
        _sig_raw.config(state="normal"); _sig_raw.delete("1.0",tk.END)
        _sig_raw.insert("1.0",raw); _sig_raw.config(state="disabled")
        try:
            import yaml as _yaml; rule = _yaml.safe_load(raw)
        except ImportError:
            _sig_parsed.config(state="normal"); _sig_parsed.delete("1.0",tk.END)
            _sig_parsed.insert("1.0","PyYAML not installed.  Run V0RTEX Setup/Reinstall to fix.\n")
            _sig_parsed.config(state="disabled"); return
        out = []
        for key in ["title","id","status","description","author","date",
                    "tags","logsource","detection","falsepositives","level"]:
            if key in rule:
                val = rule[key]
                out.append(f"  {key.upper():<20}")
                if isinstance(val,(dict,list)):
                    out.append(json.dumps(val,indent=4).replace("\n","\n    ")+"\n")
                else:
                    out.append(str(val)+"\n")
        _sig_parsed.config(state="normal"); _sig_parsed.delete("1.0",tk.END)
        _sig_parsed.insert("1.0","".join(out)); _sig_parsed.config(state="disabled")
    except Exception as e:
        _sig_parsed.config(state="normal"); _sig_parsed.delete("1.0",tk.END)
        _sig_parsed.insert("1.0",f"Error: {e}"); _sig_parsed.config(state="disabled")
_mkbtn(_sig_ctrl,"📂 Open",lambda:_sig_browse(),C["surface2"],C["text"])
_mkbtn(_sig_ctrl,"🔍 Parse",lambda: _sig_load(),C["blue"])
