def _rs_browse():
    p = filedialog.askopenfilename(title="Open binary file")
    if p: _rs_path_v.set(p)
def _rs_run():
    import re as _re_s
    p = _rs_path_v.get().strip()
    if not p or not os.path.isfile(p):
        messagebox.showwarning("Strings","No file selected."); return
    minl = _rs_minlen.get(); do_uni = _rs_unicode.get()
    _rs_out.config(state="normal"); _rs_out.delete("1.0",tk.END); _rs_out.config(state="disabled")
    def _do():
        try:
            with open(p,"rb") as f: data = f.read()
            ascii_pat = rb'[ -~]{' + str(minl).encode() + rb',}'
            strings = [(m.start(),"ASCII",m.group().decode("ascii","replace"))
                       for m in _re_s.finditer(ascii_pat, data)]
            if do_uni:
                uni_pat = rb'(?:[ -~]\x00){' + str(minl).encode() + rb',}'
                for m in _re_s.finditer(uni_pat, data):
                    try:
                        s = m.group().decode("utf-16-le","replace").rstrip("\x00")
                        strings.append((m.start(),"UTF-16",s))
                    except: pass
            strings.sort(key=lambda x: x[0])
            root.after(0, lambda: _rs_render(strings, p))
        except Exception as e:
            root.after(0, lambda: messagebox.showerror("Strings",str(e)))
    threading.Thread(target=_do, daemon=True).start()
def _rs_render(strings, p):
    _rs_out.config(state="normal"); _rs_out.delete("1.0",tk.END)
    _rs_out.tag_configure("HEAD",   foreground=C["yellow"])
    _rs_out.tag_configure("ASCII",  foreground=C["text"])
    _rs_out.tag_configure("UNI",    foreground=C["blue"])
    _rs_out.tag_configure("OFFSET", foreground=C["overlay0"])
    _rs_out.insert(tk.END, f"  File:    {os.path.basename(p)}\n","HEAD")
    _rs_out.insert(tk.END, f"  Strings: {len(strings):,}\n\n","HEAD")
    for offset, enc, s in strings[:2000]:
        _rs_out.insert(tk.END, f"  {offset:>8x}  [{enc:<6}]  ","OFFSET")
        _rs_out.insert(tk.END, s+"\n","ASCII" if enc=="ASCII" else "UNI")
    if len(strings) > 2000:
        _rs_out.insert(tk.END, f"\n  ... {len(strings)-2000:,} more strings\n","HEAD")
    _rs_out.config(state="disabled")
_mkbtn(_rs_ctrl,"📂 Browse",lambda:_rs_browse(),C["surface2"],C["text"])
