def _ping_log(msg, tag="OUT"):
    def _d():
        _ping_out.config(state="normal")
        _ping_out.insert(tk.END, msg+"\n", tag)
        _ping_out.config(state="disabled")
        _ping_out.see(tk.END)
    root.after(0, _d)
def _ping_run(trace=False):
    host = _ping_host_v.get().strip()
    if not host: return
    _ping_out.config(state="normal"); _ping_out.delete("1.0",tk.END); _ping_out.config(state="disabled")
    count = _ping_count_v.get()
    def _do():
        if sys.platform == "win32":
            cmd = ["tracert","-d",host] if trace else ["ping","-n",str(count),host]
        else:
            cmd = ["traceroute","-n",host] if trace else ["ping","-c",str(count),host]
        _ping_log(f"  > {' '.join(cmd)}", "HEAD")
        try:
            kw = {"creationflags":0x08000000} if sys.platform=="win32" else {}
            proc = subprocess.Popen(cmd, stdout=subprocess.PIPE,
                                    stderr=subprocess.STDOUT, text=True, **kw)
            for line in proc.stdout: _ping_log("  "+line.rstrip())
            proc.wait()
            _ping_log(f"\n  Return code: {proc.returncode}", "HEAD")
        except Exception as e:
            _ping_log(f"  Error: {e}", "ERR")
    threading.Thread(target=_do, daemon=True).start()
_mkbtn(_ping_ctrl,"📶 Ping",lambda: _ping_run(False),C["green"])
_mkbtn(_ping_ctrl,"🛤 Traceroute",lambda: _ping_run(True),C["blue"])
