    _BG      = "#06060f"
    _PNL     = "#0b0b1a"
    _PNL2    = "#0f0f20"
    _BRD     = "#16162a"
    _BRD2    = "#1e1e3a"
    _RED     = "#f38ba8"
    _RED2    = "#ff3366"
    _GRN     = "#a6e3a1"
    _GRN2    = "#00ff88"
    _BLU     = "#89b4fa"
    _YEL     = "#f9e2af"
    _MAU     = "#cba6f7"
    _TEA     = "#94e2d5"
    _DIM     = "#363653"
    _DIM2    = "#45475a"
    _TXT     = "#cdd6f4"
    _SUB     = "#7f849c"
    _PROMPT  = "#89b4fa"
    _SCAN    = "#00ffcc"

    _IS_CRASH = bool(exc_type or missing_files)
    _ACCENT   = _RED if _IS_CRASH else _TEA

    def _rec_is_admin():
        try:
            if _rsys.platform == "win32":
                import ctypes as _rct
                return bool(_rct.windll.shell32.IsUserAnAdmin())
            return _ros.getuid() == 0
        except Exception:
            return False

    def _rec_log_admin(msg):
        try:
            log_dir = _ros.path.join(_tcwd[0] if False else
                                     _ros.path.dirname(_ros.path.abspath(_rsys.argv[0])),
                                     "debug_log")
            _ros.makedirs(log_dir, exist_ok=True)
            with open(_ros.path.join(log_dir, "admin_status.log"), "a", encoding="utf-8") as _f:
                import datetime as _dtrec
                _f.write(f"[{_dtrec.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] RECOVERY: {msg}\n")
        except Exception:
            pass

    _REC_IS_ADMIN = [_rec_is_admin()]
    _rec_log_admin(f"Recovery UI launched — admin={_REC_IS_ADMIN[0]} — PID={_ros.getpid()}")

    _rt.sleep(0.15)
    rr = _rtk.Tk()
    rr.title(f"{_VX_NAME} — RECOVERY TERMINAL  v{_VX_VER}")
    rr.configure(bg=_BG)
    rr.geometry("1120x740")
