    _rec_log_paned.add(_rec_lp_right, minsize=180)

    _rec_llhdr = _rtk.Frame(_rec_lp_left, bg="#11111b", pady=3, padx=8)
    _rec_llhdr.pack(fill=_rtk.X)
    _rtk.Label(_rec_llhdr, text="● ● ●  OPERATION LOG",
               font=("Consolas",8,"bold"), bg="#11111b", fg=_MAU).pack(side=_rtk.LEFT)
    _rec_ll_sc = _rtk.Scrollbar(_rec_lp_left, orient="vertical", bg=_BRD2,
                                  troughcolor="#0a0a10", relief="flat", bd=0, width=6)
    rec_log_txt = _rtk.Text(_rec_lp_left, bg="#0a0a10", fg=_TXT,
                             font=("Consolas",9), yscrollcommand=_rec_ll_sc.set,
                             relief="flat", bd=0, padx=10, pady=6, wrap="word",
                             state="disabled")
    for _rtg, _rfc in [("OK",_GRN2),("ERR",_RED),("WARN",_YEL),("INFO",_BLU),
                        ("HEAD",_MAU),("DIM",_DIM2)]:
        rec_log_txt.tag_configure(_rtg, foreground=_rfc)
    _rec_ll_sc.config(command=rec_log_txt.yview)
    _rec_ll_sc.pack(side=_rtk.RIGHT, fill=_rtk.Y)
    rec_log_txt.pack(fill=_rtk.BOTH, expand=True)

    _rec_lrhdr = _rtk.Frame(_rec_lp_right, bg="#0a0508", pady=3, padx=8)
    _rec_lrhdr.pack(fill=_rtk.X)
    _rtk.Label(_rec_lrhdr, text="● ● ●  RAW OUTPUT",
               font=("Consolas",8,"bold"), bg="#0a0508", fg=_GRN).pack(side=_rtk.LEFT)
    _rtk.Button(_rec_lrhdr, text="🗑", font=("Consolas",8), bg="#0a0508", fg=_DIM2,
                relief="flat", bd=0, cursor="hand2",
                command=lambda: (rec_raw_txt.config(state="normal"),
                                 rec_raw_txt.delete("1.0",_rtk.END),
                                 rec_raw_txt.config(state="disabled"))
                ).pack(side=_rtk.RIGHT)
    _rec_lr_sc = _rtk.Scrollbar(_rec_lp_right, orient="vertical", bg=_BRD2,
                                  troughcolor="#050508", relief="flat", bd=0, width=6)
    rec_raw_txt = _rtk.Text(_rec_lp_right, bg="#050508", fg="#7fbf7f",
                             font=("Consolas",8), yscrollcommand=_rec_lr_sc.set,
                             relief="flat", bd=0, padx=10, pady=6, wrap="none",
                             state="disabled")
    _rec_lr_sc.config(command=rec_raw_txt.yview)
    _rec_lr_sc.pack(side=_rtk.RIGHT, fill=_rtk.Y)
    rec_raw_txt.pack(fill=_rtk.BOTH, expand=True)

    def _rec_oplog(msg, tag="DIM"):
        try:
            ts = _rt.strftime("%H:%M:%S")
            rec_log_txt.config(state="normal")
            rec_log_txt.insert(_rtk.END, f"[{ts}] {msg}\n", tag)
            rec_log_txt.see(_rtk.END)
            rec_log_txt.config(state="disabled")
            _rec_record_activity(msg)
        except Exception: pass

        try:
            import datetime as _dtrec_op
            _rec_ops_dir = _ros.path.join(
                _ros.path.dirname(_tcwd[0]), "v0rtex_utils", "debug_log", "recovery_ops")
            _ros.makedirs(_rec_ops_dir, exist_ok=True)
            _session_f = _ros.path.join(
                _rec_ops_dir,
                f"recovery_{_dtrec_op.datetime.now().strftime('%Y%m%d_%H%M%S')[:15]}.log")
            with open(_session_f, "a", encoding="utf-8", errors="replace") as _ropf:
                _ropf.write(f"[{_dtrec_op.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] {msg}\n")
        except Exception:
            pass

    def _rec_rawlog(header, stdout_str, stderr_str=""):
        try:
            ts = _rt.strftime("%H:%M:%S")
            rec_raw_txt.config(state="normal")
            rec_raw_txt.insert(_rtk.END, f"\n[{ts}] ❯ {header}\n", "CMD")
            for _rl in (stdout_str or "").strip().splitlines():
                rec_raw_txt.insert(_rtk.END, _rl + "\n")
            if (stderr_str or "").strip():
                rec_raw_txt.insert(_rtk.END, "--- stderr ---\n", "ERR")
                for _rl in stderr_str.strip().splitlines():
                    rec_raw_txt.insert(_rtk.END, _rl + "\n", "ERR")
            rec_raw_txt.see(_rtk.END)
            rec_raw_txt.config(state="disabled")
        except Exception: pass


    def _make_mirrored_log(orig_fn, tag_prefix=""):
        """Wrap a tab-local log function to also write to rec_oplog."""
        def _mirrored(msg, tag="DIM"):
            orig_fn(msg, tag)
            try: _rec_oplog(f"{tag_prefix}{msg}", tag)
            except Exception: pass
        return _mirrored


    _rec_log_mirror_pending = []


    _term_split = _rtk.Frame(t_term, bg=_BG); _term_split.pack(fill=_rtk.BOTH, expand=True)
    _term_left  = _rtk.Frame(_term_split, bg=_BG); _term_left.pack(side=_rtk.LEFT, fill=_rtk.BOTH, expand=True)
    _rtk.Frame(_term_split, bg=_BRD2, width=1).pack(side=_rtk.LEFT, fill=_rtk.Y)
    _term_right = _rtk.Frame(_term_split, bg=_PNL, width=180); _term_right.pack(side=_rtk.LEFT, fill=_rtk.Y)
    _term_right.pack_propagate(False)

    _lf, term_txt = _make_log(_term_left)
    _lf.pack(fill=_rtk.BOTH, expand=True)


    _rtk.Frame(_term_left, bg=_BRD, height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
    inp_row = _rtk.Frame(_term_left, bg=_PNL2, pady=5, padx=6)
    inp_row.pack(fill=_rtk.X, side=_rtk.BOTTOM)

    _tcwd = [None]
    try: _tcwd[0] = BASE_DIR
    except: _tcwd[0] = _ros.path.dirname(_ros.path.abspath(__file__))

    _prompt_lbl = _rtk.Label(inp_row,
        text=f"root@recovery:{_tcwd[0][:28]}$ ",
        font=("Consolas",9,"bold"), bg=_PNL2, fg=_GRN2)
    _prompt_lbl.pack(side=_rtk.LEFT)

    _cmd_var = _rtk.StringVar()
    _cmd_entry = _rtk.Entry(inp_row, textvariable=_cmd_var, font=("Consolas",10),
                            bg="#0d0d22", fg=_TXT, insertbackground=_GRN2,
                            relief="flat", bd=0, highlightthickness=1,
                            highlightcolor=_ACCENT, highlightbackground=_BRD2)
    _cmd_entry.pack(side=_rtk.LEFT, fill=_rtk.X, expand=True, padx=4)
    _cmd_entry.focus_set()

    _thist = []; _thpos = [0]

    def _term_write(msg, tag="DIM"):
        try:
            term_txt.config(state="normal")
            term_txt.insert(_rtk.END, msg, tag)
            term_txt.see(_rtk.END)
            term_txt.config(state="disabled")
        except Exception: pass

    def _run_cmd(event=None):
        raw = _cmd_var.get().strip()
        if not raw: return
        _thist.append(raw); _thpos[0] = len(_thist); _cmd_var.set("")
        _term_write(f"root@recovery:{_tcwd[0]}$ ", "PROMPT")
        _term_write(f"{raw}\n", "INFO")
        parts = raw.split()
        if parts[0] == "cd":
            try:
                tgt = parts[1] if len(parts) > 1 else (_tcwd[0] or ".")
                tgt = tgt if _ros.path.isabs(tgt) else _ros.path.join(_tcwd[0], tgt)
                if tgt == "..": tgt = _ros.path.dirname(_tcwd[0])
                if _ros.path.isdir(tgt):
                    _tcwd[0] = _ros.path.normpath(tgt)
                    _prompt_lbl.config(text=f"root@recovery:{_tcwd[0][:28]}$ ")
                    _term_write(f"  → {_tcwd[0]}\n", "OK")
                else:
                    _term_write(f"  cd: no such dir: {tgt}\n", "ERR")
            except Exception as _cde:
                _term_write(f"  cd error: {_cde}\n", "ERR")
            return
        if parts[0] in ("clear","cls"):
            try: term_txt.config(state="normal"); term_txt.delete("1.0",_rtk.END); term_txt.config(state="disabled")
            except Exception: pass
            return
        import threading as _tth
        def _exec():
            try:
                r = _rsp.run(raw, shell=True, cwd=_tcwd[0], capture_output=True, text=True, timeout=30, creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                if r.stdout:
                    try: rr.after(0, lambda t=r.stdout: _term_write(t, "DIM"))
                    except Exception: pass
                if r.stderr:
                    try: rr.after(0, lambda t=r.stderr: _term_write(t, "ERR"))
                    except Exception: pass
                if r.returncode != 0:
                    try: rr.after(0, lambda c=r.returncode: _term_write(f"  [exit {c}]\n","WARN"))
                    except Exception: pass
            except _rsp.TimeoutExpired:
                try: rr.after(0, lambda: _term_write("  [timeout 30s]\n","ERR"))
                except Exception: pass
            except Exception as e:
                try: rr.after(0, lambda t=str(e): _term_write(f"  [error] {t}\n","ERR"))
                except Exception: pass
        _tth.Thread(target=_exec, daemon=True).start()

    def _hist_up(e):
        if _thist and _thpos[0] > 0:
            _thpos[0] -= 1; _cmd_var.set(_thist[_thpos[0]])
    def _hist_dn(e):
        if _thpos[0] < len(_thist)-1:
            _thpos[0] += 1; _cmd_var.set(_thist[_thpos[0]])
        else:
            _thpos[0] = len(_thist); _cmd_var.set("")

    _cmd_entry.bind("<Return>", _run_cmd)
