    def _kill_lockfiles():
        try:
            import glob as _gl; bd = _tcwd[0]; removed = 0
            for f in _gl.glob(_ros.path.join(bd,"*.lock")) + _gl.glob(_ros.path.join(bd,"*.tmp")):
                try: _ros.remove(f); removed += 1
                except: pass
            _replog(f">_ Removed {removed} lock/tmp file(s).", "OK" if removed else "DIM")
        except Exception as e: _replog(f">_ Error: {e}", "ERR")

    def _repair_install_packages():
        """Install/repair all Python dependencies with full fallback chain."""
        import threading as _ith, subprocess as _isp

        req = None
        for _rname in ("requirements.txt", "requirments.txt"):
            _rp = _ros.path.join(_tcwd[0], _rname)
            if _ros.path.exists(_rp):
                req = _rp
                break

        if req is None:
            req = _ros.path.join(_tcwd[0], "requirements.txt")
            try:
                _pkgs_fallback = (
                    "requests>=2.31.0\npefile>=2023.2.7\nmatplotlib>=3.7.0\n"
                    "tkinterdnd2>=0.3.0\npsutil>=5.9.0\nfpdf2>=2.7.0\n"
                    "watchdog>=3.0.0\npystray>=0.19.0\nPillow>=10.0.0\n"
                    "cryptography>=41.0.0\nreportlab>=4.0.0\n"
                )
                with open(req, "w", encoding="utf-8") as _rf:
                    _rf.write(_pkgs_fallback)
                _replog(">_ requirements.txt recreated from built-in list.", "WARN")
            except Exception as _re:
                _replog(f">_ Cannot create requirements.txt: {_re}", "ERR")
                return

        _TH = ["--trusted-host", "pypi.org",
               "--trusted-host", "files.pythonhosted.org",
               "--trusted-host", "pypi.python.org"]

        def _rlog(msg, tag="DIM"):
            try: rr.after(0, lambda m=msg, t=tag: _replog(m, t))
            except Exception: pass

        def _pip_one(pkg):
            pname = pkg.split(">=")[0].split("==")[0].split("[")[0].strip()
            for cmd, lbl in [
                ([_rsys.executable, "-m", "pip", "install", pkg,
                  "--prefer-binary", "--no-cache-dir", "-q"] + _TH, "binary"),
                ([_rsys.executable, "-m", "pip", "install", pkg,
                  "--user", "--prefer-binary", "--no-cache-dir", "-q"] + _TH, "--user"),
                ([_rsys.executable, "-m", "pip", "install", pkg,
                  "--no-cache-dir", "-q"] + _TH, "plain"),
            ]:
                try:
                    r = _isp.run(cmd, capture_output=True, text=True, timeout=180)
                    if r.returncode == 0:
                        _rlog(f"  ✓ {pname}  [{lbl}]", "OK")
                        return True
                except Exception:
                    pass
            _rlog(f"  ✗ {pname} — all strategies failed", "ERR")
            return False

        def _bootstrap_pip_if_needed():
            """
            Ensure pip is available. Returns True if pip is usable after this call.
            Tries: ensurepip → ensurepip subprocess → get-pip.py download.
            """
            ck = _isp.run([_rsys.executable, "-m", "pip", "--version"],
                          capture_output=True, text=True)
            if ck.returncode == 0 and "No module named pip" not in (ck.stderr + ck.stdout):
                return True

            _rlog("  ~ pip not found — bootstrapping…", "WARN")

            try:
                import ensurepip as _ep2; _ep2.bootstrap(upgrade=True)
                if _isp.run([_rsys.executable, "-m", "pip", "--version"],
                            capture_output=True, text=True).returncode == 0:
                    _rlog("  ✓ pip bootstrapped (ensurepip)", "OK"); return True
            except Exception as _epe2:
                _rlog(f"  ~ ensurepip: {_epe2}", "DIM")

            _isp.run([_rsys.executable, "-m", "ensurepip", "--upgrade"],
                     capture_output=True, text=True)
            if _isp.run([_rsys.executable, "-m", "pip", "--version"],
                        capture_output=True, text=True).returncode == 0:
                _rlog("  ✓ pip bootstrapped (ensurepip subprocess)", "OK"); return True

            import tempfile as _tmp2, os as _tos2
            _gp = _tos2.path.join(_tmp2.gettempdir(), "get-pip.py")
            for _url in ["https://bootstrap.pypa.io/get-pip.py",
                         "https://bootstrap.pypa.io/pip/get-pip.py"]:
                try:
                    import urllib.request as _ur2
                    _ur2.urlretrieve(_url, _gp)
                    if _tos2.path.getsize(_gp) > 1000:
                        _isp.run([_rsys.executable, _gp, "--quiet"] + _TH,
                                 capture_output=True, text=True)
                        if _isp.run([_rsys.executable, "-m", "pip", "--version"],
                                    capture_output=True, text=True).returncode == 0:
                            _rlog("  ✓ pip installed via get-pip.py", "OK"); return True
                        break
                except Exception:
                    pass

            _rlog("  ✗ pip bootstrap failed — cannot install packages.", "ERR")
            return False

        def _w():
            try: rr.after(0, _rec_anim_start)
            except Exception: pass
            _rlog("", "DIM")
            _rlog("╔─ INSTALL / REPAIR PACKAGES ╗", "PROMPT")
            _rlog(f"  using: {req}", "DIM")
            _rlog(f"  python: {_rsys.executable}", "DIM")

            if not _bootstrap_pip_if_needed():
                _rlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
                return

            _rlog("  → Phase 1: bulk install…", "INFO")
            try:
                bulk = _isp.run(
                    [_rsys.executable, "-m", "pip", "install", "-r", req,
                     "--prefer-binary", "--no-cache-dir", "-q",
                     "--progress-bar", "off"] + _TH,
                    capture_output=True, text=True, timeout=300)
                for line in (bulk.stdout + bulk.stderr).splitlines():
                    line = line.strip()
                    if not line: continue
                    if "Successfully installed" in line: _rlog(f"  ✓ {line}", "OK")
                    elif "already satisfied" in line:
                        pkg = line.split(":")[1].strip().split()[0] if ":" in line else ""
                        _rlog(f"  · {pkg} already ok", "DIM")
                    elif "error" in line.lower(): _rlog(f"  ✗ {line}", "ERR")
                    elif line.startswith("Collecting"): _rlog(f"  ↓ {line}", "INFO")
            except Exception as _be:
                bulk = type("R", (), {"returncode": 1})()
                _rlog(f"  ✗ bulk error: {_be}", "ERR")

            if bulk.returncode == 0:
                _rlog("  ✓ All packages installed.", "OK")
                _sts("packages ok"); _rlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT"); return

            _rlog("  → Phase 2: per-package fallback…", "WARN")
            try:
                with open(req, encoding="utf-8", errors="replace") as _rf:
                    pkgs = [l.strip() for l in _rf if l.strip() and not l.strip().startswith("#")]
            except Exception as _re2:
                _rlog(f"  ✗ Cannot read requirements: {_re2}", "ERR")
                pkgs = []

            _failed      = []
            _need_cmp    = []
            _compile_sigs = (
                "error: command", "cl.exe", "gcc", "failed building",
                "build failed", "cannot find compiler", "distutils",
                "microsoft visual c++", "error: microsoft",
            )

            for pkg in pkgs:
                pname = pkg.split(">=")[0].split("==")[0].strip()
                if _pip_one(pkg):
                    continue
                try:
                    _pe = _isp.run(
                        [_rsys.executable, "-m", "pip", "install", pkg,
                         "--no-cache-dir", "-q"] + _TH,
                        capture_output=True, text=True, timeout=60)
                    if any(s in (_pe.stdout + _pe.stderr).lower() for s in _compile_sigs):
                        _need_cmp.append(pkg)
                    else:
                        _failed.append(pname)
                except Exception:
                    _failed.append(pname)

            if _need_cmp:
                import shutil as _rsh2
                _rlog(f"  ~ {len(_need_cmp)} package(s) need a C compiler — checking for VS Build Tools…", "WARN")
                _bt_ok2 = False

                                                              
                if _rsh2.which("cl") or _rsh2.which("gcc") or _rsh2.which("clang"):
                    _rlog("  ✓ C compiler already on PATH — skipping Build Tools install", "OK")
                    _bt_ok2 = True

                                                                                
                if not _bt_ok2:
                    import os as _ros_vsw
                    _vsw2_paths = [
                        _ros_vsw.path.join(_ros_vsw.environ.get("ProgramFiles(x86)", ""),
                                           "Microsoft Visual Studio", "Installer", "vswhere.exe"),
                        _ros_vsw.path.join(_ros_vsw.environ.get("ProgramFiles", ""),
                                           "Microsoft Visual Studio", "Installer", "vswhere.exe"),
                    ]
                    for _vsw2 in _vsw2_paths:
                        if _ros_vsw.path.isfile(_vsw2):
                            try:
                                import subprocess as _sp_vsw
                                _vsw2_out = _sp_vsw.check_output(
                                    [_vsw2, "-products", "*",
                                     "-requires", "Microsoft.VisualStudio.Component.VC.Tools.x86.x64",
                                     "-property", "installationPath"],
                                    stderr=_sp_vsw.DEVNULL, timeout=10
                                ).decode(errors="replace").strip()
                                if _vsw2_out:
                                    _rlog("  ✓ VS Build Tools already installed (vswhere) — skipping", "OK")
                                    _bt_ok2 = True
                                    break
                            except Exception:
                                pass

                                             
                if not _bt_ok2:
                    try:
                        import winreg as _wreg2
                        _reg_checks2 = [
                            (r"SOFTWARE\Microsoft\VisualStudio\Setup\BuildTools",         None),
                            (r"SOFTWARE\WOW6432Node\Microsoft\VisualStudio\Setup\BuildTools", None),
                            (r"SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall",
                             "Microsoft Visual Studio Build Tools 2022"),
                            (r"SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall",
                             "Microsoft Visual Studio Build Tools 2022"),
                        ]
                        for _rk2, _match2 in _reg_checks2:
                            try:
                                with _wreg2.OpenKey(_wreg2.HKEY_LOCAL_MACHINE, _rk2) as _k2:
                                    if _match2 is None:
                                        _rlog("  ✓ VS Build Tools already installed (registry) — skipping", "OK")
                                        _bt_ok2 = True
                                        break
                                    _idx2 = 0
                                    while True:
                                        try:
                                            _sub2 = _wreg2.EnumKey(_k2, _idx2)
                                            if _match2.lower() in _sub2.lower():
                                                _rlog("  ✓ VS Build Tools already installed (registry) — skipping", "OK")
                                                _bt_ok2 = True
                                                break
                                            _idx2 += 1
                                        except OSError:
                                            break
                                if _bt_ok2:
                                    break
                            except FileNotFoundError:
                                pass
                    except ImportError:
                        pass

                if not _bt_ok2 and _rsh2.which("winget") and _rsys.platform == "win32":
                    _rlog("  → winget: Microsoft.VisualStudio.2022.BuildTools…", "INFO")
                    _wg2 = _isp.run([
                        "winget", "install", "--id",
                        "Microsoft.VisualStudio.2022.BuildTools",
                        "--silent", "--accept-package-agreements",
                        "--accept-source-agreements",
                        "--override",
                        "--quiet --add Microsoft.VisualStudio.Workload.VCTools"
                        " --includeRecommended --wait",
                    ], capture_output=True, text=True, timeout=600)
                    if _wg2.returncode in (0, -1978335189):
                        _rlog("  ✓ VS Build Tools installed via winget", "OK")
                        _bt_ok2 = True

                if not _bt_ok2 and _rsys.platform == "win32":
                    _rlog("  → Downloading vs_BuildTools bootstrapper (5-15 min)…", "INFO")
                    import os as _ros3
                    _bt_path2 = _ros3.path.join(
                        _ros3.environ.get("TEMP", _ros3.path.expanduser("~")),
                        "vs_buildtools_setup.exe")
                    try:
                        import urllib.request as _urr2
                        _urr2.urlretrieve(
                            "https://aka.ms/vs/17/release/vs_buildtools.exe", _bt_path2)
                        _bi2 = _isp.run([
                            _bt_path2, "--quiet", "--wait", "--norestart",
                            "--add", "Microsoft.VisualStudio.Workload.VCTools",
                            "--includeRecommended",
                        ], capture_output=True, text=True, timeout=900)
                        if _bi2.returncode in (0, 3010):
                            _rlog(f"  ✓ VS Build Tools installed"
                                  f"{' (reboot recommended)' if _bi2.returncode == 3010 else ''}",
                                  "OK")
                            _bt_ok2 = True
                    except Exception as _bte3:
                        _rlog(f"  ✗ Build tools download failed: {_bte3}", "ERR")

                for pkg in _need_cmp:
                    pname = pkg.split(">=")[0].split("==")[0].strip()
                    if _pip_one(pkg):
                        pass
                    else:
                        reason = ("build tools installed but compile still failed"
                                  if _bt_ok2 else "build tools unavailable")
                        _rlog(f"  ✗ {pname} — {reason}", "ERR")
                        _failed.append(pname)

            if _failed:
                _rlog(f"  ⚠ Still missing: {', '.join(_failed)}", "WARN")
                _rlog("  → Run as Administrator or check internet connection.", "DIM")
                _sts(f"{len(_failed)} pkg(s) failed", ok=False)
            else:
                _rlog("  ✓ All packages installed via fallback.", "OK")
                _sts("packages ok")
            _rlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
            try: rr.after(0, _rec_anim_stop)
            except Exception: pass

        _ith.Thread(target=_w, daemon=True).start()

    def _recreate_system_files():
        import json as _rjson
        bd = _tcwd[0]
        created = []; skipped = []; errors = []
        try: rr.after(0, _rec_anim_start)
        except Exception: pass


        cfg_path = _ros.path.join(bd, "config.json")
        if _ros.path.exists(cfg_path):
            skipped.append("config.json")
        else:
            try:
                default_cfg = {
                    "api_keys": [], "proxy": "", "proxy_user": "", "proxy_pass": "",
                    "theme": "default", "auto_scan": False, "max_file_size_mb": 50
                }
                with open(cfg_path, "w", encoding="utf-8") as _f:
                    _rjson.dump(default_cfg, _f, indent=2)
                created.append("config.json")
            except Exception as _e:
                errors.append(f"config.json: {_e}")


        rules_dir = _ros.path.join(bd, "rules")
        try: _ros.makedirs(rules_dir, exist_ok=True)
        except Exception: pass
        rs_path = _ros.path.join(rules_dir, "rules_state.json")
        if _ros.path.exists(rs_path):
            skipped.append("rules/rules_state.json")
        else:
            try:
                with open(rs_path, "w", encoding="utf-8") as _f:
                    _rjson.dump({}, _f, indent=2)
                created.append("rules/rules_state.json")
            except Exception as _e:
                errors.append(f"rules/rules_state.json: {_e}")


        wl_path = _ros.path.join(bd, "whitelist.txt")
        if _ros.path.exists(wl_path):
            skipped.append("whitelist.txt")
        else:
            try:
                with open(wl_path, "w", encoding="utf-8") as _f:
                    _f.write("")
                created.append("whitelist.txt")
            except Exception as _e:
                errors.append(f"whitelist.txt: {_e}")

        nt_path = _ros.path.join(bd, "notes.txt")
        if _ros.path.exists(nt_path):
            skipped.append("notes.txt")
        else:
            try:
                with open(nt_path, "w", encoding="utf-8") as _f:
                    _f.write("")
                created.append("notes.txt")
            except Exception as _e:
                errors.append(f"notes.txt: {_e}")

        for _dname in ["_recovery", "backups", "debug_log", "quarantine", "reports", "rules"]:
            dp = _ros.path.join(bd, _dname)
            if _ros.path.isdir(dp):
                skipped.append(f"{_dname}/")
            else:
                try:
                    _ros.makedirs(dp, exist_ok=True)
                    created.append(f"{_dname}/")
                except Exception as _de:
                    errors.append(f"{_dname}/: {_de}")


        _replog("", "DIM")
        _replog("╔─ RECREATE CRITICAL FILES ──────────────────────────────────╗", "PROMPT")
        if created:
            _replog(f"  ✓  Created:", "OK")
            for _c in created:
                _replog(f"       {_c}", "GRN")
        if skipped:
            _replog(f"  ·  Already present: {', '.join(skipped)}", "DIM")
        if errors:
            _replog(f"  ✗  Errors:", "ERR")
            for _e in errors:
                _replog(f"       {_e}", "ERR")
        if not errors:
            _replog("  ✓  Critical files OK — restart the app to continue.", "OK")
            _sts("files recreated")
        else:
            _replog("  ⚠  Some files could not be created. Check errors above.", "WARN")
            _sts("recreate partial", ok=False)
        _replog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        try: rr.after(0, _rec_anim_stop)
        except Exception: pass


