    def _clear_reports():
        try:
            import glob as _gl, shutil as _shu; bd = _tcwd[0]
            rep = _ros.path.join(bd, "reports")
            if not _ros.path.isdir(rep):
                _replog(">_ reports/ not found.", "WARN"); return
            removed = 0
            for item in _ros.listdir(rep):
                fp = _ros.path.join(rep, item)
                try:
                    if _ros.path.isfile(fp): _ros.remove(fp)
                    elif _ros.path.isdir(fp): _shu.rmtree(fp)
                    removed += 1
                except Exception: pass
            _replog(f">_ Cleared {removed} item(s) from reports/.", "OK")
            _sts("reports cleared")
        except Exception as e: _replog(f">_ Error: {e}", "ERR")

