    def _integrity_check():
        import json as _rj
        bd = _tcwd[0]; ok_c = 0; err_c = 0
        try: rr.after(0, _rec_anim_start)
        except Exception: pass
        _replog("", "DIM")
        _replog("╔─ INTEGRITY CHECK ──────────────────────────────────────────╗", "PROMPT")


        for fn in ["config.json", "rules/rules_state.json"]:
            fp = _ros.path.join(bd, fn.replace("/", _ros.sep))
            if _ros.path.exists(fp):
                sz = _ros.path.getsize(fp)

                try:
                    with open(fp, encoding="utf-8") as _f: _rj.load(_f)
                    _replog(f"  ✓  {fn}  ({sz} B)  [valid JSON]", "OK"); ok_c += 1
                except Exception:
                    _replog(f"  ⚠  {fn}  ({sz} B)  [INVALID JSON — reset recommended]", "WARN"); err_c += 1
            else:
                _replog(f"  ✗  {fn}  MISSING", "ERR"); err_c += 1


        for dn in ["_recovery","backups","debug_log","quarantine","reports","rules"]:
            dp = _ros.path.join(bd, dn)
            if _ros.path.isdir(dp):
                _replog(f"  ✓  {dn}/", "OK"); ok_c += 1
            else:
                _replog(f"  ✗  {dn}/  MISSING", "ERR"); err_c += 1


        db = _ros.path.join(bd, "scan_history.db")
        if _ros.path.exists(db):
            try:
                import sqlite3 as _rsq2
                c = _rsq2.connect(db, timeout=3)
                r = c.execute("PRAGMA integrity_check").fetchone()
                c.close()
                if r and r[0] == "ok":
                    _replog(f"  ✓  scan_history.db  [integrity OK]", "OK"); ok_c += 1
                else:
                    _replog(f"  ⚠  scan_history.db  [integrity FAILED: {r}]", "WARN"); err_c += 1
            except Exception as _dbe:
                _replog(f"  ✗  scan_history.db  [error: {_dbe}]", "ERR"); err_c += 1
        else:
            _replog(f"  ·  scan_history.db  not present (will be created on first scan)", "DIM")

        _replog("╠─────────────────────────────────────────────────────────────╣", "PROMPT")
        _replog(f"  {ok_c} OK  ·  {err_c} issues", "OK" if err_c==0 else "WARN")
        _replog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts("integrity check done", err_c == 0)
        try: rr.after(0, _rec_anim_stop)
        except Exception: pass



