    def _regen_selected():
        import json as _rjsel, sqlite3 as _rsqsel
        bd = _tcwd[0]; done = []; skipped = []; errors = []
        for _sname, _v in _sel_vars.items():
            if not _v.get(): continue
            fp = _ros.path.join(bd, _sname.replace("/", _ros.sep))
            try:
                if _sname.endswith("/"):
                    if _ros.path.isdir(fp):
                        skipped.append(_sname)
                    else:
                        _ros.makedirs(fp, exist_ok=True)
                        done.append(_sname)
                elif _sname == "scan_history.db":
                    if _ros.path.isfile(fp): _ros.remove(fp)
                    c = _rsqsel.connect(fp)
                    c.execute("""CREATE TABLE IF NOT EXISTS scans (
                        file TEXT, md5 TEXT, sha1 TEXT, sha256 TEXT,
                        malicious INTEGER DEFAULT 0, suspicious INTEGER DEFAULT 0,
                        undetected INTEGER DEFAULT 0, yara_hits TEXT DEFAULT '[]',
                        pe_info TEXT DEFAULT '{}', iocs TEXT DEFAULT '{}',
                        entropy REAL DEFAULT 0.0, filetype TEXT DEFAULT 'Unknown',
                        timestamp TEXT DEFAULT '')""")
                    c.commit(); c.close()
                    done.append(_sname)
                elif _sname == "config.json":
                    if _ros.path.isfile(fp):
                        skipped.append(_sname + " (exists)")
                    else:
                        with open(fp, "w", encoding="utf-8") as _f:
                            _rjsel.dump({"api_keys":[], "proxy":"", "auto_scan": False,
                                         "max_file_size_mb": 50, "request_delay": 15}, _f, indent=2)
                        done.append(_sname)
                elif _sname in ("whitelist.txt", "notes.txt"):
                    if _ros.path.isfile(fp):
                        skipped.append(_sname + " (exists)")
                    else:
                        with open(fp, "w", encoding="utf-8") as _f: _f.write("")
                        done.append(_sname)
                elif _sname == "rules/rules_state.json":
                    rdir = _ros.path.join(bd, "rules")
                    _ros.makedirs(rdir, exist_ok=True)
                    with open(fp, "w", encoding="utf-8") as _f:
                        _rjsel.dump({}, _f, indent=2)
                    done.append(_sname)
            except Exception as _se:
                errors.append(f"{_sname}: {_se}")
        _replog("", "DIM")
        _replog("╔─ SELECTIVE REGENERATION ───────────────────────────────────╗", "PROMPT")
        if done:
            for _d in done: _replog(f"  ✓  {_d}", "OK")
        if skipped:
            for _s in skipped: _replog(f"  ·  {_s}", "DIM")
        if errors:
            for _e in errors: _replog(f"  ✗  {_e}", "ERR")
        if not done and not errors:
            _replog("  Nothing selected.", "DIM")
        _replog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts("selective regen done", not errors)


