        _rec_log_admin(f"TEST_APPLICATION launched — entry={entry} — log={log_path}")
        _replog(f">_ TEST_APPLICATION: entry={entry}", "INFO")
        _replog(f">_ Logging to: {log_path}", "DIM")

        _tw = _rtk.Toplevel(rr)
