    def _do_backup():
        import threading as _tthr
        def _w():
            try:
                ok, res = _create_full_backup(lambda m, t="DIM":
                    rr.after(0, lambda mm=m, tt=t: _bklog(mm, "OK" if "OK" in str(tt) else tt)))
                rr.after(0, lambda: _bklog(f">_ Backup {'OK' if ok else 'FAILED'}: {res}",
                                           "OK" if ok else "ERR"))
                rr.after(0, lambda: _sts("backup " + ("ok" if ok else "failed"), ok))
            except Exception as e:
                rr.after(0, lambda: _bklog(f">_ Error: {e}", "ERR"))
        _tthr.Thread(target=_w, daemon=True).start()

