    def _cln_dir(dirname, label, exts=None, confirm=True):
        from tkinter import messagebox as _mb
        if confirm:
            ok = _mb.askyesno("Confirm", f"Delete ALL files in {dirname}/?", parent=rr)
            if not ok: return
        bd = _tcwd[0]; removed = 0; freed = 0
        import glob as _gl4
        dp = _ros.path.join(bd, dirname)
        if not _ros.path.isdir(dp):
            _clnlog(f">_ {dirname}/ not found.", "WARN"); return
        patterns = [_ros.path.join(dp, f"*{e}") for e in (exts or [""])]
        files = []
        for pat in patterns:
            files += (_gl4.glob(pat) if exts else
                      [_ros.path.join(dp, f) for f in _ros.listdir(dp)
                       if _ros.path.isfile(_ros.path.join(dp, f))])
        files = list(set(files))
        for fp in files:
            try:
                freed += _ros.path.getsize(fp)
                _ros.remove(fp); removed += 1
            except Exception: pass
        _clnlog(f">_ {label}: removed {removed} file(s), freed {freed//1024} KB.",
                "OK" if removed else "DIM")
        _sts(f"cleaned {dirname}")

    def _cln_debug_logs():
        from tkinter import messagebox as _mb2
        ok = _mb2.askyesno("Confirm", "Delete all debug log files?\n(crash logs will also be removed)", parent=rr)
        if not ok: return
        import glob as _gl5
        bd = _tcwd[0]; removed = 0; freed = 0
        for pat in ["debug_log/*.txt", "debug_log/*.log", "crash_log.txt"]:
            for fp in _gl5.glob(_ros.path.join(bd, pat.replace("/", _ros.sep))):
                try:
                    freed += _ros.path.getsize(fp)
                    _ros.remove(fp); removed += 1
                except Exception: pass
        _clnlog(f">_ Debug logs: removed {removed} file(s), freed {freed//1024} KB.", "OK" if removed else "DIM")

    def _cln_pycache():
        import glob as _gl6, shutil as _sh2
        bd = _tcwd[0]; removed = 0
        for d in _gl6.glob(_ros.path.join(bd, "**", "__pycache__"), recursive=True):
            try: _sh2.rmtree(d); removed += 1
            except Exception: pass
        for f in _gl6.glob(_ros.path.join(bd, "**", "*.pyc"), recursive=True):
            try: _ros.remove(f); removed += 1
            except Exception: pass
        _clnlog(f">_ __pycache__ / .pyc: removed {removed} item(s).", "OK" if removed else "DIM")
        _sts("pycache cleared")

    def _cln_old_backups():
        from tkinter import messagebox as _mb3
        import glob as _gl7
        bd = _tcwd[0]
        try: bk_dir = BACKUPS_DIR
        except: bk_dir = _ros.path.join(bd, "backups")
        zips = sorted(_gl7.glob(_ros.path.join(bk_dir, "*.zip")),
                      key=_ros.path.getmtime, reverse=True)
