    def _cln_rebuild_db():
        from tkinter import messagebox as _mb8
        ok = _mb8.askyesno("Confirm",
            "Rebuild scan_history.db from scratch?\n"
            "ALL scan records will be permanently deleted.", parent=rr)
        if not ok: return
        try:
            import sqlite3 as _sq3
            db = _ros.path.join(_tcwd[0], "scan_history.db")
            if _ros.path.exists(db): _ros.remove(db)
            conn = _sq3.connect(db, timeout=10)
            conn.execute("PRAGMA journal_mode=WAL")
            conn.executescript("""
                CREATE TABLE scan_history (
                    id          INTEGER PRIMARY KEY AUTOINCREMENT,
                    filename    TEXT,
                    filepath    TEXT,
                    filehash    TEXT,
                    scan_date   TEXT,
                    vt_result   TEXT,
                    yara_result TEXT,
                    pe_result   TEXT,
                    notes       TEXT
                );
                CREATE TABLE whitelist (
                    id      INTEGER PRIMARY KEY AUTOINCREMENT,
                    hash    TEXT UNIQUE,
                    note    TEXT,
                    added   TEXT
                );
            """)
            conn.commit(); conn.close()
            _clnlog(">_ scan_history.db rebuilt with full schema.", "OK")
            _sts("db rebuilt")
        except Exception as _dbe2: _clnlog(f">_ Error: {_dbe2}", "ERR")

