    def _net_check_internet():
        import threading as _nth
        def _w():
            rr.after(0, lambda: _ntlog("", "DIM"))
            rr.after(0, lambda: _ntlog("╔─ INTERNET CONNECTIVITY ────────────────────────────────────╗", "PROMPT"))
            TARGETS = [
                ("8.8.8.8",              53,  "Google DNS"),
                ("1.1.1.1",              53,  "Cloudflare DNS"),
                ("www.virustotal.com",    443, "VirusTotal"),
                ("www.google.com",        80,  "Google HTTP"),
            ]
            import socket as _sk, time as _nt
            for host, port, label in TARGETS:
                t0 = _nt.time()
                try:
                    s = _sk.create_connection((host, port), timeout=4)
                    s.close()
                    ms = int((_nt.time() - t0) * 1000)
                    rr.after(0, lambda h=host, l=label, m=ms:
                        _ntlog(f"  ✓  {l:<25} {h}:{port if port!=443 else 'https'}  [{m}ms]", "OK"))
                except Exception as _ce:
                    rr.after(0, lambda h=host, l=label, e=str(_ce):
                        _ntlog(f"  ✗  {l:<25} {h}  — {e}", "ERR"))
            rr.after(0, lambda: _ntlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT"))
            rr.after(0, lambda: _sts("net check done"))
        _nth.Thread(target=_w, daemon=True).start()

    def _net_check_vt_api():
        import threading as _nth2
        def _w():
            rr.after(0, lambda: _ntlog("", "DIM"))
            rr.after(0, lambda: _ntlog("╔─ VIRUSTOTAL API CHECK ─────────────────────────────────────╗", "PROMPT"))
            try:
                import json as _nj
                cfg_p = _ros.path.join(_tcwd[0], "config.json")
                keys = []
                if _ros.path.exists(cfg_p):
                    cfg = _nj.loads(open(cfg_p, encoding="utf-8").read())
                    keys = cfg.get("api_keys", [])
                if not keys:
                    rr.after(0, lambda: _ntlog("  ✗  No API keys found in config.json", "ERR"))
                    rr.after(0, lambda: _ntlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT"))
                    return
                try:
                    import urllib.request as _ur
                    for i, key in enumerate(keys[:3]):
                        url = f"https://www.virustotal.com/api/v3/files/abc"
                        req = _ur.Request(url, headers={"x-apikey": key})
                        try:
                            _ur.urlopen(req, timeout=8)
                            rr.after(0, lambda k=i+1: _ntlog(f"  ✓  Key [{k}]: API reachable", "OK"))
                        except Exception as _ve:
                            code = getattr(getattr(_ve, 'code', None), '__str__', lambda: str(_ve))()
                            tag = "WARN" if "404" in str(code) or "401" in str(code) else "ERR"

                            status = ("reachable (hash not found = API alive)" if "404" in str(code)
                                      else ("invalid key (401)" if "401" in str(code)
                                      else f"error: {_ve}"))
                            rr.after(0, lambda k=i+1, s=status, t=tag:
                                _ntlog(f"  {'✓' if t=='WARN' else '✗'}  Key [{k}]: {s}", t))
                except ImportError:
                    rr.after(0, lambda: _ntlog("  ✗  urllib not available", "ERR"))
            except Exception as _ve2:
                rr.after(0, lambda e=str(_ve2): _ntlog(f"  ✗  Error: {e}", "ERR"))
            rr.after(0, lambda: _ntlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT"))
            rr.after(0, lambda: _sts("VT api check done"))
        _nth2.Thread(target=_w, daemon=True).start()

    def _net_proxy_info():
        _ntlog("", "DIM")
        _ntlog("╔─ PROXY CONFIG ─────────────────────────────────────────────╗", "PROMPT")
        try:
            import json as _nj2
            cfg_p = _ros.path.join(_tcwd[0], "config.json")
            if _ros.path.exists(cfg_p):
                cfg = _nj2.loads(open(cfg_p, encoding="utf-8").read())
                proxy = cfg.get("proxy", "")
                user  = cfg.get("proxy_user", "")
                _ntlog(f"  ·  Proxy URL  : {proxy if proxy else '(none)'}", "INFO" if proxy else "DIM")
                _ntlog(f"  ·  Proxy user : {user if user else '(none)'}", "DIM")
                _ntlog(f"  ·  Proxy pass : {'(set)' if cfg.get('proxy_pass') else '(not set)'}", "DIM")
            else:
                _ntlog("  ✗  config.json not found", "ERR")
        except Exception as _pe2: _ntlog(f"  ✗  {_pe2}", "ERR")

        for env_var in ["HTTP_PROXY","HTTPS_PROXY","http_proxy","https_proxy","NO_PROXY"]:
            val = _ros.environ.get(env_var)
            if val: _ntlog(f"  ·  {env_var:<14}: {val}", "DIM")
        _ntlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

    def _net_show_interfaces():
        import threading as _nth3
        def _w():
            rr.after(0, lambda: _ntlog("", "DIM"))
            rr.after(0, lambda: _ntlog("╔─ NETWORK INTERFACES ───────────────────────────────────────╗", "PROMPT"))
            try:
                import psutil as _nps
                for iface, addrs in _nps.net_if_addrs().items():
                    rr.after(0, lambda i=iface: _ntlog(f"  {i}", "INFO"))
                    for a in addrs:
                        rr.after(0, lambda a=a: _ntlog(
                            f"       {str(a.family).split('.')[-1]:<10} {a.address}", "DIM"))
            except ImportError:
                import socket as _sk2
                try:
                    hostname = _sk2.gethostname()
                    ip = _sk2.gethostbyname(hostname)
                    rr.after(0, lambda h=hostname, i=ip: _ntlog(f"  {h} → {i}", "INFO"))
                except Exception as _ie: rr.after(0, lambda e=str(_ie): _ntlog(f"  error: {e}", "ERR"))
            rr.after(0, lambda: _ntlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT"))
        _nth3.Thread(target=_w, daemon=True).start()

    def _net_dns_lookup():
        from tkinter import simpledialog as _sd
        host = _sd.askstring("DNS Lookup", "Hostname to resolve:", parent=rr)
        if not host: return
        import threading as _nth4
        def _w():
            import socket as _sk3, time as _nt2
            rr.after(0, lambda: _ntlog(f">_ Resolving: {host}", "PROMPT"))
            t0 = _nt2.time()
            try:
                results = _sk3.getaddrinfo(host, None)
                ms = int((_nt2.time() - t0) * 1000)
                seen = set()
                for r in results:
                    ip = r[4][0]
                    if ip not in seen:
                        seen.add(ip)
                        rr.after(0, lambda i=ip, m=ms: _ntlog(f"  ✓  {host} → {i}  [{m}ms]", "OK"))
            except Exception as _de2:
                rr.after(0, lambda e=str(_de2): _ntlog(f"  ✗  {host}: {e}", "ERR"))
        _nth4.Thread(target=_w, daemon=True).start()

