    def _build_defender_tab(frame):
        import subprocess as _rspdef, threading as _tdef
        _df, dlog = _make_log(frame)
        _df.pack(fill=_rtk.BOTH, expand=True)
        _dbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
        _dbf.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Frame(frame, bg="#ff3366", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Label(_dbf, text="  ⚠ " + _ADM_BADGE_S + " — changes affect Windows Defender system-wide",
                   font=("Consolas",8,"bold"), bg=_PNL2, fg="#ff3366").pack(anchor="w", pady=(0,4))

        def _dlog_w(msg, tag="DIM"):
            try:
                dlog.config(state="normal")
                dlog.insert(_rtk.END, msg+"\n", tag)
                dlog.see(_rtk.END)
                dlog.config(state="disabled")
            except Exception: pass

        def _ps_run(cmd):
            try:
                r = _rspdef.run(["power" + "shell","-NoProfile","-NonInteractive",
                                  "-WindowStyle","Hidden","-Command", cmd],
                                 capture_output=True, text=True, timeout=30)
                return r.stdout.strip(), r.stderr.strip(), r.returncode
            except Exception as e:
                return "", str(e), -1

        def _add_exclusion():
            from tkinter import filedialog as _fddef
            p = _fddef.askdirectory(title="Select folder to exclude from Defender", parent=rr)
            if not p: return
            def _w():
                _dlog_w(f">_ Adding Defender exclusion: {p}", "INFO")
                out, err, rc = _ps_run(f'Add-MpPreference -ExclusionPath "{p}"')
                if rc == 0:
                    _dlog_w(f"  ✓ Exclusion added: {p}", "OK")
                    _rec_log_admin(f"Defender exclusion added: {p}")
                else:
                    _dlog_w(f"  ✗ Failed (rc={rc}): {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _remove_exclusion():
            from tkinter import simpledialog as _sddef
            p = _sddef.askstring("Remove Exclusion", "Path to remove:", parent=rr)
            if not p: return
            def _w():
                out, err, rc = _ps_run(f'Remove-MpPreference -ExclusionPath "{p}"')
                if rc == 0:
                    _dlog_w(f"  ✓ Exclusion removed: {p}", "OK")
                    _rec_log_admin(f"Defender exclusion removed: {p}")
                else:
                    _dlog_w(f"  ✗ Failed: {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _list_exclusions():
            def _w():
                _dlog_w(">_ Listing Defender exclusions...", "INFO")
                out, err, rc = _ps_run("(Get-MpPreference).ExclusionPath")
                if rc == 0:
                    lines = [l for l in out.splitlines() if l.strip()]
                    _dlog_w(f"  Found {len(lines)} path exclusion(s):", "OK")
                    for l in lines: _dlog_w(f"    • {l}", "DIM")
                    _rec_log_admin(f"Defender exclusions listed: {len(lines)} found")
                else:
                    _dlog_w(f"  ✗ {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _disable_realtime():
            if not _rtk.messagebox.askyesno("Confirm", "Disable Defender Real-Time Protection?\n\nThis reduces system security.", parent=rr): return
            def _w():
                out, err, rc = _ps_run("Set-MpPreference -DisableRealtimeMonitoring $true")
                if rc == 0:
                    _dlog_w("  ✓ Real-time protection DISABLED", "WARN")
                    _rec_log_admin("Defender real-time protection disabled")
                else:
                    _dlog_w(f"  ✗ Failed: {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _enable_realtime():
            def _w():
                out, err, rc = _ps_run("Set-MpPreference -DisableRealtimeMonitoring $false")
                if rc == 0:
                    _dlog_w("  ✓ Real-time protection RE-ENABLED", "OK")
                    _rec_log_admin("Defender real-time protection re-enabled")
                else:
                    _dlog_w(f"  ✗ Failed: {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _scan_status():
            def _w():
                _dlog_w(">_ Defender status...", "INFO")
                out, err, rc = _ps_run(_PS_AV_STATUS2)
                if rc == 0:
                    for l in out.splitlines(): _dlog_w(f"  {l}", "DIM")
                else:
                    _dlog_w(f"  ✗ {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        _row_d = _rtk.Frame(_dbf, bg=_PNL2); _row_d.pack(fill=_rtk.X, pady=2)
        for _bt, _bc, _cmd in [
            ("📋  List Exclusions",       _BLU,  _list_exclusions),
            ("➕  Add Folder Exclusion",   _GRN2, _add_exclusion),
            ("➖  Remove Exclusion",       _YEL,  _remove_exclusion),
            ("📊  Defender Status",        _TEA,  _scan_status),
            ("⏸  Disable Real-Time",      _RED,  _disable_realtime),
            ("▶  Re-enable Real-Time",     _GRN2, _enable_realtime),
        ]:
            _rtk.Button(_row_d, text=_bt, command=_cmd, bg=_BRD2, fg=_bc,
                        font=("Consolas",9), relief="flat", padx=10, pady=5,
                        cursor="hand2", bd=0).pack(side=_rtk.LEFT, padx=3)
        _dlog_w("╔─ DEFENDER & EXCLUSIONS (ADMIN) ─────────────────────────────╗", "PROMPT")
        _dlog_w("║  Manage Windows Defender exclusions and real-time protection. ║", "DIM")
        _dlog_w("║  ⚠  " + _ADM_BADGE_S + " — all changes are live.  ║", "ERR")
        _dlog_w("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

    def _build_permissions_tab(frame):
        import subprocess as _rspperm, threading as _tperm
        _pf, plog = _make_log(frame)
        _pf.pack(fill=_rtk.BOTH, expand=True)
        _pbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
        _pbf.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Frame(frame, bg="#ff3366", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Label(_pbf, text="  ⚠ " + _ADM_BADGE_S + " — file permission changes are irreversible",
                   font=("Consolas",8,"bold"), bg=_PNL2, fg="#ff3366").pack(anchor="w", pady=(0,4))

        def _plog_w(msg, tag="DIM"):
            try:
                plog.config(state="normal")
                plog.insert(_rtk.END, msg+"\n", tag)
                plog.see(_rtk.END)
                plog.config(state="disabled")
            except Exception: pass

        def _take_ownership():
            from tkinter import filedialog as _fdperm
            p = _fdperm.askdirectory(title="Take ownership of folder", parent=rr)
            if not p: return
            def _w():
                _plog_w(f">_ Taking ownership of: {p}", "INFO")
                r = _rspperm.run(["takeown", "/F", p, "/R", "/D", "Y"],
                                  capture_output=True, text=True, timeout=120)
                for l in r.stdout.splitlines()[-10:]: _plog_w(f"  {l}", "DIM")
                r2 = _rspperm.run(["icacls", p, "/grant", f"{_ros.environ.get('USERNAME','Users')}:F",
                                    "/T", "/C", "/Q"],
                                   capture_output=True, text=True, timeout=120)
                if r2.returncode == 0:
                    _plog_w(f"  ✓ Full control granted on {p}", "OK")
                    _rec_log_admin(f"takeown + icacls on: {p}")
                else:
                    _plog_w(f"  ✗ icacls failed: {r2.stderr[:200]}", "ERR")
            _tperm.Thread(target=_w, daemon=True).start()

        def _fix_app_permissions():
            def _w():
                bd = _ros.path.dirname(_ros.path.abspath(_rsys.argv[0]))
                _plog_w(f">_ Fixing permissions on: {bd}", "INFO")
                r = _rspperm.run(["icacls", bd, "/grant",
                                   f"{_ros.environ.get('USERNAME','Users')}:(OI)(CI)F",
                                   "/T", "/C", "/Q"],
                                  capture_output=True, text=True, timeout=60)
                if r.returncode == 0:
                    _plog_w("  ✓ App folder permissions repaired.", "OK")
                    _rec_log_admin(f"App folder permissions repaired: {bd}")
                else:
                    _plog_w(f"  ✗ Failed: {r.stderr[:200]}", "ERR")
            _tperm.Thread(target=_w, daemon=True).start()

        def _reset_quarantine_perms():
            def _w():
                qp = _ros.path.join(_ros.path.dirname(_ros.path.abspath(_rsys.argv[0])), "quarantine")
                _ros.makedirs(qp, exist_ok=True)
                r = _rspperm.run(["icacls", qp, "/grant",
                                   f"{_ros.environ.get('USERNAME','Users')}:F",
                                   "/T", "/C", "/Q"],
                                  capture_output=True, text=True, timeout=30)
                if r.returncode == 0:
                    _plog_w("  ✓ Quarantine permissions reset.", "OK")
                    _rec_log_admin(f"Quarantine permissions reset: {qp}")
                else:
                    _plog_w(f"  ✗ Failed: {r.stderr[:100]}", "ERR")
            _tperm.Thread(target=_w, daemon=True).start()

        def _check_file_perms():
            from tkinter import filedialog as _fdperm2
            p = _fdperm2.askopenfilename(title="Check file permissions", parent=rr)
            if not p: return
            def _w():
                _plog_w(f">_ Checking: {p}", "INFO")
                r = _rspperm.run(["icacls", p], capture_output=True, text=True, timeout=15)
                for l in r.stdout.splitlines(): _plog_w(f"  {l}", "DIM")
            _tperm.Thread(target=_w, daemon=True).start()

        _row_p = _rtk.Frame(_pbf, bg=_PNL2); _row_p.pack(fill=_rtk.X, pady=2)
        for _bt, _bc, _cmd in [
            ("🔑  Take Ownership (folder)",   _YEL,  _take_ownership),
            ("🔧  Fix App Folder Perms",       _GRN2, _fix_app_permissions),
            ("🔒  Reset Quarantine Perms",     _BLU,  _reset_quarantine_perms),
            ("📋  Check File Permissions",     _TEA,  _check_file_perms),
        ]:
            _rtk.Button(_row_p, text=_bt, command=_cmd, bg=_BRD2, fg=_bc,
                        font=("Consolas",9), relief="flat", padx=10, pady=5,
                        cursor="hand2", bd=0).pack(side=_rtk.LEFT, padx=3)
        _plog_w("╔─ FILE PERMISSIONS & OWNERSHIP (ADMIN) ──────────────────────╗", "PROMPT")
        _plog_w("║  takeown / icacls — repair locked or inaccessible files.    ║", "DIM")
        _plog_w("║  ⚠  " + _ADM_BADGE_S + " — use with caution.     ║", "ERR")
        _plog_w("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

    def _build_services_tab(frame):
        import subprocess as _rspsvc, threading as _tsvc
        _sf, slog = _make_log(frame)
        _sf.pack(fill=_rtk.BOTH, expand=True)
        _sbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
        _sbf.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Frame(frame, bg="#ff3366", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Label(_sbf, text="  ⚠ " + _ADM_BADGE_S + " — starting/stopping services affects the OS",
                   font=("Consolas",8,"bold"), bg=_PNL2, fg="#ff3366").pack(anchor="w", pady=(0,4))

        def _slog_w(msg, tag="DIM"):
            try:
                slog.config(state="normal")
                slog.insert(_rtk.END, msg+"\n", tag)
                slog.see(_rtk.END)
                slog.config(state="disabled")
            except Exception: pass

        _svc_entry_v = _rtk.StringVar(value="wuauserv")

        def _svc_status():
            sn = _svc_entry_v.get().strip()
            if not sn: return
            def _w():
                _slog_w(f">_ Status of '{sn}'...", "INFO")
                r = _rspsvc.run(["sc", "query", sn], capture_output=True, text=True)
                for l in r.stdout.splitlines():
                    tag = "OK" if "RUNNING" in l else ("WARN" if "STOPPED" in l else "DIM")
                    _slog_w(f"  {l}", tag)
            _tsvc.Thread(target=_w, daemon=True).start()

        def _svc_stop():
            sn = _svc_entry_v.get().strip()
            if not sn: return
            if not _rtk.messagebox.askyesno("Confirm", f"Stop service '{sn}'?", parent=rr): return
            def _w():
                r = _rspsvc.run(["net", "stop", sn], capture_output=True, text=True)
                tag = "OK" if r.returncode == 0 else "ERR"
                _slog_w(f"  {'✓' if r.returncode==0 else '✗'} {sn}: {r.stdout.strip() or r.stderr.strip()}", tag)
                _rec_log_admin(f"Service stopped: {sn} rc={r.returncode}")
            _tsvc.Thread(target=_w, daemon=True).start()

        def _svc_start():
            sn = _svc_entry_v.get().strip()
            if not sn: return
            def _w():
                r = _rspsvc.run(["net", "start", sn], capture_output=True, text=True)
                tag = "OK" if r.returncode == 0 else "ERR"
                _slog_w(f"  {'✓' if r.returncode==0 else '✗'} {sn}: {r.stdout.strip() or r.stderr.strip()}", tag)
                _rec_log_admin(f"Service started: {sn} rc={r.returncode}")
            _tsvc.Thread(target=_w, daemon=True).start()

        def _list_suspicious_svcs():
            def _w():
                _slog_w(">_ Listing non-Microsoft services...", "INFO")
                r = _rspsvc.run(["sc", "query", "type=", "all", "state=", "all"],
                                 capture_output=True, text=True, timeout=30)
                lines = [l for l in r.stdout.splitlines() if "SERVICE_NAME" in l.upper()]
                _slog_w(f"  Total services: {len(lines)}", "DIM")
                for l in lines[:30]: _slog_w(f"  {l.strip()}", "DIM")
                if len(lines) > 30: _slog_w(f"  ... and {len(lines)-30} more", "DIM")
            _tsvc.Thread(target=_w, daemon=True).start()

        def _flush_dns():
            def _w():
                _slog_w(">_ Flushing DNS cache...", "INFO")
                r = _rspsvc.run(["ipconfig", "/flushdns"], capture_output=True, text=True)
                tag = "OK" if r.returncode == 0 else "ERR"
                _slog_w(f"  {'✓' if r.returncode==0 else '✗'} {r.stdout.strip()}", tag)
                _rec_log_admin(f"DNS flushed rc={r.returncode}")
            _tsvc.Thread(target=_w, daemon=True).start()

        def _reset_winsock():
            if not _rtk.messagebox.askyesno("Confirm", "Reset Winsock catalog?\n(requires reboot)", parent=rr): return
            def _w():
                r = _rspsvc.run(["netsh", "winsock", "reset"], capture_output=True, text=True)
                tag = "OK" if r.returncode == 0 else "ERR"
                _slog_w(f"  {'✓' if r.returncode==0 else '✗'} Winsock reset: {r.stdout.strip()}", tag)
                _rec_log_admin(f"Winsock reset rc={r.returncode}")
            _tsvc.Thread(target=_w, daemon=True).start()

        _svc_ctrl_row = _rtk.Frame(_sbf, bg=_PNL2); _svc_ctrl_row.pack(fill=_rtk.X, pady=(0,2))
        _rtk.Label(_svc_ctrl_row, text="Service name:", font=("Consolas",8),
                   bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=4)
