    def _build_registry_tab(frame):
        import subprocess as _rspreg, threading as _treg
        _rf, rlog = _make_log(frame)
        _rf.pack(fill=_rtk.BOTH, expand=True)
        _rbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
        _rbf.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Frame(frame, bg="#ff3366", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Label(_rbf, text="  ⚠ " + _ADM_BADGE_S + " — registry changes affect the OS globally",
                   font=("Consolas",8,"bold"), bg=_PNL2, fg="#ff3366").pack(anchor="w", pady=(0,4))

        def _rlog_w(msg, tag="DIM"):
            try:
                rlog.config(state="normal")
                rlog.insert(_rtk.END, msg+"\n", tag)
                rlog.see(_rtk.END)
                rlog.config(state="disabled")
            except Exception: pass

        _reg_key_v = _rtk.StringVar(value=r"HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Run")
        _reg_val_v = _rtk.StringVar()
        _reg_data_v = _rtk.StringVar()

        def _reg_query():
            k = _reg_key_v.get().strip()
            if not k: return
            def _w():
                _rlog_w(f">_ Query: {k}", "INFO")
                r = _rspreg.run(["reg", "query", k], capture_output=True, text=True, timeout=15)
                if r.returncode == 0:
                    for l in r.stdout.splitlines():
                        tag = "WARN" if any(x in l.lower() for x in ["run","startup","shell","load"]) else "DIM"
                        _rlog_w(f"  {l}", tag)
                    _rec_log_admin(f"Registry query: {k}")
                else:
                    _rlog_w(f"  ✗ {r.stderr.strip()[:200]}", "ERR")
            _treg.Thread(target=_w, daemon=True).start()

        def _reg_delete_val():
            k = _reg_key_v.get().strip(); v = _reg_val_v.get().strip()
            if not k or not v: _rlog_w("  ✗ Provide both key path and value name", "ERR"); return
            import tkinter.messagebox as _mb
            if not _mb.askyesno("Confirm", f"Delete registry value:\n\n{k}\\{v}\n\nThis cannot be undone.", parent=rr): return
            def _w():
                r = _rspreg.run(["reg", "delete", k, "/v", v, "/f"],
                                 capture_output=True, text=True, timeout=15)
                if r.returncode == 0:
                    _rlog_w(f"  ✓ Deleted: {k}\\{v}", "OK")
                    _rec_log_admin(f"Registry value deleted: {k}\\{v}")
                else:
                    _rlog_w(f"  ✗ {r.stderr.strip()[:200]}", "ERR")
            _treg.Thread(target=_w, daemon=True).start()

        def _reg_add_val():
            k = _reg_key_v.get().strip(); v = _reg_val_v.get().strip(); d = _reg_data_v.get().strip()
            if not k or not v or not d: _rlog_w("  ✗ Provide key, value name and data", "ERR"); return
            def _w():
                r = _rspreg.run(["reg", "add", k, "/v", v, "/d", d, "/f"],
                                 capture_output=True, text=True, timeout=15)
                if r.returncode == 0:
                    _rlog_w(f"  ✓ Set: {k}\\{v} = {d}", "OK")
                    _rec_log_admin(f"Registry value set: {k}\\{v} = {d}")
                else:
                    _rlog_w(f"  ✗ {r.stderr.strip()[:200]}", "ERR")
            _treg.Thread(target=_w, daemon=True).start()

        def _reg_scan_run_keys():
            def _w():
                _rlog_w(">_ Scanning common persistence / Run keys...", "INFO")
                _run_keys = [
                    r"HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Run",
                    r"HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce",
                    r"HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\Run",
                    r"HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce",
                    r"HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Winlogon",
                ]
                for key in _run_keys:
                    _rlog_w(f"\n── {key}", "HEAD")
                    r = _rspreg.run(["reg", "query", key], capture_output=True, text=True, timeout=10)
                    if r.returncode == 0:
                        for l in r.stdout.splitlines():
                            if l.strip(): _rlog_w(f"  {l}", "WARN" if "REG_" in l else "DIM")
                    else:
                        _rlog_w(f"  (not found or access denied)", "DIM")
                _rlog_w("\n  ✓ Scan complete.", "OK")
                _rec_log_admin("Registry Run key scan performed")
            _treg.Thread(target=_w, daemon=True).start()

        _reg_row1 = _rtk.Frame(_rbf, bg=_PNL2); _reg_row1.pack(fill=_rtk.X, pady=(0,2))
        _rtk.Label(_reg_row1, text="Key path:", font=("Consolas",8), bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=4)
        _rtk.Entry(_reg_row1, textvariable=_reg_key_v, font=("Consolas",8),
                   bg=_BRD2, fg=_TXT, insertbackground=_GRN2, relief="flat", bd=2, width=52).pack(side=_rtk.LEFT, padx=4)
        _reg_row2 = _rtk.Frame(_rbf, bg=_PNL2); _reg_row2.pack(fill=_rtk.X, pady=(0,2))
        _rtk.Label(_reg_row2, text="Value:", font=("Consolas",8), bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=4)
        _rtk.Entry(_reg_row2, textvariable=_reg_val_v, font=("Consolas",8),
                   bg=_BRD2, fg=_TXT, insertbackground=_GRN2, relief="flat", bd=2, width=22).pack(side=_rtk.LEFT, padx=4)
        _rtk.Label(_reg_row2, text="Data:", font=("Consolas",8), bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=8)
        _rtk.Entry(_reg_row2, textvariable=_reg_data_v, font=("Consolas",8),
                   bg=_BRD2, fg=_TXT, insertbackground=_GRN2, relief="flat", bd=2, width=22).pack(side=_rtk.LEFT, padx=4)
        _reg_row3 = _rtk.Frame(_rbf, bg=_PNL2); _reg_row3.pack(fill=_rtk.X, pady=2)
        for _bt, _bc, _cmd in [
            ("🔍  Query Key",         _BLU,  _reg_query),
            ("🦠  Scan Run Keys",      _YEL,  _reg_scan_run_keys),
            ("➕  Set Value",          _GRN2, _reg_add_val),
            ("🗑  Delete Value",       _RED,  _reg_delete_val),
        ]:
            _rtk.Button(_reg_row3, text=_bt, command=_cmd, bg=_BRD2, fg=_bc,
                        font=("Consolas",9), relief="flat", padx=10, pady=5,
                        cursor="hand2", bd=0).pack(side=_rtk.LEFT, padx=3)
        _rlog_w("╔─ REGISTRY EDITOR (ADMIN) ───────────────────────────────────╗", "PROMPT")
        _rlog_w("║  Query, add, or delete registry values.                     ║", "DIM")
        _rlog_w("║  'Scan Run Keys' checks common malware persistence paths.   ║", "DIM")
        _rlog_w("║  ⚠  " + _ADM_BADGE_S + " — handle with care.     ║", "ERR")
        _rlog_w("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

    def _build_hosts_firewall_tab(frame):
        import subprocess as _rsphf, threading as _thf
        _hff, hlog = _make_log(frame)
        _hff.pack(fill=_rtk.BOTH, expand=True)
        _hfbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
        _hfbf.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Frame(frame, bg="#ff3366", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Label(_hfbf, text="  ⚠ " + _ADM_BADGE_S + " — hosts/firewall changes affect the OS network stack",
                   font=("Consolas",8,"bold"), bg=_PNL2, fg="#ff3366").pack(anchor="w", pady=(0,4))

        def _hlog_w(msg, tag="DIM"):
            try:
                hlog.config(state="normal")
                hlog.insert(_rtk.END, msg+"\n", tag)
                hlog.see(_rtk.END)
                hlog.config(state="disabled")
            except Exception: pass

        _hf_ip_v    = _rtk.StringVar(value="0.0.0.0")
        _hf_host_v  = _rtk.StringVar(value="malware.example.com")
        _hf_fw_port = _rtk.StringVar(value="4444")
        _hf_fw_name = _rtk.StringVar(value="V0RTEX_BLOCK")

        _HOSTS_PATH = (r"C:\Windows\System32\drivers\etc\hosts"
                       if _rsys.platform == "win32" else "/etc/hosts")

        def _hosts_view():
            def _w():
                _hlog_w(f">_ Reading: {_HOSTS_PATH}", "INFO")
                try:
                    with open(_HOSTS_PATH, encoding="utf-8", errors="replace") as _hf2:
                        lines = _hf2.readlines()
                    _hlog_w(f"  {len(lines)} lines:", "DIM")
                    for l in lines:
                        l = l.rstrip()
                        if l and not l.startswith("#"):
                            _hlog_w(f"  {l}", "WARN")
                        else:
                            _hlog_w(f"  {l}", "DIM")
                    _rec_log_admin("Hosts file viewed")
                except Exception as _he: _hlog_w(f"  ✗ {_he}", "ERR")
            _thf.Thread(target=_w, daemon=True).start()

        def _hosts_block():
            ip = _hf_ip_v.get().strip(); host = _hf_host_v.get().strip()
            if not host: _hlog_w("  ✗ Provide a hostname", "ERR"); return
            def _w():
                try:
                    entry = f"\n{ip}\t{host}\t# V0RTEX BLOCK\n"
                    with open(_HOSTS_PATH, "a", encoding="utf-8") as _hf3:
                        _hf3.write(entry)
                    _hlog_w(f"  ✓ Blocked: {ip} → {host}", "OK")
                    _rec_log_admin(f"Hosts block added: {ip} {host}")
                except Exception as _he2: _hlog_w(f"  ✗ {_he2}", "ERR")
            _thf.Thread(target=_w, daemon=True).start()

        def _hosts_remove_vortex():
            def _w():
                _hlog_w(">_ Removing V0RTEX BLOCK entries...", "INFO")
                try:
                    with open(_HOSTS_PATH, "r", encoding="utf-8", errors="replace") as _hf4:
                        lines = _hf4.readlines()
                    clean = [l for l in lines if "V0RTEX BLOCK" not in l]
                    removed = len(lines) - len(clean)
                    with open(_HOSTS_PATH, "w", encoding="utf-8") as _hf4w:
                        _hf4w.writelines(clean)
                    _hlog_w(f"  ✓ Removed {removed} V0RTEX BLOCK entries", "OK")
                    _rec_log_admin(f"Hosts V0RTEX entries removed: {removed}")
                except Exception as _he3: _hlog_w(f"  ✗ {_he3}", "ERR")
            _thf.Thread(target=_w, daemon=True).start()

        def _fw_block_port():
            port = _hf_fw_port.get().strip(); name = _hf_fw_name.get().strip()
            if not port: _hlog_w("  ✗ Provide a port number", "ERR"); return
            def _w():
                _hlog_w(f">_ Blocking outbound port {port}...", "INFO")
                r = _rsphf.run(["netsh","advfirewall","firewall","add","rule",
                                  f"name={name}_{port}","dir=out","action=block",
                                  f"protocol=tcp","remoteport="+port],
                                 capture_output=True, text=True, timeout=20,
                                 creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                if r.returncode == 0:
                    _hlog_w(f"  ✓ Outbound TCP {port} blocked (rule: {name}_{port})", "OK")
                    _rec_log_admin(f"Firewall block added: outbound TCP {port}")
                else:
                    _hlog_w(f"  ✗ {r.stderr.strip()[:200]}", "ERR")
            _thf.Thread(target=_w, daemon=True).start()

        def _fw_list_rules():
            def _w():
                _hlog_w(">_ Listing firewall rules containing 'V0RTEX'...", "INFO")
                r = _rsphf.run(["netsh","advfirewall","firewall","show","rule","name=all"],
                                 capture_output=True, text=True, timeout=30,
                                 creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                lines = r.stdout.splitlines()
                found = []
                for i, l in enumerate(lines):
                    if "V0RTEX" in l.upper():
                        found.extend(lines[max(0,i-1):i+4])
                if found:
                    for l in found: _hlog_w(f"  {l}", "WARN")
                    _rec_log_admin(f"Firewall V0RTEX rules listed: {len(found)} lines")
                else:
                    _hlog_w("  (no V0RTEX firewall rules found)", "DIM")
            _thf.Thread(target=_w, daemon=True).start()

        def _fw_delete_rule():
            name = _hf_fw_name.get().strip()
            if not name: _hlog_w("  ✗ Provide a rule name", "ERR"); return
            def _w():
                r = _rsphf.run(["netsh","advfirewall","firewall","delete","rule",f"name={name}"],
                                 capture_output=True, text=True, timeout=15,
                                 creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                tag = "OK" if r.returncode == 0 else "ERR"
                _hlog_w(f"  {'✓' if r.returncode==0 else '✗'} Delete rule '{name}': {r.stdout.strip() or r.stderr.strip()}", tag)
                _rec_log_admin(f"Firewall rule deleted: {name} rc={r.returncode}")
            _thf.Thread(target=_w, daemon=True).start()

        _hfr1 = _rtk.Frame(_hfbf, bg=_PNL2); _hfr1.pack(fill=_rtk.X, pady=(0,2))
        _rtk.Label(_hfr1, text="IP:", font=("Consolas",8), bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=4)
        _rtk.Entry(_hfr1, textvariable=_hf_ip_v, font=("Consolas",8), bg=_BRD2, fg=_TXT,
                   insertbackground=_GRN2, relief="flat", bd=2, width=15).pack(side=_rtk.LEFT, padx=2)
        _rtk.Label(_hfr1, text="Hostname:", font=("Consolas",8), bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=(8,2))
        _rtk.Entry(_hfr1, textvariable=_hf_host_v, font=("Consolas",8), bg=_BRD2, fg=_TXT,
                   insertbackground=_GRN2, relief="flat", bd=2, width=28).pack(side=_rtk.LEFT, padx=2)
        _hfr2 = _rtk.Frame(_hfbf, bg=_PNL2); _hfr2.pack(fill=_rtk.X, pady=(0,2))
        _rtk.Label(_hfr2, text="Port:", font=("Consolas",8), bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=4)
        _rtk.Entry(_hfr2, textvariable=_hf_fw_port, font=("Consolas",8), bg=_BRD2, fg=_TXT,
                   insertbackground=_GRN2, relief="flat", bd=2, width=8).pack(side=_rtk.LEFT, padx=2)
        _rtk.Label(_hfr2, text="Rule name:", font=("Consolas",8), bg=_PNL2, fg=_SUB).pack(side=_rtk.LEFT, padx=(8,2))
        _rtk.Entry(_hfr2, textvariable=_hf_fw_name, font=("Consolas",8), bg=_BRD2, fg=_TXT,
                   insertbackground=_GRN2, relief="flat", bd=2, width=20).pack(side=_rtk.LEFT, padx=2)
        _hfr3 = _rtk.Frame(_hfbf, bg=_PNL2); _hfr3.pack(fill=_rtk.X, pady=2)
        for _bt, _bc, _cmd in [
            ("📄  View Hosts",          _BLU,  _hosts_view),
            ("🚫  Block Host",          _YEL,  _hosts_block),
            ("🧹  Remove V0RTEX Blocks", _TEA,  _hosts_remove_vortex),
            ("🔥  Block Port (FW)",      _RED,  _fw_block_port),
            ("📋  List FW Rules",        _MAU,  _fw_list_rules),
            ("🗑  Delete FW Rule",       _RED,  _fw_delete_rule),
        ]:
            _rtk.Button(_hfr3, text=_bt, command=_cmd, bg=_BRD2, fg=_bc,
                        font=("Consolas",9), relief="flat", padx=8, pady=5,
                        cursor="hand2", bd=0).pack(side=_rtk.LEFT, padx=2)
        _hlog_w("╔─ HOSTS & FIREWALL (ADMIN) ───────────────────────────────────╗", "PROMPT")
        _hlog_w("║  Block malicious hosts · manage Windows Firewall rules.      ║", "DIM")
        _hlog_w("║  ⚠  " + _ADM_BADGE_S + " — affects OS networking. ║", "ERR")
        _hlog_w("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

    def _build_processkiller_tab(frame):
        import subprocess as _rsppk, threading as _tpk
        _pkf, pklog = _make_log(frame)
        _pkf.pack(fill=_rtk.BOTH, expand=True)
        _pkbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
        _pkbf.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Frame(frame, bg="#ff3366", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Label(_pkbf, text="  ⚠ " + _ADM_BADGE_S + " — killing system processes may crash the OS",
                   font=("Consolas",8,"bold"), bg=_PNL2, fg="#ff3366").pack(anchor="w", pady=(0,4))

        def _pklog_w(msg, tag="DIM"):
            try:
                pklog.config(state="normal")
                pklog.insert(_rtk.END, msg+"\n", tag)
                pklog.see(_rtk.END)
                pklog.config(state="disabled")
            except Exception: pass

        _pk_pid_v  = _rtk.StringVar()
        _pk_name_v = _rtk.StringVar()

        def _pk_list_all():
            def _w():
                _pklog_w(">_ Listing running processes...", "INFO")
                if _rsys.platform == "win32":
                    r = _rsppk.run(["tasklist","/FO","CSV","/NH"],
                                    capture_output=True, text=True, timeout=20, creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                    lines = [l.strip().strip('"') for l in r.stdout.splitlines() if l.strip()]
                    _pklog_w(f"  Total: {len(lines)} processes", "DIM")
                    for l in lines:
                        parts = l.replace('","', '|').strip('"').split("|")
                        name = parts[0] if parts else l
                        pid  = parts[1] if len(parts) > 1 else ""
                        _pklog_w(f"  PID {pid:<8}  {name}", "DIM")
                else:
                    r = _rsppk.run(["ps","aux","--no-header"], capture_output=True, text=True, timeout=20)
                    for l in r.stdout.splitlines()[:60]: _pklog_w(f"  {l}", "DIM")
                _rec_log_admin("Process list viewed")
            _tpk.Thread(target=_w, daemon=True).start()

        def _pk_list_suspicious():
            def _w():
                _pklog_w(">_ Checking for suspicious process names...", "INFO")
                _sus = ["power" + "shell","cmd","wscript","cscript","mshta","regsvr32",
                        "rundll32","schtasks","certutil","bitsadmin","mimikatz",
                        "netcat","nc","ncat","psexec","procdump","meterpreter",
                        "cobaltstrike","beacon","inject","dump","keylog"]
                r = _rsppk.run(["tasklist","/FO","CSV","/NH"],
                                capture_output=True, text=True, timeout=20, creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                found = []
                for l in r.stdout.splitlines():
                    low = l.lower()
                    if any(s in low for s in _sus):
                        found.append(l.strip().strip('"'))
                if found:
                    _pklog_w(f"  ⚠ Found {len(found)} suspicious process(es):", "WARN")
                    for l in found: _pklog_w(f"    ▶  {l}", "ERR")
                else:
                    _pklog_w("  ✓ No suspicious processes detected (basic heuristic)", "OK")
                _rec_log_admin(f"Suspicious process scan: {len(found)} flagged")
            _tpk.Thread(target=_w, daemon=True).start()

        def _pk_kill_pid():
            pid = _pk_pid_v.get().strip()
            if not pid.isdigit(): _pklog_w("  ✗ Enter a valid numeric PID", "ERR"); return
            import tkinter.messagebox as _mb
            if not _mb.askyesno("Confirm", f"Terminate process PID {pid}?\n\nThis cannot be undone.", parent=rr): return
            def _w():
                if _rsys.platform == "win32":
                    r = _rsppk.run(["taskkill","/F","/PID",pid], capture_output=True, text=True, creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                else:
                    r = _rsppk.run(["kill","-9",pid], capture_output=True, text=True)
                tag = "OK" if r.returncode == 0 else "ERR"
                _pklog_w(f"  {'✓' if r.returncode==0 else '✗'} PID {pid}: {r.stdout.strip() or r.stderr.strip()}", tag)
                _rec_log_admin(f"Process killed by PID: {pid} rc={r.returncode}")
            _tpk.Thread(target=_w, daemon=True).start()

        def _pk_kill_name():
            name = _pk_name_v.get().strip()
            if not name: _pklog_w("  ✗ Enter a process name", "ERR"); return
            import tkinter.messagebox as _mb
            if not _mb.askyesno("Confirm", f"Terminate ALL processes named '{name}'?\n\nThis cannot be undone.", parent=rr): return
            def _w():
                if _rsys.platform == "win32":
                    r = _rsppk.run(["taskkill","/F","/IM",name], capture_output=True, text=True, creationflags=0x08000000 if _rsys.platform=="win32" else 0)
                else:
                    r = _rsppk.run(["killall","-9",name], capture_output=True, text=True)
