_tab_scroll_registry: dict = {}
_last_scrolled_widget = [None]

def _is_scrollable_canvas(widget) -> bool:
    try:
        if str(widget) in _MATPLOTLIB_CANVAS_IDS:
            return False
        if widget.winfo_class() != "Canvas":
            return False
        sc = str(widget.cget("yscrollcommand"))
        if sc and sc not in ("", "{}"):
            return True
        sr = widget.cget("scrollregion")
        if sr and str(sr) not in ("", "{}", "0 0 0 0"):
            return True
    except Exception:
        pass
    return False

def _find_scrollable_in_subtree(widget, depth=0) -> list:
    if depth > 10:
        return []
    results = []
    try:
        cls = widget.winfo_class()
        if cls in ("Text", "Listbox"):
            results.append(widget)
        elif cls == "Canvas" and _is_scrollable_canvas(widget):
            results.append(widget)
        for child in widget.winfo_children():
            results.extend(_find_scrollable_in_subtree(child, depth + 1))
    except Exception:
        pass
    return results

def _find_scrollable_ancestor(widget):
    w = widget
    for _ in range(25):
        try:
            cls = w.winfo_class()
            if cls in ("Text", "Listbox"):
                return w
            if cls == "Canvas" and _is_scrollable_canvas(w):
                return w
            w = w.nametowidget(w.winfo_parent())
        except Exception:
            break
    return None

def _get_tab_scrollable():
    try:
        tab_idx  = _nb.index(_nb.select())
        cached   = _tab_scroll_registry.get(tab_idx)
        if cached:
            try:
                cached.winfo_class()
                return cached
            except Exception:
                pass

        try:
            tab_frame = _nb.winfo_children()[tab_idx]
        except Exception:
            return None
        candidates = _find_scrollable_in_subtree(tab_frame)
        if candidates:

            texts   = [w for w in candidates if w.winfo_class() == "Text"]
            canvases = [w for w in candidates if w.winfo_class() == "Canvas"]
            best = texts[0] if texts else (canvases[0] if canvases else candidates[0])
            _tab_scroll_registry[tab_idx] = best
            return best
    except Exception:
        pass
    return None

def _global_scroll_handler(event):
    try:

        delta = 0
        if event.delta:
            delta = -1 if event.delta > 0 else 1
            units = max(1, abs(event.delta) // 120)
            delta *= units

        if not delta:
            return


        target = event.widget
        scrollable = None

        try:
            cls = target.winfo_class()
            if cls in ("Text", "Listbox"):
                scrollable = target
            elif cls == "Canvas" and _is_scrollable_canvas(target):
                scrollable = target
        except Exception:
            pass


        if not scrollable:
            scrollable = _find_scrollable_ancestor(target)


        if not scrollable:
            scrollable = _get_tab_scrollable()


        if not scrollable:
            scrollable = _last_scrolled_widget[0]

        if not scrollable:
            return


        if scrollable.winfo_class() == "Canvas":
            try:
                bb = scrollable.bbox("all")
                if bb:
                    scrollable.configure(scrollregion=bb)
            except Exception:
                pass

            try:
                yv = scrollable.yview()
                if delta < 0 and yv[0] <= 0.001: return
                if delta > 0 and yv[1] >= 0.999: return
            except Exception:
                pass

        scrollable.yview_scroll(delta, "units")
        _last_scrolled_widget[0] = scrollable
    except Exception:
        pass

def _on_tab_changed(event):
    try:
        idx = _nb.index(_nb.select())
        _tab_scroll_registry.pop(idx, None)
    except Exception:
        pass

_nb.bind("<<NotebookTabChanged>>", _on_tab_changed)


root.bind_all("<MouseWheel>", _global_scroll_handler)


def _bind_scrollables_recursively(widget, depth=0):
    if depth > 15:
        return
    try:
        cls = widget.winfo_class()
        if cls in ("Text", "Listbox"):
            widget.bind("<MouseWheel>", _global_scroll_handler, add=True)
        elif cls == "Canvas" and _is_scrollable_canvas(widget):
            widget.bind("<MouseWheel>", _global_scroll_handler, add=True)
        for child in widget.winfo_children():
            _bind_scrollables_recursively(child, depth + 1)
    except Exception:
        pass

def _refresh_all_canvas_scrollregions(widget=None):
    if widget is None:
        widget = root
    try:
        if widget.winfo_class() == "Canvas" and _is_scrollable_canvas(widget):
            try:
                bb = widget.bbox("all")
                if bb:
                    widget.configure(scrollregion=bb)
            except Exception:
                pass
        for child in widget.winfo_children():
            _refresh_all_canvas_scrollregions(child)
    except Exception:
        pass

root.after(600,  _refresh_all_canvas_scrollregions)
root.after(800,  lambda: _bind_scrollables_recursively(root))
